"""
Parameterized generator for GH438_bdk_1486.

Source PR:    https://github.com/bitcoindevkit/bdk/pull/1486
Source Issue: https://github.com/bitcoindevkit/bdk/issues/1483

Seed varies: renames 'absolute' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH438_bdk_1486'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH438_bdk_1486'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('absolute', 'absolute' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH438_bdk_1486',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'bitcoindevkit/bdk',
                "pr_number": 1486,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/bitcoindevkit/bdk/pull/1486",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'crates/chain/src/descriptor_ext.rs': 'use crate::{\n    alloc::{string::ToString, vec::Vec},\n    miniscript::{Descriptor, DescriptorPublicKey},\n};\nuse bitcoin::hashes::{hash_newtype, sha256, Hash};\n\nhash_newtype! {\n    /// Represents the ID of a descriptor, defined as the sha256 hash of\n    /// the descriptor string, checksum excluded.\n    ///\n    /// This is useful for having a fixed-length unique representation of a descriptor,\n    /// in particular, we use it to persist application state changes related to the\n    /// descriptor without having to re-write the whole descriptor each time.\n    ///\n    pub struct DescriptorId(pub sha256::Hash);\n}\n\n/// A trait to extend the functionality of a miniscript descriptor.\npub trait DescriptorExt {\n    /// Returns the minimum value (in satoshis) at which an output is broadcastable.\n    /// Panics if the descriptor wildcard is hardened.\n    fn dust_value(&self) -> u64;\n\n    /// Returns the descriptor id, calculated as the sha256 of the descriptor, checksum not\n    /// included.\n    fn descriptor_id(&self) -> DescriptorId;\n}\n\nimpl DescriptorExt for Descriptor<DescriptorPublicKey> {\n    fn dust_value(&self) -> u64 {\n        self.at_derivation_index(0)\n            .expect("descriptor can\'t have hardened derivation")\n            .script_pubkey()\n            .minimal_non_dust()\n            .to_sat()\n    }\n\n    fn descriptor_id(&self) -> DescriptorId {\n        let desc = self.to_string();\n        let desc_without_checksum = desc.split(\'#\').next().expect("Must be here");\n        let descriptor_bytes = <Vec<u8>>::from(desc_without_checksum.as_bytes());\n        DescriptorId(sha256::Hash::hash(&descriptor_bytes))\n    }\n}\n',
            'crates/chain/src/keychain/txout_index.rs': 'use crate::{\n    collections::*,\n    indexed_tx_graph::Indexer,\n    miniscript::{Descriptor, DescriptorPublicKey},\n    spk_iter::BIP32_MAX_INDEX,\n    DescriptorExt, DescriptorId, SpkIterator, SpkTxOutIndex,\n};\nuse alloc::{borrow::ToOwned, vec::Vec};\nuse bitcoin::{Amount, OutPoint, Script, SignedAmount, Transaction, TxOut, Txid};\nuse core::{\n    fmt::Debug,\n    ops::{Bound, RangeBounds},\n};\n\nuse super::*;\nuse crate::Append;\n\n/// The default lookahead for a [`KeychainTxOutIndex`]\npub const DEFAULT_LOOKAHEAD: u32 = 25;\n\n/// [`KeychainTxOutIndex`] controls how script pubkeys are revealed for multiple keychains, and\n/// indexes [`TxOut`]s with them.\n///\n/// A single keychain is a chain of script pubkeys derived from a single [`Descriptor`]. Keychains\n/// are identified using the `K` generic. Script pubkeys are identified by the keychain that they\n/// are derived from `K`, as well as the derivation index `u32`.\n///\n/// There is a strict 1-to-1 relationship between descriptors and keychains. Each keychain has one\n/// and only one descriptor and each descriptor has one and only one keychain. The\n/// [`insert_descriptor`] method will return an error if you try and violate this invariant. This\n/// rule is a proxy for a stronger rule: no two descriptors should produce the same script pubkey.\n/// Having two descriptors produce the same script pubkey should cause whichever keychain derives\n/// the script pubkey first to be the effective owner of it but you should not rely on this\n/// behaviour. ⚠ It is up you, the developer, not to violate this invariant.\n///\n/// # Revealed script pubkeys\n///\n/// Tracking how script pubkeys are revealed is useful for collecting chain data. For example, if\n/// the user has requested 5 script pubkeys (to receive money with), we only need to use those\n/// script pubkeys to scan for chain data.\n///\n/// Call [`reveal_to_target`] or [`reveal_next_spk`] to reveal more script pubkeys.\n/// Call [`revealed_keychain_spks`] or [`revealed_spks`] to iterate through revealed script pubkeys.\n///\n/// # Lookahead script pubkeys\n///\n/// When an user first recovers a wallet (i.e. from a recovery phrase and/or descriptor), we will\n/// NOT have knowledge of which script pubkeys are revealed. So when we index a transaction or\n/// txout (using [`index_tx`]/[`index_txout`]) we scan the txouts against script pubkeys derived\n/// above the last revealed index. These additionally-derived script pubkeys are called the\n/// lookahead.\n///\n/// The [`KeychainTxOutIndex`] is constructed with the `lookahead` and cannot be altered. See\n/// [`DEFAULT_LOOKAHEAD`] for the value used in the `Default` implementation. Use [`new`] to set a\n/// custom `lookahead`.\n///\n/// # Unbounded script pubkey iterator\n///\n/// For script-pubkey-based chain sources (such as Electrum/Esplora), an initial scan is best done\n/// by iterating though derived script pubkeys one by one and requesting transaction histories for\n/// each script pubkey. We will stop after x-number of script pubkeys have empty histories. An\n/// unbounded script pubkey iterator is useful to pass to such a chain source because it doesn\'t\n/// require holding a reference to the index.\n///\n/// Call [`unbounded_spk_iter`] to get an unbounded script pubkey iterator for a given keychain.\n/// Call [`all_unbounded_spk_iters`] to get unbounded script pubkey iterators for all keychains.\n///\n/// # Change sets\n///\n/// Methods that can update the last revealed index or add keychains will return [`ChangeSet`] to report\n/// these changes. This should be persisted for future recovery.\n///\n/// ## Synopsis\n///\n/// ```\n/// use bdk_chain::keychain::KeychainTxOutIndex;\n/// # use bdk_chain::{ miniscript::{Descriptor, DescriptorPublicKey} };\n/// # use core::str::FromStr;\n///\n/// // imagine our service has internal and external addresses but also addresses for users\n/// #[derive(Clone, Debug, PartialEq, Eq, Ord, PartialOrd)]\n/// enum MyKeychain {\n///     External,\n///     Internal,\n///     MyAppUser {\n///         user_id: u32\n///     }\n/// }\n///\n/// let mut txout_index = KeychainTxOutIndex::<MyKeychain>::default();\n///\n/// # let secp = bdk_chain::bitcoin::secp256k1::Secp256k1::signing_only();\n/// # let (external_descriptor,_) = Descriptor::<DescriptorPublicKey>::parse_descriptor(&secp, "tr([73c5da0a/86\'/0\'/0\']xprv9xgqHN7yz9MwCkxsBPN5qetuNdQSUttZNKw1dcYTV4mkaAFiBVGQziHs3NRSWMkCzvgjEe3n9xV8oYywvM8at9yRqyaZVz6TYYhX98VjsUk/0/*)").unwrap();\n/// # let (internal_descriptor,_) = Descriptor::<DescriptorPublicKey>::parse_descriptor(&secp, "tr([73c5da0a/86\'/0\'/0\']xprv9xgqHN7yz9MwCkxsBPN5qetuNdQSUttZNKw1dcYTV4mkaAFiBVGQziHs3NRSWMkCzvgjEe3n9xV8oYywvM8at9yRqyaZVz6TYYhX98VjsUk/1/*)").unwrap();\n/// # let (descriptor_42, _) = Descriptor::<DescriptorPublicKey>::parse_descriptor(&secp, "tr([73c5da0a/86\'/0\'/0\']xprv9xgqHN7yz9MwCkxsBPN5qetuNdQSUttZNKw1dcYTV4mkaAFiBVGQziHs3NRSWMkCzvgjEe3n9xV8oYywvM8at9yRqyaZVz6TYYhX98VjsUk/2/*)").unwrap();\n/// let _ = txout_index.insert_descriptor(MyKeychain::External, external_descriptor)?;\n/// let _ = txout_index.insert_descriptor(MyKeychain::Internal, internal_descriptor)?;\n/// let _ = txout_index.insert_descriptor(MyKeychain::MyAppUser { user_id: 42 }, descriptor_42)?;\n///\n/// let new_spk_for_user = txout_index.reveal_next_spk(&MyKeychain::MyAppUser{ user_id: 42 });\n/// # Ok::<_, bdk_chain::keychain::InsertDescriptorError<_>>(())\n/// ```\n///\n/// [`Ord`]: core::cmp::Ord\n/// [`SpkTxOutIndex`]: crate::spk_txout_index::SpkTxOutIndex\n/// [`Descriptor`]: crate::miniscript::Descriptor\n/// [`reveal_to_target`]: Self::reveal_to_target\n/// [`reveal_next_spk`]: Self::reveal_next_spk\n/// [`revealed_keychain_spks`]: Self::revealed_keychain_spks\n/// [`revealed_spks`]: Self::revealed_spks\n/// [`index_tx`]: Self::index_tx\n/// [`index_txout`]: Self::index_txout\n/// [`new`]: Self::new\n/// [`unbounded_spk_iter`]: Self::unbounded_spk_iter\n/// [`all_unbounded_spk_iters`]: Self::all_unbounded_spk_iters\n/// [`outpoints`]: Self::outpoints\n/// [`txouts`]: Self::txouts\n/// [`unused_spks`]: Self::unused_spks\n/// [`insert_descriptor`]: Self::insert_descriptor\n#[derive(Clone, Debug)]\npub struct KeychainTxOutIndex<K> {\n    inner: SpkTxOutIndex<(K, u32)>,\n    keychain_to_descriptor_id: BTreeMap<K, DescriptorId>,\n    descriptor_id_to_keychain: HashMap<DescriptorId, K>,\n    descriptors: HashMap<DescriptorId, Descriptor<DescriptorPublicKey>>,\n    last_revealed: HashMap<DescriptorId, u32>,\n    lookahead: u32,\n}\n\nimpl<K> Default for KeychainTxOutIndex<K> {\n    fn default() -> Self {\n        Self::new(DEFAULT_LOOKAHEAD)\n    }\n}\n\nimpl<K: Clone + Ord + Debug> Indexer for KeychainTxOutIndex<K> {\n    type ChangeSet = ChangeSet<K>;\n\n    fn index_txout(&mut self, outpoint: OutPoint, txout: &TxOut) -> Self::ChangeSet {\n        let mut changeset = ChangeSet::default();\n        if let Some((keychain, index)) = self.inner.scan_txout(outpoint, txout).cloned() {\n            let did = self\n                .keychain_to_descriptor_id\n                .get(&keychain)\n                .expect("invariant");\n            if self.last_revealed.get(did) < Some(&index) {\n                self.last_revealed.insert(*did, index);\n                changeset.last_revealed.insert(*did, index);\n                self.replenish_inner_index(*did, &keychain, self.lookahead);\n            }\n        }\n        changeset\n    }\n\n    fn index_tx(&mut self, tx: &bitcoin::Transaction) -> Self::ChangeSet {\n        let mut changeset = ChangeSet::<K>::default();\n        let txid = tx.compute_txid();\n        for (op, txout) in tx.output.iter().enumerate() {\n            changeset.append(self.index_txout(OutPoint::new(txid, op as u32), txout));\n        }\n        changeset\n    }\n\n    fn initial_changeset(&self) -> Self::ChangeSet {\n        ChangeSet {\n            keychains_added: self\n                .keychains()\n                .map(|(k, v)| (k.clone(), v.clone()))\n                .collect(),\n            last_revealed: self.last_revealed.clone().into_iter().collect(),\n        }\n    }\n\n    fn apply_changeset(&mut self, changeset: Self::ChangeSet) {\n        self.apply_changeset(changeset)\n    }\n\n    fn is_tx_relevant(&self, tx: &bitcoin::Transaction) -> bool {\n        self.inner.is_relevant(tx)\n    }\n}\n\nimpl<K> KeychainTxOutIndex<K> {\n    /// Construct a [`KeychainTxOutIndex`] with the given `lookahead`.\n    ///\n    /// The `lookahead` is the number of script pubkeys to derive and cache from the internal\n    /// descriptors over and above the last revealed script index. Without a lookahead the index\n    /// will miss outputs you own when processing transactions whose output script pubkeys lie\n    /// beyond the last revealed index. In certain situations, such as when performing an initial\n    /// scan of the blockchain during wallet import, it may be uncertain or unknown what the index\n    /// of the last revealed script pubkey actually is.\n    ///\n    /// Refer to [struct-level docs](KeychainTxOutIndex) for more about `lookahead`.\n    pub fn new(lookahead: u32) -> Self {\n        Self {\n            inner: SpkTxOutIndex::default(),\n            keychain_to_descriptor_id: Default::default(),\n            descriptors: Default::default(),\n            descriptor_id_to_keychain: Default::default(),\n            last_revealed: Default::default(),\n            lookahead,\n        }\n    }\n}\n\n/// Methods that are *re-exposed* from the internal [`SpkTxOutIndex`].\nimpl<K: Clone + Ord + Debug> KeychainTxOutIndex<K> {\n    /// Return a reference to the internal [`SpkTxOutIndex`].\n    ///\n    /// **WARNING**: The internal index will contain lookahead spks. Refer to\n    /// [struct-level docs](KeychainTxOutIndex) for more about `lookahead`.\n    pub fn inner(&self) -> &SpkTxOutIndex<(K, u32)> {\n        &self.inner\n    }\n\n    /// Get the set of indexed outpoints, corresponding to tracked keychains.\n    pub fn outpoints(&self) -> &BTreeSet<KeychainIndexed<K, OutPoint>> {\n        self.inner.outpoints()\n    }\n\n    /// Iterate over known txouts that spend to tracked script pubkeys.\n    pub fn txouts(\n        &self,\n    ) -> impl DoubleEndedIterator<Item = KeychainIndexed<K, (OutPoint, &TxOut)>> + ExactSizeIterator\n    {\n        self.inner\n            .txouts()\n            .map(|(index, op, txout)| (index.clone(), (op, txout)))\n    }\n\n    /// Finds all txouts on a transaction that has previously been scanned and indexed.\n    pub fn txouts_in_tx(\n        &self,\n        txid: Txid,\n    ) -> impl DoubleEndedIterator<Item = KeychainIndexed<K, (OutPoint, &TxOut)>> {\n        self.inner\n            .txouts_in_tx(txid)\n            .map(|(index, op, txout)| (index.clone(), (op, txout)))\n    }\n\n    /// Return the [`TxOut`] of `outpoint` if it has been indexed, and if it corresponds to a\n    /// tracked keychain.\n    ///\n    /// The associated keychain and keychain index of the txout\'s spk is also returned.\n    ///\n    /// This calls [`SpkTxOutIndex::txout`] internally.\n    pub fn txout(&self, outpoint: OutPoint) -> Option<KeychainIndexed<K, &TxOut>> {\n        self.inner\n            .txout(outpoint)\n            .map(|(index, txout)| (index.clone(), txout))\n    }\n\n    /// Return the script that exists under the given `keychain`\'s `index`.\n    ///\n    /// This calls [`SpkTxOutIndex::spk_at_index`] internally.\n    pub fn spk_at_index(&self, keychain: K, index: u32) -> Option<&Script> {\n        self.inner.spk_at_index(&(keychain.clone(), index))\n    }\n\n    /// Returns the keychain and keychain index associated with the spk.\n    ///\n    /// This calls [`SpkTxOutIndex::index_of_spk`] internally.\n    pub fn index_of_spk(&self, script: &Script) -> Option<&(K, u32)> {\n        self.inner.index_of_spk(script)\n    }\n\n    /// Returns whether the spk under the `keychain`\'s `index` has been used.\n    ///\n    /// Here, "unused" means that after the script pubkey was stored in the index, the index has\n    /// never scanned a transaction output with it.\n    ///\n    /// This calls [`SpkTxOutIndex::is_used`] internally.\n    pub fn is_used(&self, keychain: K, index: u32) -> bool {\n        self.inner.is_used(&(keychain, index))\n    }\n\n    /// Marks the script pubkey at `index` as used even though the tracker hasn\'t seen an output\n    /// with it.\n    ///\n    /// This only has an effect when the `index` had been added to `self` already and was unused.\n    ///\n    /// Returns whether the spk under the given `keychain` and `index` is successfully\n    /// marked as used. Returns false either when there is no descriptor under the given\n    /// keychain, or when the spk is already marked as used.\n    ///\n    /// This is useful when you want to reserve a script pubkey for something but don\'t want to add\n    /// the transaction output using it to the index yet. Other callers will consider `index` on\n    /// `keychain` used until you call [`unmark_used`].\n    ///\n    /// This calls [`SpkTxOutIndex::mark_used`] internally.\n    ///\n    /// [`unmark_used`]: Self::unmark_used\n    pub fn mark_used(&mut self, keychain: K, index: u32) -> bool {\n        self.inner.mark_used(&(keychain, index))\n    }\n\n    /// Undoes the effect of [`mark_used`]. Returns whether the `index` is inserted back into\n    /// `unused`.\n    ///\n    /// Note that if `self` has scanned an output with this script pubkey, then this will have no\n    /// effect.\n    ///\n    /// This calls [`SpkTxOutIndex::unmark_used`] internally.\n    ///\n    /// [`mark_used`]: Self::mark_used\n    pub fn unmark_used(&mut self, keychain: K, index: u32) -> bool {\n        self.inner.unmark_used(&(keychain, index))\n    }\n\n    /// Computes the total value transfer effect `tx` has on the script pubkeys belonging to the\n    /// keychains in `range`. Value is *sent* when a script pubkey in the `range` is on an input and\n    /// *received* when it is on an output. For `sent` to be computed correctly, the output being\n    /// spent must have already been scanned by the index. Calculating received just uses the\n    /// [`Transaction`] outputs directly, so it will be correct even if it has not been scanned.\n    pub fn sent_and_received(\n        &self,\n        tx: &Transaction,\n        range: impl RangeBounds<K>,\n    ) -> (Amount, Amount) {\n        self.inner\n            .sent_and_received(tx, self.map_to_inner_bounds(range))\n    }\n\n    /// Computes the net value that this transaction gives to the script pubkeys in the index and\n    /// *takes* from the transaction outputs in the index. Shorthand for calling\n    /// [`sent_and_received`] and subtracting sent from received.\n    ///\n    /// This calls [`SpkTxOutIndex::net_value`] internally.\n    ///\n    /// [`sent_and_received`]: Self::sent_and_received\n    pub fn net_value(&self, tx: &Transaction, range: impl RangeBounds<K>) -> SignedAmount {\n        self.inner.net_value(tx, self.map_to_inner_bounds(range))\n    }\n}\n\nimpl<K: Clone + Ord + Debug> KeychainTxOutIndex<K> {\n    /// Return all keychains and their corresponding descriptors.\n    pub fn keychains(\n        &self,\n    ) -> impl DoubleEndedIterator<Item = (&K, &Descriptor<DescriptorPublicKey>)> + ExactSizeIterator + \'_\n    {\n        self.keychain_to_descriptor_id\n            .iter()\n            .map(|(k, did)| (k, self.descriptors.get(did).expect("invariant")))\n    }\n\n    /// Insert a descriptor with a keychain associated to it.\n    ///\n    /// Adding a descriptor means you will be able to derive new script pubkeys under it and the\n    /// txout index will discover transaction outputs with those script pubkeys (once they\'ve been\n    /// derived and added to the index).\n    ///\n    /// keychain <-> descriptor is a one-to-one mapping that cannot be changed. Attempting to do so\n    /// will return a [`InsertDescriptorError<K>`].\n    pub fn insert_descriptor(\n        &mut self,\n        keychain: K,\n        descriptor: Descriptor<DescriptorPublicKey>,\n    ) -> Result<ChangeSet<K>, InsertDescriptorError<K>> {\n        let mut changeset = ChangeSet::<K>::default();\n        let did = descriptor.descriptor_id();\n        if !self.keychain_to_descriptor_id.contains_key(&keychain)\n            && !self.descriptor_id_to_keychain.contains_key(&did)\n        {\n            self.descriptors.insert(did, descriptor.clone());\n            self.keychain_to_descriptor_id.insert(keychain.clone(), did);\n            self.descriptor_id_to_keychain.insert(did, keychain.clone());\n            self.replenish_inner_index(did, &keychain, self.lookahead);\n            changeset\n                .keychains_added\n                .insert(keychain.clone(), descriptor);\n        } else {\n            if let Some(existing_desc_id) = self.keychain_to_descriptor_id.get(&keychain) {\n                let descriptor = self.descriptors.get(existing_desc_id).expect("invariant");\n                if *existing_desc_id != did {\n                    return Err(InsertDescriptorError::KeychainAlreadyAssigned {\n                        existing_assignment: descriptor.clone(),\n                        keychain,\n                    });\n                }\n            }\n\n            if let Some(existing_keychain) = self.descriptor_id_to_keychain.get(&did) {\n                let descriptor = self.descriptors.get(&did).expect("invariant").clone();\n\n                if *existing_keychain != keychain {\n                    return Err(InsertDescriptorError::DescriptorAlreadyAssigned {\n                        existing_assignment: existing_keychain.clone(),\n                        descriptor,\n                    });\n                }\n            }\n        }\n\n        Ok(changeset)\n    }\n\n    /// Gets the descriptor associated with the keychain. Returns `None` if the keychain doesn\'t\n    /// have a descriptor associated with it.\n    pub fn get_descriptor(&self, keychain: &K) -> Option<&Descriptor<DescriptorPublicKey>> {\n        let did = self.keychain_to_descriptor_id.get(keychain)?;\n        self.descriptors.get(did)\n    }\n\n    /// Get the lookahead setting.\n    ///\n    /// Refer to [`new`] for more information on the `lookahead`.\n    ///\n    /// [`new`]: Self::new\n    pub fn lookahead(&self) -> u32 {\n        self.lookahead\n    }\n\n    /// Store lookahead scripts until `target_index` (inclusive).\n    ///\n    /// This does not change the global `lookahead` setting.\n    pub fn lookahead_to_target(&mut self, keychain: &K, target_index: u32) {\n        if let Some((next_index, _)) = self.next_index(keychain) {\n            let temp_lookahead = (target_index + 1)\n                .checked_sub(next_index)\n                .filter(|&index| index > 0);\n\n            if let Some(temp_lookahead) = temp_lookahead {\n                self.replenish_inner_index_keychain(keychain, temp_lookahead);\n            }\n        }\n    }\n\n    fn replenish_inner_index_did(&mut self, did: DescriptorId, lookahead: u32) {\n        if let Some(keychain) = self.descriptor_id_to_keychain.get(&did).cloned() {\n            self.replenish_inner_index(did, &keychain, lookahead);\n        }\n    }\n\n    fn replenish_inner_index_keychain(&mut self, keychain: &K, lookahead: u32) {\n        if let Some(did) = self.keychain_to_descriptor_id.get(keychain) {\n            self.replenish_inner_index(*did, keychain, lookahead);\n        }\n    }\n\n    /// Syncs the state of the inner spk index after changes to a keychain\n    fn replenish_inner_index(&mut self, did: DescriptorId, keychain: &K, lookahead: u32) {\n        let descriptor = self.descriptors.get(&did).expect("invariant");\n        let next_store_index = self\n            .inner\n            .all_spks()\n            .range(&(keychain.clone(), u32::MIN)..=&(keychain.clone(), u32::MAX))\n            .last()\n            .map_or(0, |((_, index), _)| *index + 1);\n        let next_reveal_index = self.last_revealed.get(&did).map_or(0, |v| *v + 1);\n        for (new_index, new_spk) in\n            SpkIterator::new_with_range(descriptor, next_store_index..next_reveal_index + lookahead)\n        {\n            let _inserted = self\n                .inner\n                .insert_spk((keychain.clone(), new_index), new_spk);\n            debug_assert!(_inserted, "replenish lookahead: must not have existing spk: keychain={:?}, lookahead={}, next_store_index={}, next_reveal_index={}", keychain, lookahead, next_store_index, next_reveal_index);\n        }\n    }\n\n    /// Get an unbounded spk iterator over a given `keychain`. Returns `None` if the provided\n    /// keychain doesn\'t exist\n    pub fn unbounded_spk_iter(\n        &self,\n        keychain: &K,\n    ) -> Option<SpkIterator<Descriptor<DescriptorPublicKey>>> {\n        let descriptor = self.get_descriptor(keychain)?.clone();\n        Some(SpkIterator::new(descriptor))\n    }\n\n    /// Get unbounded spk iterators for all keychains.\n    pub fn all_unbounded_spk_iters(\n        &self,\n    ) -> BTreeMap<K, SpkIterator<Descriptor<DescriptorPublicKey>>> {\n        self.keychain_to_descriptor_id\n            .iter()\n            .map(|(k, did)| {\n                (\n                    k.clone(),\n                    SpkIterator::new(self.descriptors.get(did).expect("invariant").clone()),\n                )\n            })\n            .collect()\n    }\n\n    /// Iterate over revealed spks of keychains in `range`\n    pub fn revealed_spks(\n        &self,\n        range: impl RangeBounds<K>,\n    ) -> impl Iterator<Item = KeychainIndexed<K, &Script>> {\n        let start = range.start_bound();\n        let end = range.end_bound();\n        let mut iter_last_revealed = self\n            .keychain_to_descriptor_id\n            .range((start, end))\n            .map(|(k, did)| (k, self.last_revealed.get(did).cloned()));\n        let mut iter_spks = self\n            .inner\n            .all_spks()\n            .range(self.map_to_inner_bounds((start, end)));\n        let mut current_keychain = iter_last_revealed.next();\n        // The reason we need a tricky algorithm is because of the "lookahead" feature which means\n        // that some of the spks in the SpkTxoutIndex will not have been revealed yet. So we need to\n        // filter out those spks that are above the last_revealed for that keychain. To do this we\n        // iterate through the last_revealed for each keychain and the spks for each keychain in\n        // tandem. This minimizes BTreeMap queries.\n        core::iter::from_fn(move || loop {\n            let ((keychain, index), spk) = iter_spks.next()?;\n            // We need to find the last revealed that matches the current spk we are considering so\n            // we skip ahead.\n            while current_keychain?.0 < keychain {\n                current_keychain = iter_last_revealed.next();\n            }\n            let (current_keychain, last_revealed) = current_keychain?;\n\n            if current_keychain == keychain && Some(*index) <= last_revealed {\n                break Some(((keychain.clone(), *index), spk.as_script()));\n            }\n        })\n    }\n\n    /// Iterate over revealed spks of the given `keychain` with ascending indices.\n    ///\n    /// This is a double ended iterator so you can easily reverse it to get an iterator where\n    /// the script pubkeys that were most recently revealed are first.\n    pub fn revealed_keychain_spks<\'a>(\n        &\'a self,\n        keychain: &\'a K,\n    ) -> impl DoubleEndedIterator<Item = Indexed<&Script>> + \'a {\n        let end = self\n            .last_revealed_index(keychain)\n            .map(|v| v + 1)\n            .unwrap_or(0);\n        self.inner\n            .all_spks()\n            .range((keychain.clone(), 0)..(keychain.clone(), end))\n            .map(|((_, index), spk)| (*index, spk.as_script()))\n    }\n\n    /// Iterate over revealed, but unused, spks of all keychains.\n    pub fn unused_spks(\n        &self,\n    ) -> impl DoubleEndedIterator<Item = KeychainIndexed<K, &Script>> + Clone {\n        self.keychain_to_descriptor_id.keys().flat_map(|keychain| {\n            self.unused_keychain_spks(keychain)\n                .map(|(i, spk)| ((keychain.clone(), i), spk))\n        })\n    }\n\n    /// Iterate over revealed, but unused, spks of the given `keychain`.\n    /// Returns an empty iterator if the provided keychain doesn\'t exist.\n    pub fn unused_keychain_spks(\n        &self,\n        keychain: &K,\n    ) -> impl DoubleEndedIterator<Item = Indexed<&Script>> + Clone {\n        let end = match self.keychain_to_descriptor_id.get(keychain) {\n            Some(did) => self.last_revealed.get(did).map(|v| *v + 1).unwrap_or(0),\n            None => 0,\n        };\n\n        self.inner\n            .unused_spks((keychain.clone(), 0)..(keychain.clone(), end))\n            .map(|((_, i), spk)| (*i, spk))\n    }\n\n    /// Get the next derivation index for `keychain`. The next index is the index after the last revealed\n    /// derivation index.\n    ///\n    /// The second field in the returned tuple represents whether the next derivation index is new.\n    /// There are two scenarios where the next derivation index is reused (not new):\n    ///\n    /// 1. The keychain\'s descriptor has no wildcard, and a script has already been revealed.\n    /// 2. The number of revealed scripts has already reached 2^31 (refer to BIP-32).\n    ///\n    /// Not checking the second field of the tuple may result in address reuse.\n    ///\n    /// Returns None if the provided `keychain` doesn\'t exist.\n    pub fn next_index(&self, keychain: &K) -> Option<(u32, bool)> {\n        let did = self.keychain_to_descriptor_id.get(keychain)?;\n        let last_index = self.last_revealed.get(did).cloned();\n        let descriptor = self.descriptors.get(did).expect("invariant");\n\n        // we can only get the next index if the wildcard exists.\n        let has_wildcard = descriptor.has_wildcard();\n\n        Some(match last_index {\n            // if there is no index, next_index is always 0.\n            None => (0, true),\n            // descriptors without wildcards can only have one index.\n            Some(_) if !has_wildcard => (0, false),\n            // derivation index must be < 2^31 (BIP-32).\n            Some(index) if index > BIP32_MAX_INDEX => {\n                unreachable!("index is out of bounds")\n            }\n            Some(index) if index == BIP32_MAX_INDEX => (index, false),\n            // get the next derivation index.\n            Some(index) => (index + 1, true),\n        })\n    }\n\n    /// Get the last derivation index that is revealed for each keychain.\n    ///\n    /// Keychains with no revealed indices will not be included in the returned [`BTreeMap`].\n    pub fn last_revealed_indices(&self) -> BTreeMap<K, u32> {\n        self.last_revealed\n            .iter()\n            .filter_map(|(desc_id, index)| {\n                let keychain = self.descriptor_id_to_keychain.get(desc_id)?;\n                Some((keychain.clone(), *index))\n            })\n            .collect()\n    }\n\n    /// Get the last derivation index revealed for `keychain`. Returns None if the keychain doesn\'t\n    /// exist, or if the keychain doesn\'t have any revealed scripts.\n    pub fn last_revealed_index(&self, keychain: &K) -> Option<u32> {\n        let descriptor_id = self.keychain_to_descriptor_id.get(keychain)?;\n        self.last_revealed.get(descriptor_id).cloned()\n    }\n\n    /// Convenience method to call [`Self::reveal_to_target`] on multiple keychains.\n    pub fn reveal_to_target_multi(&mut self, keychains: &BTreeMap<K, u32>) -> ChangeSet<K> {\n        let mut changeset = ChangeSet::default();\n\n        for (keychain, &index) in keychains {\n            if let Some((_, new_changeset)) = self.reveal_to_target(keychain, index) {\n                changeset.append(new_changeset);\n            }\n        }\n\n        changeset\n    }\n\n    /// Reveals script pubkeys of the `keychain`\'s descriptor **up to and including** the\n    /// `target_index`.\n    ///\n    /// If the `target_index` cannot be reached (due to the descriptor having no wildcard and/or\n    /// the `target_index` is in the hardened index range), this method will make a best-effort and\n    /// reveal up to the last possible index.\n    ///\n    /// This returns list of newly revealed indices (alongside their scripts) and a\n    /// [`ChangeSet`], which reports updates to the latest revealed index. If no new script\n    /// pubkeys are revealed, then both of these will be empty.\n    ///\n    /// Returns None if the provided `keychain` doesn\'t exist.\n    #[must_use]\n    pub fn reveal_to_target(\n        &mut self,\n        keychain: &K,\n        target_index: u32,\n    ) -> Option<(Vec<Indexed<ScriptBuf>>, ChangeSet<K>)> {\n        let mut changeset = ChangeSet::default();\n        let mut spks: Vec<Indexed<ScriptBuf>> = vec![];\n        while let Some((i, new)) = self.next_index(keychain) {\n            if !new || i > target_index {\n                break;\n            }\n            match self.reveal_next_spk(keychain) {\n                Some(((i, spk), change)) => {\n                    spks.push((i, spk));\n                    changeset.append(change);\n                }\n                None => break,\n            }\n        }\n\n        Some((spks, changeset))\n    }\n\n    /// Attempts to reveal the next script pubkey for `keychain`.\n    ///\n    /// Returns the derivation index of the revealed script pubkey, the revealed script pubkey and a\n    /// [`ChangeSet`] which represents changes in the last revealed index (if any).\n    /// Returns None if the provided keychain doesn\'t exist.\n    ///\n    /// When a new script cannot be revealed, we return the last revealed script and an empty\n    /// [`ChangeSet`]. There are two scenarios when a new script pubkey cannot be derived:\n    ///\n    ///  1. The descriptor has no wildcard and already has one script revealed.\n    ///  2. The descriptor has already revealed scripts up to the numeric bound.\n    ///  3. There is no descriptor associated with the given keychain.\n    pub fn reveal_next_spk(&mut self, keychain: &K) -> Option<(Indexed<ScriptBuf>, ChangeSet<K>)> {\n        let (next_index, new) = self.next_index(keychain)?;\n        let mut changeset = ChangeSet::default();\n\n        if new {\n            let did = self.keychain_to_descriptor_id.get(keychain)?;\n            self.last_revealed.insert(*did, next_index);\n            changeset.last_revealed.insert(*did, next_index);\n            self.replenish_inner_index(*did, keychain, self.lookahead);\n        }\n        let script = self\n            .inner\n            .spk_at_index(&(keychain.clone(), next_index))\n            .expect("we just inserted it");\n        Some(((next_index, script.into()), changeset))\n    }\n\n    /// Gets the next unused script pubkey in the keychain. I.e., the script pubkey with the lowest\n    /// index that has not been used yet.\n    ///\n    /// This will derive and reveal a new script pubkey if no more unused script pubkeys exist.\n    ///\n    /// If the descriptor has no wildcard and already has a used script pubkey or if a descriptor\n    /// has used all scripts up to the derivation bounds, then the last derived script pubkey will be\n    /// returned.\n    ///\n    /// Returns `None` if there are no script pubkeys that have been used and no new script pubkey\n    /// could be revealed (see [`reveal_next_spk`] for when this happens).\n    ///\n    /// [`reveal_next_spk`]: Self::reveal_next_spk\n    pub fn next_unused_spk(&mut self, keychain: &K) -> Option<(Indexed<ScriptBuf>, ChangeSet<K>)> {\n        let next_unused = self\n            .unused_keychain_spks(keychain)\n            .next()\n            .map(|(i, spk)| ((i, spk.to_owned()), ChangeSet::default()));\n\n        next_unused.or_else(|| self.reveal_next_spk(keychain))\n    }\n\n    /// Iterate over all [`OutPoint`]s that have `TxOut`s with script pubkeys derived from\n    /// `keychain`.\n    pub fn keychain_outpoints<\'a>(\n        &\'a self,\n        keychain: &\'a K,\n    ) -> impl DoubleEndedIterator<Item = Indexed<OutPoint>> + \'a {\n        self.keychain_outpoints_in_range(keychain..=keychain)\n            .map(|((_, i), op)| (i, op))\n    }\n\n    /// Iterate over [`OutPoint`]s that have script pubkeys derived from keychains in `range`.\n    pub fn keychain_outpoints_in_range<\'a>(\n        &\'a self,\n        range: impl RangeBounds<K> + \'a,\n    ) -> impl DoubleEndedIterator<Item = KeychainIndexed<K, OutPoint>> + \'a {\n        self.inner\n            .outputs_in_range(self.map_to_inner_bounds(range))\n            .map(|((k, i), op)| ((k.clone(), *i), op))\n    }\n\n    fn map_to_inner_bounds(&self, bound: impl RangeBounds<K>) -> impl RangeBounds<(K, u32)> {\n        let start = match bound.start_bound() {\n            Bound::Included(keychain) => Bound::Included((keychain.clone(), u32::MIN)),\n            Bound::Excluded(keychain) => Bound::Excluded((keychain.clone(), u32::MAX)),\n            Bound::Unbounded => Bound::Unbounded,\n        };\n        let end = match bound.end_bound() {\n            Bound::Included(keychain) => Bound::Included((keychain.clone(), u32::MAX)),\n            Bound::Excluded(keychain) => Bound::Excluded((keychain.clone(), u32::MIN)),\n            Bound::Unbounded => Bound::Unbounded,\n        };\n\n        (start, end)\n    }\n\n    /// Returns the highest derivation index of the `keychain` where [`KeychainTxOutIndex`] has\n    /// found a [`TxOut`] with it\'s script pubkey.\n    pub fn last_used_index(&self, keychain: &K) -> Option<u32> {\n        self.keychain_outpoints(keychain).last().map(|(i, _)| i)\n    }\n\n    /// Returns the highest derivation index of each keychain that [`KeychainTxOutIndex`] has found\n    /// a [`TxOut`] with it\'s script pubkey.\n    pub fn last_used_indices(&self) -> BTreeMap<K, u32> {\n        self.keychain_to_descriptor_id\n            .iter()\n            .filter_map(|(keychain, _)| {\n                self.last_used_index(keychain)\n                    .map(|index| (keychain.clone(), index))\n            })\n            .collect()\n    }\n\n    /// Applies the `ChangeSet<K>` to the [`KeychainTxOutIndex<K>`]\n    ///\n    /// Keychains added by the `keychains_added` field of `ChangeSet<K>` respect the one-to-one\n    /// keychain <-> descriptor invariant by silently ignoring attempts to violate it (but will\n    /// panic if `debug_assertions` are enabled).\n    pub fn apply_changeset(&mut self, changeset: ChangeSet<K>) {\n        let ChangeSet {\n            keychains_added,\n            last_revealed,\n        } = changeset;\n        for (keychain, descriptor) in keychains_added {\n            let _ignore_invariant_violation = self.insert_descriptor(keychain, descriptor);\n        }\n\n        for (&desc_id, &index) in &last_revealed {\n            let v = self.last_revealed.entry(desc_id).or_default();\n            *v = index.max(*v);\n        }\n\n        for did in last_revealed.keys() {\n            self.replenish_inner_index_did(*did, self.lookahead);\n        }\n    }\n}\n\n#[derive(Clone, Debug, PartialEq)]\n/// Error returned from [`KeychainTxOutIndex::insert_descriptor`]\npub enum InsertDescriptorError<K> {\n    /// The descriptor has already been assigned to a keychain so you can\'t assign it to another\n    DescriptorAlreadyAssigned {\n        /// The descriptor you have attempted to reassign\n        descriptor: Descriptor<DescriptorPublicKey>,\n        /// The keychain that the descriptor is already assigned to\n        existing_assignment: K,\n    },\n    /// The keychain is already assigned to a descriptor so you can\'t reassign it\n    KeychainAlreadyAssigned {\n        /// The keychain that you have attempted to reassign\n        keychain: K,\n        /// The descriptor that the keychain is already assigned to\n        existing_assignment: Descriptor<DescriptorPublicKey>,\n    },\n}\n\nimpl<K: core::fmt::Debug> core::fmt::Display for InsertDescriptorError<K> {\n    fn fmt(&self, f: &mut core::fmt::Formatter<\'_>) -> core::fmt::Result {\n        match self {\n            InsertDescriptorError::DescriptorAlreadyAssigned {\n                existing_assignment: existing,\n                descriptor,\n            } => {\n                write!(\n                    f,\n                    "attempt to re-assign descriptor {descriptor:?} already assigned to {existing:?}"\n                )\n            }\n            InsertDescriptorError::KeychainAlreadyAssigned {\n                existing_assignment: existing,\n                keychain,\n            } => {\n                write!(\n                    f,\n                    "attempt to re-assign keychain {keychain:?} already assigned to {existing:?}"\n                )\n            }\n        }\n    }\n}\n\n#[cfg(feature = "std")]\nimpl<K: core::fmt::Debug> std::error::Error for InsertDescriptorError<K> {}\n\n/// Represents updates to the derivation index of a [`KeychainTxOutIndex`].\n/// It maps each keychain `K` to a descriptor and its last revealed index.\n///\n/// It can be applied to [`KeychainTxOutIndex`] with [`apply_changeset`].\n///\n/// The `last_revealed` field is monotone in that [`append`] will never decrease it.\n/// `keychains_added` is *not* monotone, once it is set any attempt to change it is subject to the\n/// same *one-to-one* keychain <-> descriptor mapping invariant as [`KeychainTxOutIndex`] itself.\n///\n/// [`KeychainTxOutIndex`]: crate::keychain::KeychainTxOutIndex\n/// [`apply_changeset`]: crate::keychain::KeychainTxOutIndex::apply_changeset\n/// [`append`]: Self::append\n#[derive(Clone, Debug, PartialEq)]\n#[cfg_attr(\n    feature = "serde",\n    derive(serde::Deserialize, serde::Serialize),\n    serde(\n        crate = "serde_crate",\n        bound(\n            deserialize = "K: Ord + serde::Deserialize<\'de>",\n            serialize = "K: Ord + serde::Serialize"\n        )\n    )\n)]\n#[must_use]\npub struct ChangeSet<K> {\n    /// Contains the keychains that have been added and their respective descriptor\n    pub keychains_added: BTreeMap<K, Descriptor<DescriptorPublicKey>>,\n    /// Contains for each descriptor_id the last revealed index of derivation\n    pub last_revealed: BTreeMap<DescriptorId, u32>,\n}\n\nimpl<K: Ord> Append for ChangeSet<K> {\n    /// Merge another [`ChangeSet<K>`] into self.\n    ///\n    /// For the `keychains_added` field this method respects the invariants of\n    /// [`insert_descriptor`]. `last_revealed` always becomes the larger of the two.\n    ///\n    /// [`insert_descriptor`]: KeychainTxOutIndex::insert_descriptor\n    fn append(&mut self, other: Self) {\n        for (new_keychain, new_descriptor) in other.keychains_added {\n            // enforce 1-to-1 invariance\n            if !self.keychains_added.contains_key(&new_keychain)\n                // FIXME: very inefficient\n                && self\n                    .keychains_added\n                    .values()\n                    .all(|descriptor| descriptor != &new_descriptor)\n            {\n                self.keychains_added.insert(new_keychain, new_descriptor);\n            }\n        }\n\n        // for `last_revealed`, entries of `other` will take precedence ONLY if it is greater than\n        // what was originally in `self`.\n        for (desc_id, index) in other.last_revealed {\n            use crate::collections::btree_map::Entry;\n            match self.last_revealed.entry(desc_id) {\n                Entry::Vacant(entry) => {\n                    entry.insert(index);\n                }\n                Entry::Occupied(mut entry) => {\n                    if *entry.get() < index {\n                        entry.insert(index);\n                    }\n                }\n            }\n        }\n    }\n\n    /// Returns whether the changeset are empty.\n    fn is_empty(&self) -> bool {\n        self.last_revealed.is_empty() && self.keychains_added.is_empty()\n    }\n}\n\nimpl<K> Default for ChangeSet<K> {\n    fn default() -> Self {\n        Self {\n            last_revealed: BTreeMap::default(),\n            keychains_added: BTreeMap::default(),\n        }\n    }\n}\n\n#[derive(Clone, Debug, Eq, PartialEq)]\n/// The keychain doesn\'t exist. Most likley hasn\'t been inserted with [`KeychainTxOutIndex::insert_descriptor`].\npub struct NoSuchKeychain<K>(K);\n\nimpl<K: Debug> core::fmt::Display for NoSuchKeychain<K> {\n    fn fmt(&self, f: &mut core::fmt::Formatter<\'_>) -> core::fmt::Result {\n        write!(f, "no such keychain {:?} exists", &self.0)\n    }\n}\n',
            'crates/wallet/src/wallet/mod.rs': '// Bitcoin Dev Kit\n// Written in 2020 by Alekos Filini <alekos.filini@gmail.com>\n//\n// Copyright (c) 2020-2021 Bitcoin Dev Kit Developers\n//\n// This file is licensed under the Apache License, Version 2.0 <LICENSE-APACHE\n// or http://www.apache.org/licenses/LICENSE-2.0> or the MIT license\n// <LICENSE-MIT or http://opensource.org/licenses/MIT>, at your option.\n// You may not use this file except in accordance with one or both of these\n// licenses.\n\n//! Wallet\n//!\n//! This module defines the [`Wallet`].\nuse crate::collections::{BTreeMap, HashMap};\nuse alloc::{\n    boxed::Box,\n    string::{String, ToString},\n    sync::Arc,\n    vec::Vec,\n};\npub use bdk_chain::keychain::Balance;\nuse bdk_chain::{\n    indexed_tx_graph,\n    keychain::KeychainTxOutIndex,\n    local_chain::{\n        self, ApplyHeaderError, CannotConnectError, CheckPoint, CheckPointIter, LocalChain,\n    },\n    spk_client::{FullScanRequest, FullScanResult, SyncRequest, SyncResult},\n    tx_graph::{CanonicalTx, TxGraph},\n    Append, BlockId, ChainPosition, ConfirmationTime, ConfirmationTimeHeightAnchor, FullTxOut,\n    Indexed, IndexedTxGraph,\n};\nuse bitcoin::sighash::{EcdsaSighashType, TapSighashType};\nuse bitcoin::{\n    absolute, psbt, Address, Block, FeeRate, Network, OutPoint, Script, ScriptBuf, Sequence,\n    Transaction, TxOut, Txid, Witness,\n};\nuse bitcoin::{consensus::encode::serialize, transaction, BlockHash, Psbt};\nuse bitcoin::{constants::genesis_block, Amount};\nuse bitcoin::{\n    secp256k1::{All, Secp256k1},\n    Weight,\n};\nuse core::fmt;\nuse core::mem;\nuse core::ops::Deref;\nuse rand_core::RngCore;\n\nuse descriptor::error::Error as DescriptorError;\nuse miniscript::psbt::{PsbtExt, PsbtInputExt, PsbtInputSatisfier};\n\nuse bdk_chain::tx_graph::CalculateFeeError;\n\npub mod coin_selection;\npub mod export;\npub mod signer;\npub mod tx_builder;\npub(crate) mod utils;\n\npub mod error;\n\npub use utils::IsDust;\n\nuse coin_selection::DefaultCoinSelectionAlgorithm;\nuse signer::{SignOptions, SignerOrdering, SignersContainer, TransactionSigner};\nuse tx_builder::{FeePolicy, TxBuilder, TxParams};\nuse utils::{check_nsequence_rbf, After, Older, SecpCtx};\n\nuse crate::descriptor::policy::BuildSatisfaction;\nuse crate::descriptor::{\n    self, calc_checksum, into_wallet_descriptor_checked, DerivedDescriptor, DescriptorMeta,\n    ExtendedDescriptor, ExtractPolicy, IntoWalletDescriptor, Policy, XKeyUtils,\n};\nuse crate::psbt::PsbtUtils;\nuse crate::signer::SignerError;\nuse crate::types::*;\nuse crate::wallet::coin_selection::Excess::{Change, NoChange};\nuse crate::wallet::error::{BuildFeeBumpError, CreateTxError, MiniscriptPsbtError};\n\nuse self::coin_selection::Error;\n\nconst COINBASE_MATURITY: u32 = 100;\n\n/// A Bitcoin wallet\n///\n/// The `Wallet` acts as a way of coherently interfacing with output descriptors and related transactions.\n/// Its main components are:\n///\n/// 1. output *descriptors* from which it can derive addresses.\n/// 2. [`signer`]s that can contribute signatures to addresses instantiated from the descriptors.\n///\n/// The user is responsible for loading and writing wallet changes which are represented as\n/// [`ChangeSet`]s (see [`take_staged`]). Also see individual functions and example for instructions\n/// on when [`Wallet`] state needs to be persisted.\n///\n/// [`signer`]: crate::signer\n/// [`take_staged`]: Wallet::take_staged\n#[derive(Debug)]\npub struct Wallet {\n    signers: Arc<SignersContainer>,\n    change_signers: Arc<SignersContainer>,\n    chain: LocalChain,\n    indexed_graph: IndexedTxGraph<ConfirmationTimeHeightAnchor, KeychainTxOutIndex<KeychainKind>>,\n    stage: ChangeSet,\n    network: Network,\n    secp: SecpCtx,\n}\n\n/// An update to [`Wallet`].\n///\n/// It updates [`bdk_chain::keychain::KeychainTxOutIndex`], [`bdk_chain::TxGraph`] and [`local_chain::LocalChain`] atomically.\n#[derive(Debug, Clone, Default)]\npub struct Update {\n    /// Contains the last active derivation indices per keychain (`K`), which is used to update the\n    /// [`KeychainTxOutIndex`].\n    pub last_active_indices: BTreeMap<KeychainKind, u32>,\n\n    /// Update for the wallet\'s internal [`TxGraph`].\n    pub graph: TxGraph<ConfirmationTimeHeightAnchor>,\n\n    /// Update for the wallet\'s internal [`LocalChain`].\n    ///\n    /// [`LocalChain`]: local_chain::LocalChain\n    pub chain: Option<CheckPoint>,\n}\n\nimpl From<FullScanResult<KeychainKind>> for Update {\n    fn from(value: FullScanResult<KeychainKind>) -> Self {\n        Self {\n            last_active_indices: value.last_active_indices,\n            graph: value.graph_update,\n            chain: Some(value.chain_update),\n        }\n    }\n}\n\nimpl From<SyncResult> for Update {\n    fn from(value: SyncResult) -> Self {\n        Self {\n            last_active_indices: BTreeMap::new(),\n            graph: value.graph_update,\n            chain: Some(value.chain_update),\n        }\n    }\n}\n\n/// The changes made to a wallet by applying an [`Update`].\npub type ChangeSet = bdk_chain::CombinedChangeSet<KeychainKind, ConfirmationTimeHeightAnchor>;\n\n/// A derived address and the index it was found at.\n/// For convenience this automatically derefs to `Address`\n#[derive(Debug, PartialEq, Eq)]\npub struct AddressInfo {\n    /// Child index of this address\n    pub index: u32,\n    /// Address\n    pub address: Address,\n    /// Type of keychain\n    pub keychain: KeychainKind,\n}\n\nimpl Deref for AddressInfo {\n    type Target = Address;\n\n    fn deref(&self) -> &Self::Target {\n        &self.address\n    }\n}\n\nimpl fmt::Display for AddressInfo {\n    fn fmt(&self, f: &mut fmt::Formatter<\'_>) -> fmt::Result {\n        write!(f, "{}", self.address)\n    }\n}\n\n/// The error type when constructing a fresh [`Wallet`].\n///\n/// Methods [`new`] and [`new_with_genesis_hash`] may return this error.\n///\n/// [`new`]: Wallet::new\n/// [`new_with_genesis_hash`]: Wallet::new_with_genesis_hash\n#[derive(Debug)]\npub enum NewError {\n    /// There was problem with the passed-in descriptor(s).\n    Descriptor(crate::descriptor::DescriptorError),\n}\n\nimpl fmt::Display for NewError {\n    fn fmt(&self, f: &mut fmt::Formatter<\'_>) -> fmt::Result {\n        match self {\n            NewError::Descriptor(e) => e.fmt(f),\n        }\n    }\n}\n\n#[cfg(feature = "std")]\nimpl std::error::Error for NewError {}\n\n/// The error type when loading a [`Wallet`] from a [`ChangeSet`].\n///\n/// Method [`load_from_changeset`] may return this error.\n///\n/// [`load_from_changeset`]: Wallet::load_from_changeset\n#[derive(Debug)]\npub enum LoadError {\n    /// There was a problem with the passed-in descriptor(s).\n    Descriptor(crate::descriptor::DescriptorError),\n    /// Data loaded from persistence is missing network type.\n    MissingNetwork,\n    /// Data loaded from persistence is missing genesis hash.\n    MissingGenesis,\n    /// Data loaded from persistence is missing descriptor.\n    MissingDescriptor(KeychainKind),\n}\n\nimpl fmt::Display for LoadError {\n    fn fmt(&self, f: &mut fmt::Formatter<\'_>) -> fmt::Result {\n        match self {\n            LoadError::Descriptor(e) => e.fmt(f),\n            LoadError::MissingNetwork => write!(f, "loaded data is missing network type"),\n            LoadError::MissingGenesis => write!(f, "loaded data is missing genesis hash"),\n            LoadError::MissingDescriptor(k) => {\n                write!(f, "loaded data is missing descriptor for keychain {k:?}")\n            }\n        }\n    }\n}\n\n#[cfg(feature = "std")]\nimpl std::error::Error for LoadError {}\n\n/// Error type for when we try load a [`Wallet`] from persistence and creating it if non-existent.\n///\n/// Methods [`new_or_load`] and [`new_or_load_with_genesis_hash`] may return this error.\n///\n/// [`new_or_load`]: Wallet::new_or_load\n/// [`new_or_load_with_genesis_hash`]: Wallet::new_or_load_with_genesis_hash\n#[derive(Debug)]\npub enum NewOrLoadError {\n    /// There is a problem with the passed-in descriptor.\n    Descriptor(crate::descriptor::DescriptorError),\n    /// The loaded genesis hash does not match what was provided.\n    LoadedGenesisDoesNotMatch {\n        /// The expected genesis block hash.\n        expected: BlockHash,\n        /// The block hash loaded from persistence.\n        got: Option<BlockHash>,\n    },\n    /// The loaded network type does not match what was provided.\n    LoadedNetworkDoesNotMatch {\n        /// The expected network type.\n        expected: Network,\n        /// The network type loaded from persistence.\n        got: Option<Network>,\n    },\n    /// The loaded desccriptor does not match what was provided.\n    LoadedDescriptorDoesNotMatch {\n        /// The descriptor loaded from persistence.\n        got: Option<ExtendedDescriptor>,\n        /// The keychain of the descriptor not matching\n        keychain: KeychainKind,\n    },\n}\n\nimpl fmt::Display for NewOrLoadError {\n    fn fmt(&self, f: &mut fmt::Formatter<\'_>) -> fmt::Result {\n        match self {\n            NewOrLoadError::Descriptor(e) => e.fmt(f),\n            NewOrLoadError::LoadedGenesisDoesNotMatch { expected, got } => {\n                write!(f, "loaded genesis hash is not {}, got {:?}", expected, got)\n            }\n            NewOrLoadError::LoadedNetworkDoesNotMatch { expected, got } => {\n                write!(f, "loaded network type is not {}, got {:?}", expected, got)\n            }\n            NewOrLoadError::LoadedDescriptorDoesNotMatch { got, keychain } => {\n                write!(\n                    f,\n                    "loaded descriptor is different from what was provided, got {:?} for keychain {:?}",\n                    got, keychain\n                )\n            }\n        }\n    }\n}\n\n#[cfg(feature = "std")]\nimpl std::error::Error for NewOrLoadError {}\n\n/// An error that may occur when inserting a transaction into [`Wallet`].\n#[derive(Debug)]\npub enum InsertTxError {\n    /// The error variant that occurs when the caller attempts to insert a transaction with a\n    /// confirmation height that is greater than the internal chain tip.\n    ConfirmationHeightCannotBeGreaterThanTip {\n        /// The internal chain\'s tip height.\n        tip_height: u32,\n        /// The introduced transaction\'s confirmation height.\n        tx_height: u32,\n    },\n}\n\nimpl fmt::Display for InsertTxError {\n    fn fmt(&self, f: &mut fmt::Formatter<\'_>) -> fmt::Result {\n        match self {\n            InsertTxError::ConfirmationHeightCannotBeGreaterThanTip {\n                tip_height,\n                tx_height,\n            } => {\n                write!(f, "cannot insert tx with confirmation height ({}) higher than internal tip height ({})", tx_height, tip_height)\n            }\n        }\n    }\n}\n\n#[cfg(feature = "std")]\nimpl std::error::Error for InsertTxError {}\n\n/// An error that may occur when applying a block to [`Wallet`].\n#[derive(Debug)]\npub enum ApplyBlockError {\n    /// Occurs when the update chain cannot connect with original chain.\n    CannotConnect(CannotConnectError),\n    /// Occurs when the `connected_to` hash does not match the hash derived from `block`.\n    UnexpectedConnectedToHash {\n        /// Block hash of `connected_to`.\n        connected_to_hash: BlockHash,\n        /// Expected block hash of `connected_to`, as derived from `block`.\n        expected_hash: BlockHash,\n    },\n}\n\nimpl fmt::Display for ApplyBlockError {\n    fn fmt(&self, f: &mut fmt::Formatter<\'_>) -> fmt::Result {\n        match self {\n            ApplyBlockError::CannotConnect(err) => err.fmt(f),\n            ApplyBlockError::UnexpectedConnectedToHash {\n                expected_hash: block_hash,\n                connected_to_hash: checkpoint_hash,\n            } => write!(\n                f,\n                "`connected_to` hash {} differs from the expected hash {} (which is derived from `block`)",\n                checkpoint_hash, block_hash\n            ),\n        }\n    }\n}\n\n#[cfg(feature = "std")]\nimpl std::error::Error for ApplyBlockError {}\n\nimpl Wallet {\n    /// Initialize an empty [`Wallet`].\n    pub fn new<E: IntoWalletDescriptor>(\n        descriptor: E,\n        change_descriptor: E,\n        network: Network,\n    ) -> Result<Self, NewError> {\n        let genesis_hash = genesis_block(network).block_hash();\n        Self::new_with_genesis_hash(descriptor, change_descriptor, network, genesis_hash)\n    }\n\n    /// Initialize an empty [`Wallet`] with a custom genesis hash.\n    ///\n    /// This is like [`Wallet::new`] with an additional `genesis_hash` parameter. This is useful\n    /// for syncing from alternative networks.\n    pub fn new_with_genesis_hash<E: IntoWalletDescriptor>(\n        descriptor: E,\n        change_descriptor: E,\n        network: Network,\n        genesis_hash: BlockHash,\n    ) -> Result<Self, NewError> {\n        let secp = Secp256k1::new();\n        let (chain, chain_changeset) = LocalChain::from_genesis_hash(genesis_hash);\n        let mut index = KeychainTxOutIndex::<KeychainKind>::default();\n\n        let (signers, change_signers) =\n            create_signers(&mut index, &secp, descriptor, change_descriptor, network)\n                .map_err(NewError::Descriptor)?;\n\n        let indexed_graph = IndexedTxGraph::new(index);\n\n        let staged = ChangeSet {\n            chain: chain_changeset,\n            indexed_tx_graph: indexed_graph.initial_changeset(),\n            network: Some(network),\n        };\n\n        Ok(Wallet {\n            signers,\n            change_signers,\n            network,\n            chain,\n            indexed_graph,\n            stage: staged,\n            secp,\n        })\n    }\n\n    /// Load [`Wallet`] from the given previously persisted [`ChangeSet`].\n    ///\n    /// Note that the descriptor secret keys are not persisted to the db; this means that after\n    /// calling this method the [`Wallet`] **won\'t** know the secret keys, and as such, won\'t be\n    /// able to sign transactions.\n    ///\n    /// If you wish to use the wallet to sign transactions, you need to add the secret keys\n    /// manually to the [`Wallet`]:\n    ///\n    /// ```rust,no_run\n    /// # use bdk_wallet::Wallet;\n    /// # use bdk_wallet::signer::{SignersContainer, SignerOrdering};\n    /// # use bdk_wallet::descriptor::Descriptor;\n    /// # use bitcoin::key::Secp256k1;\n    /// # use bdk_wallet::KeychainKind;\n    /// use bdk_sqlite::{Store, rusqlite::Connection};\n    /// #\n    /// # fn main() -> Result<(), anyhow::Error> {\n    /// # let temp_dir = tempfile::tempdir().expect("must create tempdir");\n    /// # let file_path = temp_dir.path().join("store.db");\n    /// let conn = Connection::open(file_path).expect("must open connection");\n    /// let mut db = Store::new(conn).expect("must create db");\n    /// let secp = Secp256k1::new();\n    ///\n    /// let (external_descriptor, external_keymap) = Descriptor::parse_descriptor(&secp, "wpkh(tprv8ZgxMBicQKsPdy6LMhUtFHAgpocR8GC6QmwMSFpZs7h6Eziw3SpThFfczTDh5rW2krkqffa11UpX3XkeTTB2FvzZKWXqPY54Y6Rq4AQ5R8L/84\'/1\'/0\'/0/*)").unwrap();\n    /// let (internal_descriptor, internal_keymap) = Descriptor::parse_descriptor(&secp, "wpkh(tprv8ZgxMBicQKsPdy6LMhUtFHAgpocR8GC6QmwMSFpZs7h6Eziw3SpThFfczTDh5rW2krkqffa11UpX3XkeTTB2FvzZKWXqPY54Y6Rq4AQ5R8L/84\'/1\'/0\'/1/*)").unwrap();\n    ///\n    /// let external_signer_container = SignersContainer::build(external_keymap, &external_descriptor, &secp);\n    /// let internal_signer_container = SignersContainer::build(internal_keymap, &internal_descriptor, &secp);\n    /// let changeset = db.read()?.expect("there must be an existing changeset");\n    /// let mut wallet = Wallet::load_from_changeset(changeset)?;\n    ///\n    /// external_signer_container.signers().into_iter()\n    ///     .for_each(|s| wallet.add_signer(KeychainKind::External, SignerOrdering::default(), s.clone()));\n    /// internal_signer_container.signers().into_iter()\n    ///     .for_each(|s| wallet.add_signer(KeychainKind::Internal, SignerOrdering::default(), s.clone()));\n    /// # Ok(())\n    /// # }\n    /// ```\n    ///\n    /// Alternatively, you can call [`Wallet::new_or_load`], which will add the private keys of the\n    /// passed-in descriptors to the [`Wallet`].\n    pub fn load_from_changeset(changeset: ChangeSet) -> Result<Self, LoadError> {\n        let secp = Secp256k1::new();\n        let network = changeset.network.ok_or(LoadError::MissingNetwork)?;\n        let chain =\n            LocalChain::from_changeset(changeset.chain).map_err(|_| LoadError::MissingGenesis)?;\n        let mut index = KeychainTxOutIndex::<KeychainKind>::default();\n        let descriptor = changeset\n            .indexed_tx_graph\n            .indexer\n            .keychains_added\n            .get(&KeychainKind::External)\n            .ok_or(LoadError::MissingDescriptor(KeychainKind::External))?\n            .clone();\n        let change_descriptor = changeset\n            .indexed_tx_graph\n            .indexer\n            .keychains_added\n            .get(&KeychainKind::Internal)\n            .ok_or(LoadError::MissingDescriptor(KeychainKind::Internal))?\n            .clone();\n\n        let (signers, change_signers) =\n            create_signers(&mut index, &secp, descriptor, change_descriptor, network)\n                .expect("Can\'t fail: we passed in valid descriptors, recovered from the changeset");\n\n        let mut indexed_graph = IndexedTxGraph::new(index);\n        indexed_graph.apply_changeset(changeset.indexed_tx_graph);\n\n        let stage = ChangeSet::default();\n\n        Ok(Wallet {\n            signers,\n            change_signers,\n            chain,\n            indexed_graph,\n            stage,\n            network,\n            secp,\n        })\n    }\n\n    /// Either loads [`Wallet`] from the given [`ChangeSet`] or initializes it if one does not exist.\n    ///\n    /// This method will fail if the loaded [`ChangeSet`] has different parameters to those provided.\n    ///\n    /// ```rust,no_run\n    /// # use bdk_wallet::Wallet;\n    /// use bdk_sqlite::{Store, rusqlite::Connection};\n    /// # use bitcoin::Network::Testnet;\n    /// let conn = Connection::open_in_memory().expect("must open connection");\n    /// let mut db = Store::new(conn).expect("must create db");\n    /// let changeset = db.read()?;\n    ///\n    /// let external_descriptor = "wpkh(tprv8ZgxMBicQKsPdy6LMhUtFHAgpocR8GC6QmwMSFpZs7h6Eziw3SpThFfczTDh5rW2krkqffa11UpX3XkeTTB2FvzZKWXqPY54Y6Rq4AQ5R8L/84\'/1\'/0\'/0/*)";\n    /// let internal_descriptor = "wpkh(tprv8ZgxMBicQKsPdy6LMhUtFHAgpocR8GC6QmwMSFpZs7h6Eziw3SpThFfczTDh5rW2krkqffa11UpX3XkeTTB2FvzZKWXqPY54Y6Rq4AQ5R8L/84\'/1\'/0\'/1/*)";\n    ///\n    /// let mut wallet = Wallet::new_or_load(external_descriptor, internal_descriptor, changeset, Testnet)?;\n    /// # Ok::<(), anyhow::Error>(())\n    /// ```\n    pub fn new_or_load<E: IntoWalletDescriptor>(\n        descriptor: E,\n        change_descriptor: E,\n        changeset: Option<ChangeSet>,\n        network: Network,\n    ) -> Result<Self, NewOrLoadError> {\n        let genesis_hash = genesis_block(network).block_hash();\n        Self::new_or_load_with_genesis_hash(\n            descriptor,\n            change_descriptor,\n            changeset,\n            network,\n            genesis_hash,\n        )\n    }\n\n    /// Either loads [`Wallet`] from a [`ChangeSet`] or initializes it if one does not exist, using the\n    /// provided descriptor, change descriptor, network, and custom genesis hash.\n    ///\n    /// This method will fail if the loaded [`ChangeSet`] has different parameters to those provided.\n    /// This is like [`Wallet::new_or_load`] with an additional `genesis_hash` parameter. This is\n    /// useful for syncing from alternative networks.\n    pub fn new_or_load_with_genesis_hash<E: IntoWalletDescriptor>(\n        descriptor: E,\n        change_descriptor: E,\n        changeset: Option<ChangeSet>,\n        network: Network,\n        genesis_hash: BlockHash,\n    ) -> Result<Self, NewOrLoadError> {\n        if let Some(changeset) = changeset {\n            let mut wallet = Self::load_from_changeset(changeset).map_err(|e| match e {\n                LoadError::Descriptor(e) => NewOrLoadError::Descriptor(e),\n                LoadError::MissingNetwork => NewOrLoadError::LoadedNetworkDoesNotMatch {\n                    expected: network,\n                    got: None,\n                },\n                LoadError::MissingGenesis => NewOrLoadError::LoadedGenesisDoesNotMatch {\n                    expected: genesis_hash,\n                    got: None,\n                },\n                LoadError::MissingDescriptor(keychain) => {\n                    NewOrLoadError::LoadedDescriptorDoesNotMatch {\n                        got: None,\n                        keychain,\n                    }\n                }\n            })?;\n            if wallet.network != network {\n                return Err(NewOrLoadError::LoadedNetworkDoesNotMatch {\n                    expected: network,\n                    got: Some(wallet.network),\n                });\n            }\n            if wallet.chain.genesis_hash() != genesis_hash {\n                return Err(NewOrLoadError::LoadedGenesisDoesNotMatch {\n                    expected: genesis_hash,\n                    got: Some(wallet.chain.genesis_hash()),\n                });\n            }\n\n            let (expected_descriptor, expected_descriptor_keymap) = descriptor\n                .into_wallet_descriptor(&wallet.secp, network)\n                .map_err(NewOrLoadError::Descriptor)?;\n            let wallet_descriptor = wallet.public_descriptor(KeychainKind::External);\n            if wallet_descriptor != &expected_descriptor {\n                return Err(NewOrLoadError::LoadedDescriptorDoesNotMatch {\n                    got: Some(wallet_descriptor.clone()),\n                    keychain: KeychainKind::External,\n                });\n            }\n            // if expected descriptor has private keys add them as new signers\n            if !expected_descriptor_keymap.is_empty() {\n                let signer_container = SignersContainer::build(\n                    expected_descriptor_keymap,\n                    &expected_descriptor,\n                    &wallet.secp,\n                );\n                signer_container.signers().into_iter().for_each(|signer| {\n                    wallet.add_signer(\n                        KeychainKind::External,\n                        SignerOrdering::default(),\n                        signer.clone(),\n                    )\n                });\n            }\n\n            let (expected_change_descriptor, expected_change_descriptor_keymap) = change_descriptor\n                .into_wallet_descriptor(&wallet.secp, network)\n                .map_err(NewOrLoadError::Descriptor)?;\n            let wallet_change_descriptor = wallet.public_descriptor(KeychainKind::Internal);\n            if wallet_change_descriptor != &expected_change_descriptor {\n                return Err(NewOrLoadError::LoadedDescriptorDoesNotMatch {\n                    got: Some(wallet_change_descriptor.clone()),\n                    keychain: KeychainKind::Internal,\n                });\n            }\n            // if expected change descriptor has private keys add them as new signers\n            if !expected_change_descriptor_keymap.is_empty() {\n                let signer_container = SignersContainer::build(\n                    expected_change_descriptor_keymap,\n                    &expected_change_descriptor,\n                    &wallet.secp,\n                );\n                signer_container.signers().into_iter().for_each(|signer| {\n                    wallet.add_signer(\n                        KeychainKind::Internal,\n                        SignerOrdering::default(),\n                        signer.clone(),\n                    )\n                });\n            }\n\n            Ok(wallet)\n        } else {\n            Self::new_with_genesis_hash(descriptor, change_descriptor, network, genesis_hash)\n                .map_err(|e| match e {\n                    NewError::Descriptor(e) => NewOrLoadError::Descriptor(e),\n                })\n        }\n    }\n\n    /// Get the Bitcoin network the wallet is using.\n    pub fn network(&self) -> Network {\n        self.network\n    }\n\n    /// Iterator over all keychains in this wallet\n    pub fn keychains(&self) -> impl Iterator<Item = (&KeychainKind, &ExtendedDescriptor)> {\n        self.indexed_graph.index.keychains()\n    }\n\n    /// Peek an address of the given `keychain` at `index` without revealing it.\n    ///\n    /// For non-wildcard descriptors this returns the same address at every provided index.\n    ///\n    /// # Panics\n    ///\n    /// This panics when the caller requests for an address of derivation index greater than the\n    /// [BIP32](https://github.com/bitcoin/bips/blob/master/bip-0032.mediawiki) max index.\n    pub fn peek_address(&self, keychain: KeychainKind, mut index: u32) -> AddressInfo {\n        let mut spk_iter = self\n            .indexed_graph\n            .index\n            .unbounded_spk_iter(&keychain)\n            .expect("keychain must exist");\n        if !spk_iter.descriptor().has_wildcard() {\n            index = 0;\n        }\n        let (index, spk) = spk_iter\n            .nth(index as usize)\n            .expect("derivation index is out of bounds");\n\n        AddressInfo {\n            index,\n            address: Address::from_script(&spk, self.network).expect("must have address form"),\n            keychain,\n        }\n    }\n\n    /// Attempt to reveal the next address of the given `keychain`.\n    ///\n    /// This will increment the keychain\'s derivation index. If the keychain\'s descriptor doesn\'t\n    /// contain a wildcard or every address is already revealed up to the maximum derivation\n    /// index defined in [BIP32](https://github.com/bitcoin/bips/blob/master/bip-0032.mediawiki),\n    /// then the last revealed address will be returned.\n    ///\n    /// **WARNING**: To avoid address reuse you must persist the changes resulting from one or more\n    /// calls to this method before closing the wallet. For example:\n    ///\n    /// ```rust,no_run\n    /// # use bdk_wallet::wallet::{Wallet, ChangeSet};\n    /// # use bdk_wallet::KeychainKind;\n    /// use bdk_sqlite::{rusqlite::Connection, Store};\n    /// let conn = Connection::open_in_memory().expect("must open connection");\n    /// let mut db = Store::new(conn).expect("must create store");\n    /// # let changeset = ChangeSet::default();\n    /// # let mut wallet = Wallet::load_from_changeset(changeset).expect("load wallet");\n    /// let next_address = wallet.reveal_next_address(KeychainKind::External);\n    /// if let Some(changeset) = wallet.take_staged() {\n    ///     db.write(&changeset)?;\n    /// }\n    ///\n    /// // Now it\'s safe to show the user their next address!\n    /// println!("Next address: {}", next_address.address);\n    /// # Ok::<(), anyhow::Error>(())\n    /// ```\n    pub fn reveal_next_address(&mut self, keychain: KeychainKind) -> AddressInfo {\n        let index = &mut self.indexed_graph.index;\n        let stage = &mut self.stage;\n\n        let ((index, spk), index_changeset) = index\n            .reveal_next_spk(&keychain)\n            .expect("keychain must exist");\n\n        stage.append(indexed_tx_graph::ChangeSet::from(index_changeset).into());\n\n        AddressInfo {\n            index,\n            address: Address::from_script(spk.as_script(), self.network)\n                .expect("must have address form"),\n            keychain,\n        }\n    }\n\n    /// Reveal addresses up to and including the target `index` and return an iterator\n    /// of newly revealed addresses.\n    ///\n    /// If the target `index` is unreachable, we make a best effort to reveal up to the last\n    /// possible index. If all addresses up to the given `index` are already revealed, then\n    /// no new addresses are returned.\n    ///\n    /// **WARNING**: To avoid address reuse you must persist the changes resulting from one or more\n    /// calls to this method before closing the wallet. See [`Wallet::reveal_next_address`].\n    pub fn reveal_addresses_to(\n        &mut self,\n        keychain: KeychainKind,\n        index: u32,\n    ) -> impl Iterator<Item = AddressInfo> + \'_ {\n        let (spks, index_changeset) = self\n            .indexed_graph\n            .index\n            .reveal_to_target(&keychain, index)\n            .expect("keychain must exist");\n\n        self.stage.append(index_changeset.into());\n\n        spks.into_iter().map(move |(index, spk)| AddressInfo {\n            index,\n            address: Address::from_script(&spk, self.network).expect("must have address form"),\n            keychain,\n        })\n    }\n\n    /// Get the next unused address for the given `keychain`, i.e. the address with the lowest\n    /// derivation index that hasn\'t been used.\n    ///\n    /// This will attempt to derive and reveal a new address if no newly revealed addresses\n    /// are available. See also [`reveal_next_address`](Self::reveal_next_address).\n    ///\n    /// **WARNING**: To avoid address reuse you must persist the changes resulting from one or more\n    /// calls to this method before closing the wallet. See [`Wallet::reveal_next_address`].\n    pub fn next_unused_address(&mut self, keychain: KeychainKind) -> AddressInfo {\n        let index = &mut self.indexed_graph.index;\n\n        let ((index, spk), index_changeset) = index\n            .next_unused_spk(&keychain)\n            .expect("keychain must exist");\n\n        self.stage\n            .append(indexed_tx_graph::ChangeSet::from(index_changeset).into());\n\n        AddressInfo {\n            index,\n            address: Address::from_script(spk.as_script(), self.network)\n                .expect("must have address form"),\n            keychain,\n        }\n    }\n\n    /// Marks an address used of the given `keychain` at `index`.\n    ///\n    /// Returns whether the given index was present and then removed from the unused set.\n    pub fn mark_used(&mut self, keychain: KeychainKind, index: u32) -> bool {\n        self.indexed_graph.index.mark_used(keychain, index)\n    }\n\n    /// Undoes the effect of [`mark_used`] and returns whether the `index` was inserted\n    /// back into the unused set.\n    ///\n    /// Since this is only a superficial marker, it will have no effect if the address at the given\n    /// `index` was actually used, i.e. the wallet has previously indexed a tx output for the\n    /// derived spk.\n    ///\n    /// [`mark_used`]: Self::mark_used\n    pub fn unmark_used(&mut self, keychain: KeychainKind, index: u32) -> bool {\n        self.indexed_graph.index.unmark_used(keychain, index)\n    }\n\n    /// List addresses that are revealed but unused.\n    ///\n    /// Note if the returned iterator is empty you can reveal more addresses\n    /// by using [`reveal_next_address`](Self::reveal_next_address) or\n    /// [`reveal_addresses_to`](Self::reveal_addresses_to).\n    pub fn list_unused_addresses(\n        &self,\n        keychain: KeychainKind,\n    ) -> impl DoubleEndedIterator<Item = AddressInfo> + \'_ {\n        self.indexed_graph\n            .index\n            .unused_keychain_spks(&keychain)\n            .map(move |(index, spk)| AddressInfo {\n                index,\n                address: Address::from_script(spk, self.network).expect("must have address form"),\n                keychain,\n            })\n    }\n\n    /// Return whether or not a `script` is part of this wallet (either internal or external)\n    pub fn is_mine(&self, script: &Script) -> bool {\n        self.indexed_graph.index.index_of_spk(script).is_some()\n    }\n\n    /// Finds how the wallet derived the script pubkey `spk`.\n    ///\n    /// Will only return `Some(_)` if the wallet has given out the spk.\n    pub fn derivation_of_spk(&self, spk: &Script) -> Option<(KeychainKind, u32)> {\n        self.indexed_graph.index.index_of_spk(spk).cloned()\n    }\n\n    /// Return the list of unspent outputs of this wallet\n    pub fn list_unspent(&self) -> impl Iterator<Item = LocalOutput> + \'_ {\n        self.indexed_graph\n            .graph()\n            .filter_chain_unspents(\n                &self.chain,\n                self.chain.tip().block_id(),\n                self.indexed_graph.index.outpoints().iter().cloned(),\n            )\n            .map(|((k, i), full_txo)| new_local_utxo(k, i, full_txo))\n    }\n\n    /// List all relevant outputs (includes both spent and unspent, confirmed and unconfirmed).\n    ///\n    /// To list only unspent outputs (UTXOs), use [`Wallet::list_unspent`] instead.\n    pub fn list_output(&self) -> impl Iterator<Item = LocalOutput> + \'_ {\n        self.indexed_graph\n            .graph()\n            .filter_chain_txouts(\n                &self.chain,\n                self.chain.tip().block_id(),\n                self.indexed_graph.index.outpoints().iter().cloned(),\n            )\n            .map(|((k, i), full_txo)| new_local_utxo(k, i, full_txo))\n    }\n\n    /// Get all the checkpoints the wallet is currently storing indexed by height.\n    pub fn checkpoints(&self) -> CheckPointIter {\n        self.chain.iter_checkpoints()\n    }\n\n    /// Returns the latest checkpoint.\n    pub fn latest_checkpoint(&self) -> CheckPoint {\n        self.chain.tip()\n    }\n\n    /// Get unbounded script pubkey iterators for both `Internal` and `External` keychains.\n    ///\n    /// This is intended to be used when doing a full scan of your addresses (e.g. after restoring\n    /// from seed words). You pass the `BTreeMap` of iterators to a blockchain data source (e.g.\n    /// electrum server) which will go through each address until it reaches a *stop gap*.\n    ///\n    /// Note carefully that iterators go over **all** script pubkeys on the keychains (not what\n    /// script pubkeys the wallet is storing internally).\n    pub fn all_unbounded_spk_iters(\n        &self,\n    ) -> BTreeMap<KeychainKind, impl Iterator<Item = Indexed<ScriptBuf>> + Clone> {\n        self.indexed_graph.index.all_unbounded_spk_iters()\n    }\n\n    /// Get an unbounded script pubkey iterator for the given `keychain`.\n    ///\n    /// See [`all_unbounded_spk_iters`] for more documentation\n    ///\n    /// [`all_unbounded_spk_iters`]: Self::all_unbounded_spk_iters\n    pub fn unbounded_spk_iter(\n        &self,\n        keychain: KeychainKind,\n    ) -> impl Iterator<Item = Indexed<ScriptBuf>> + Clone {\n        self.indexed_graph\n            .index\n            .unbounded_spk_iter(&keychain)\n            .expect("keychain must exist")\n    }\n\n    /// Returns the utxo owned by this wallet corresponding to `outpoint` if it exists in the\n    /// wallet\'s database.\n    pub fn get_utxo(&self, op: OutPoint) -> Option<LocalOutput> {\n        let ((keychain, index), _) = self.indexed_graph.index.txout(op)?;\n        self.indexed_graph\n            .graph()\n            .filter_chain_unspents(\n                &self.chain,\n                self.chain.tip().block_id(),\n                core::iter::once(((), op)),\n            )\n            .map(|(_, full_txo)| new_local_utxo(keychain, index, full_txo))\n            .next()\n    }\n\n    /// Inserts a [`TxOut`] at [`OutPoint`] into the wallet\'s transaction graph.\n    ///\n    /// This is used for providing a previous output\'s value so that we can use [`calculate_fee`]\n    /// or [`calculate_fee_rate`] on a given transaction. Outputs inserted with this method will\n    /// not be returned in [`list_unspent`] or [`list_output`].\n    ///\n    /// **WARNINGS:** This should only be used to add `TxOut`s that the wallet does not own. Only\n    /// insert `TxOut`s that you trust the values for!\n    ///\n    /// You must persist the changes resulting from one or more calls to this method if you need\n    /// the inserted `TxOut` data to be reloaded after closing the wallet.\n    /// See [`Wallet::reveal_next_address`].\n    ///\n    /// [`calculate_fee`]: Self::calculate_fee\n    /// [`calculate_fee_rate`]: Self::calculate_fee_rate\n    /// [`list_unspent`]: Self::list_unspent\n    /// [`list_output`]: Self::list_output\n    pub fn insert_txout(&mut self, outpoint: OutPoint, txout: TxOut) {\n        let additions = self.indexed_graph.insert_txout(outpoint, txout);\n        self.stage.append(additions.into());\n    }\n\n    /// Calculates the fee of a given transaction. Returns [`Amount::ZERO`] if `tx` is a coinbase transaction.\n    ///\n    /// To calculate the fee for a [`Transaction`] with inputs not owned by this wallet you must\n    /// manually insert the TxOut(s) into the tx graph using the [`insert_txout`] function.\n    ///\n    /// Note `tx` does not have to be in the graph for this to work.\n    ///\n    /// # Examples\n    ///\n    /// ```rust, no_run\n    /// # use bitcoin::Txid;\n    /// # use bdk_wallet::Wallet;\n    /// # let mut wallet: Wallet = todo!();\n    /// # let txid:Txid = todo!();\n    /// let tx = wallet.get_tx(txid).expect("transaction").tx_node.tx;\n    /// let fee = wallet.calculate_fee(&tx).expect("fee");\n    /// ```\n    ///\n    /// ```rust, no_run\n    /// # use bitcoin::Psbt;\n    /// # use bdk_wallet::Wallet;\n    /// # let mut wallet: Wallet = todo!();\n    /// # let mut psbt: Psbt = todo!();\n    /// let tx = &psbt.clone().extract_tx().expect("tx");\n    /// let fee = wallet.calculate_fee(tx).expect("fee");\n    /// ```\n    /// [`insert_txout`]: Self::insert_txout\n    pub fn calculate_fee(&self, tx: &Transaction) -> Result<Amount, CalculateFeeError> {\n        self.indexed_graph.graph().calculate_fee(tx)\n    }\n\n    /// Calculate the [`FeeRate`] for a given transaction.\n    ///\n    /// To calculate the fee rate for a [`Transaction`] with inputs not owned by this wallet you must\n    /// manually insert the TxOut(s) into the tx graph using the [`insert_txout`] function.\n    ///\n    /// Note `tx` does not have to be in the graph for this to work.\n    ///\n    /// # Examples\n    ///\n    /// ```rust, no_run\n    /// # use bitcoin::Txid;\n    /// # use bdk_wallet::Wallet;\n    /// # let mut wallet: Wallet = todo!();\n    /// # let txid:Txid = todo!();\n    /// let tx = wallet.get_tx(txid).expect("transaction").tx_node.tx;\n    /// let fee_rate = wallet.calculate_fee_rate(&tx).expect("fee rate");\n    /// ```\n    ///\n    /// ```rust, no_run\n    /// # use bitcoin::Psbt;\n    /// # use bdk_wallet::Wallet;\n    /// # let mut wallet: Wallet = todo!();\n    /// # let mut psbt: Psbt = todo!();\n    /// let tx = &psbt.clone().extract_tx().expect("tx");\n    /// let fee_rate = wallet.calculate_fee_rate(tx).expect("fee rate");\n    /// ```\n    /// [`insert_txout`]: Self::insert_txout\n    pub fn calculate_fee_rate(&self, tx: &Transaction) -> Result<FeeRate, CalculateFeeError> {\n        self.calculate_fee(tx).map(|fee| fee / tx.weight())\n    }\n\n    /// Compute the `tx`\'s sent and received [`Amount`]s.\n    ///\n    /// This method returns a tuple `(sent, received)`. Sent is the sum of the txin amounts\n    /// that spend from previous txouts tracked by this wallet. Received is the summation\n    /// of this tx\'s outputs that send to script pubkeys tracked by this wallet.\n    ///\n    /// # Examples\n    ///\n    /// ```rust, no_run\n    /// # use bitcoin::Txid;\n    /// # use bdk_wallet::Wallet;\n    /// # let mut wallet: Wallet = todo!();\n    /// # let txid:Txid = todo!();\n    /// let tx = wallet.get_tx(txid).expect("tx exists").tx_node.tx;\n    /// let (sent, received) = wallet.sent_and_received(&tx);\n    /// ```\n    ///\n    /// ```rust, no_run\n    /// # use bitcoin::Psbt;\n    /// # use bdk_wallet::Wallet;\n    /// # let mut wallet: Wallet = todo!();\n    /// # let mut psbt: Psbt = todo!();\n    /// let tx = &psbt.clone().extract_tx().expect("tx");\n    /// let (sent, received) = wallet.sent_and_received(tx);\n    /// ```\n    pub fn sent_and_received(&self, tx: &Transaction) -> (Amount, Amount) {\n        self.indexed_graph.index.sent_and_received(tx, ..)\n    }\n\n    /// Get a single transaction from the wallet as a [`CanonicalTx`] (if the transaction exists).\n    ///\n    /// `CanonicalTx` contains the full transaction alongside meta-data such as:\n    /// * Blocks that the transaction is [`Anchor`]ed in. These may or may not be blocks that exist\n    ///   in the best chain.\n    /// * The [`ChainPosition`] of the transaction in the best chain - whether the transaction is\n    ///   confirmed or unconfirmed. If the transaction is confirmed, the anchor which proves the\n    ///   confirmation is provided. If the transaction is unconfirmed, the unix timestamp of when\n    ///   the transaction was last seen in the mempool is provided.\n    ///\n    /// ```rust, no_run\n    /// use bdk_chain::Anchor;\n    /// use bdk_wallet::{chain::ChainPosition, Wallet};\n    /// # let wallet: Wallet = todo!();\n    /// # let my_txid: bitcoin::Txid = todo!();\n    ///\n    /// let canonical_tx = wallet.get_tx(my_txid).expect("panic if tx does not exist");\n    ///\n    /// // get reference to full transaction\n    /// println!("my tx: {:#?}", canonical_tx.tx_node.tx);\n    ///\n    /// // list all transaction anchors\n    /// for anchor in canonical_tx.tx_node.anchors {\n    ///     println!(\n    ///         "tx is anchored by block of hash {}",\n    ///         anchor.anchor_block().hash\n    ///     );\n    /// }\n    ///\n    /// // get confirmation status of transaction\n    /// match canonical_tx.chain_position {\n    ///     ChainPosition::Confirmed(anchor) => println!(\n    ///         "tx is confirmed at height {}, we know this since {}:{} is in the best chain",\n    ///         anchor.confirmation_height, anchor.anchor_block.height, anchor.anchor_block.hash,\n    ///     ),\n    ///     ChainPosition::Unconfirmed(last_seen) => println!(\n    ///         "tx is last seen at {}, it is unconfirmed as it is not anchored in the best chain",\n    ///         last_seen,\n    ///     ),\n    /// }\n    /// ```\n    ///\n    /// [`Anchor`]: bdk_chain::Anchor\n    pub fn get_tx(\n        &self,\n        txid: Txid,\n    ) -> Option<CanonicalTx<\'_, Arc<Transaction>, ConfirmationTimeHeightAnchor>> {\n        let graph = self.indexed_graph.graph();\n\n        Some(CanonicalTx {\n            chain_position: graph.get_chain_position(\n                &self.chain,\n                self.chain.tip().block_id(),\n                txid,\n            )?,\n            tx_node: graph.get_tx_node(txid)?,\n        })\n    }\n\n    /// Add a new checkpoint to the wallet\'s internal view of the chain.\n    ///\n    /// Returns whether anything changed with the insertion (e.g. `false` if checkpoint was already\n    /// there).\n    ///\n    /// **WARNING**: You must persist the changes resulting from one or more calls to this method\n    /// if you need the inserted checkpoint data to be reloaded after closing the wallet.\n    /// See [`Wallet::reveal_next_address`].\n    ///\n    /// [`commit`]: Self::commit\n    pub fn insert_checkpoint(\n        &mut self,\n        block_id: BlockId,\n    ) -> Result<bool, local_chain::AlterCheckPointError> {\n        let changeset = self.chain.insert_block(block_id)?;\n        let changed = !changeset.is_empty();\n        self.stage.append(changeset.into());\n        Ok(changed)\n    }\n\n    /// Add a transaction to the wallet\'s internal view of the chain. This stages the change,\n    /// you must persist it later.\n    ///\n    /// Returns whether anything changed with the transaction insertion (e.g. `false` if the\n    /// transaction was already inserted at the same position).\n    ///\n    /// A `tx` can be rejected if `position` has a height greater than the [`latest_checkpoint`].\n    /// Therefore you should use [`insert_checkpoint`] to insert new checkpoints before manually\n    /// inserting new transactions.\n    ///\n    /// **WARNING**: If `position` is confirmed, we anchor the `tx` to the lowest checkpoint that\n    /// is >= the `position`\'s height. The caller is responsible for ensuring the `tx` exists in our\n    /// local view of the best chain\'s history.\n    ///\n    /// You must persist the changes resulting from one or more calls to this method if you need\n    /// the inserted tx to be reloaded after closing the wallet.\n    ///\n    /// [`commit`]: Self::commit\n    /// [`latest_checkpoint`]: Self::latest_checkpoint\n    /// [`insert_checkpoint`]: Self::insert_checkpoint\n    pub fn insert_tx(\n        &mut self,\n        tx: Transaction,\n        position: ConfirmationTime,\n    ) -> Result<bool, InsertTxError> {\n        let (anchor, last_seen) = match position {\n            ConfirmationTime::Confirmed { height, time } => {\n                // anchor tx to checkpoint with lowest height that is >= position\'s height\n                let anchor = self\n                    .chain\n                    .range(height..)\n                    .last()\n                    .ok_or(InsertTxError::ConfirmationHeightCannotBeGreaterThanTip {\n                        tip_height: self.chain.tip().height(),\n                        tx_height: height,\n                    })\n                    .map(|anchor_cp| ConfirmationTimeHeightAnchor {\n                        anchor_block: anchor_cp.block_id(),\n                        confirmation_height: height,\n                        confirmation_time: time,\n                    })?;\n\n                (Some(anchor), None)\n            }\n            ConfirmationTime::Unconfirmed { last_seen } => (None, Some(last_seen)),\n        };\n\n        let mut changeset = ChangeSet::default();\n        let txid = tx.compute_txid();\n        changeset.append(self.indexed_graph.insert_tx(tx).into());\n        if let Some(anchor) = anchor {\n            changeset.append(self.indexed_graph.insert_anchor(txid, anchor).into());\n        }\n        if let Some(last_seen) = last_seen {\n            changeset.append(self.indexed_graph.insert_seen_at(txid, last_seen).into());\n        }\n\n        let changed = !changeset.is_empty();\n        self.stage.append(changeset);\n        Ok(changed)\n    }\n\n    /// Iterate over the transactions in the wallet.\n    pub fn transactions(\n        &self,\n    ) -> impl Iterator<Item = CanonicalTx<\'_, Arc<Transaction>, ConfirmationTimeHeightAnchor>> + \'_\n    {\n        self.indexed_graph\n            .graph()\n            .list_chain_txs(&self.chain, self.chain.tip().block_id())\n    }\n\n    /// Return the balance, separated into available, trusted-pending, untrusted-pending and immature\n    /// values.\n    pub fn balance(&self) -> Balance {\n        self.indexed_graph.graph().balance(\n            &self.chain,\n            self.chain.tip().block_id(),\n            self.indexed_graph.index.outpoints().iter().cloned(),\n            |&(k, _), _| k == KeychainKind::Internal,\n        )\n    }\n\n    /// Add an external signer\n    ///\n    /// See [the `signer` module](signer) for an example.\n    pub fn add_signer(\n        &mut self,\n        keychain: KeychainKind,\n        ordering: SignerOrdering,\n        signer: Arc<dyn TransactionSigner>,\n    ) {\n        let signers = match keychain {\n            KeychainKind::External => Arc::make_mut(&mut self.signers),\n            KeychainKind::Internal => Arc::make_mut(&mut self.change_signers),\n        };\n\n        signers.add_external(signer.id(&self.secp), ordering, signer);\n    }\n\n    /// Get the signers\n    ///\n    /// ## Example\n    ///\n    /// ```\n    /// # use bdk_wallet::{Wallet, KeychainKind};\n    /// # use bdk_wallet::bitcoin::Network;\n    /// let descriptor = "wpkh(tprv8ZgxMBicQKsPe73PBRSmNbTfbcsZnwWhz5eVmhHpi31HW29Z7mc9B4cWGRQzopNUzZUT391DeDJxL2PefNunWyLgqCKRMDkU1s2s8bAfoSk/84\'/1\'/0\'/0/*)";\n    /// let change_descriptor = "wpkh(tprv8ZgxMBicQKsPe73PBRSmNbTfbcsZnwWhz5eVmhHpi31HW29Z7mc9B4cWGRQzopNUzZUT391DeDJxL2PefNunWyLgqCKRMDkU1s2s8bAfoSk/84\'/1\'/0\'/1/*)";\n    /// let wallet = Wallet::new(descriptor, change_descriptor, Network::Testnet)?;\n    /// for secret_key in wallet.get_signers(KeychainKind::External).signers().iter().filter_map(|s| s.descriptor_secret_key()) {\n    ///     // secret_key: tprv8ZgxMBicQKsPe73PBRSmNbTfbcsZnwWhz5eVmhHpi31HW29Z7mc9B4cWGRQzopNUzZUT391DeDJxL2PefNunWyLgqCKRMDkU1s2s8bAfoSk/84\'/0\'/0\'/0/*\n    ///     println!("secret_key: {}", secret_key);\n    /// }\n    ///\n    /// Ok::<(), Box<dyn std::error::Error>>(())\n    /// ```\n    pub fn get_signers(&self, keychain: KeychainKind) -> Arc<SignersContainer> {\n        match keychain {\n            KeychainKind::External => Arc::clone(&self.signers),\n            KeychainKind::Internal => Arc::clone(&self.change_signers),\n        }\n    }\n\n    /// Start building a transaction.\n    ///\n    /// This returns a blank [`TxBuilder`] from which you can specify the parameters for the transaction.\n    ///\n    /// ## Example\n    ///\n    /// ```\n    /// # use std::str::FromStr;\n    /// # use bitcoin::*;\n    /// # use bdk_wallet::*;\n    /// # use bdk_wallet::wallet::ChangeSet;\n    /// # use bdk_wallet::wallet::error::CreateTxError;\n    /// # use anyhow::Error;\n    /// # let descriptor = "wpkh(tpubD6NzVbkrYhZ4Xferm7Pz4VnjdcDPFyjVu5K4iZXQ4pVN8Cks4pHVowTBXBKRhX64pkRyJZJN5xAKj4UDNnLPb5p2sSKXhewoYx5GbTdUFWq/*)";\n    /// # let mut wallet = doctest_wallet!();\n    /// # let to_address = Address::from_str("2N4eQYCbKUHCCTUjBJeHcJp9ok6J2GZsTDt").unwrap().assume_checked();\n    /// let psbt = {\n    ///    let mut builder =  wallet.build_tx();\n    ///    builder\n    ///        .add_recipient(to_address.script_pubkey(), Amount::from_sat(50_000));\n    ///    builder.finish()?\n    /// };\n    ///\n    /// // sign and broadcast ...\n    /// # Ok::<(), anyhow::Error>(())\n    /// ```\n    ///\n    /// [`TxBuilder`]: crate::TxBuilder\n    pub fn build_tx(&mut self) -> TxBuilder<\'_, DefaultCoinSelectionAlgorithm> {\n        TxBuilder {\n            wallet: alloc::rc::Rc::new(core::cell::RefCell::new(self)),\n            params: TxParams::default(),\n            coin_selection: DefaultCoinSelectionAlgorithm::default(),\n        }\n    }\n\n    pub(crate) fn create_tx<Cs: coin_selection::CoinSelectionAlgorithm>(\n        &mut self,\n        coin_selection: Cs,\n        params: TxParams,\n        rng: &mut impl RngCore,\n    ) -> Result<Psbt, CreateTxError> {\n        let keychains: BTreeMap<_, _> = self.indexed_graph.index.keychains().collect();\n        let external_descriptor = keychains.get(&KeychainKind::External).expect("must exist");\n        let internal_descriptor = keychains.get(&KeychainKind::Internal).expect("must exist");\n\n        let external_policy = external_descriptor\n            .extract_policy(&self.signers, BuildSatisfaction::None, &self.secp)?\n            .unwrap();\n        let internal_policy = internal_descriptor\n            .extract_policy(&self.change_signers, BuildSatisfaction::None, &self.secp)?\n            .unwrap();\n\n        // The policy allows spending external outputs, but it requires a policy path that hasn\'t been\n        // provided\n        if params.change_policy != tx_builder::ChangeSpendPolicy::OnlyChange\n            && external_policy.requires_path()\n            && params.external_policy_path.is_none()\n        {\n            return Err(CreateTxError::SpendingPolicyRequired(\n                KeychainKind::External,\n            ));\n        };\n        // Same for the internal_policy path\n        if params.change_policy != tx_builder::ChangeSpendPolicy::ChangeForbidden\n            && internal_policy.requires_path()\n            && params.internal_policy_path.is_none()\n        {\n            return Err(CreateTxError::SpendingPolicyRequired(\n                KeychainKind::Internal,\n            ));\n        };\n\n        let external_requirements = external_policy.get_condition(\n            params\n                .external_policy_path\n                .as_ref()\n                .unwrap_or(&BTreeMap::new()),\n        )?;\n        let internal_requirements = internal_policy.get_condition(\n            params\n                .internal_policy_path\n                .as_ref()\n                .unwrap_or(&BTreeMap::new()),\n        )?;\n\n        let requirements = external_requirements.merge(&internal_requirements)?;\n\n        let version = match params.version {\n            Some(tx_builder::Version(0)) => return Err(CreateTxError::Version0),\n            Some(tx_builder::Version(1)) if requirements.csv.is_some() => {\n                return Err(CreateTxError::Version1Csv)\n            }\n            Some(tx_builder::Version(x)) => x,\n            None if requirements.csv.is_some() => 2,\n            None => 1,\n        };\n\n        // We use a match here instead of a unwrap_or_else as it\'s way more readable :)\n        let current_height = match params.current_height {\n            // If they didn\'t tell us the current height, we assume it\'s the latest sync height.\n            None => {\n                let tip_height = self.chain.tip().height();\n                absolute::LockTime::from_height(tip_height).expect("invalid height")\n            }\n            Some(h) => h,\n        };\n\n        let lock_time = match params.locktime {\n            // When no nLockTime is specified, we try to prevent fee sniping, if possible\n            None => {\n                // Fee sniping can be partially prevented by setting the timelock\n                // to current_height. If we don\'t know the current_height,\n                // we default to 0.\n                let fee_sniping_height = current_height;\n\n                // We choose the biggest between the required nlocktime and the fee sniping\n                // height\n                match requirements.timelock {\n                    // No requirement, just use the fee_sniping_height\n                    None => fee_sniping_height,\n                    // There\'s a block-based requirement, but the value is lower than the fee_sniping_height\n                    Some(value @ absolute::LockTime::Blocks(_)) if value < fee_sniping_height => {\n                        fee_sniping_height\n                    }\n                    // There\'s a time-based requirement or a block-based requirement greater\n                    // than the fee_sniping_height use that value\n                    Some(value) => value,\n                }\n            }\n            // Specific nLockTime required and we have no constraints, so just set to that value\n            Some(x) if requirements.timelock.is_none() => x,\n            // Specific nLockTime required and it\'s compatible with the constraints\n            Some(x)\n                if requirements.timelock.unwrap().is_same_unit(x)\n                    && x >= requirements.timelock.unwrap() =>\n            {\n                x\n            }\n            // Invalid nLockTime required\n            Some(x) => {\n                return Err(CreateTxError::LockTime {\n                    requested: x,\n                    required: requirements.timelock.unwrap(),\n                })\n            }\n        };\n\n        // The nSequence to be by default for inputs unless an explicit sequence is specified.\n        let n_sequence = match (params.rbf, requirements.csv) {\n            // No RBF or CSV but there\'s an nLockTime, so the nSequence cannot be final\n            (None, None) if lock_time != absolute::LockTime::ZERO => {\n                Sequence::ENABLE_LOCKTIME_NO_RBF\n            }\n            // No RBF, CSV or nLockTime, make the transaction final\n            (None, None) => Sequence::MAX,\n\n            // No RBF requested, use the value from CSV. Note that this value is by definition\n            // non-final, so even if a timelock is enabled this nSequence is fine, hence why we\n            // don\'t bother checking for it here. The same is true for all the other branches below\n            (None, Some(csv)) => csv,\n\n            // RBF with a specific value but that value is too high\n            (Some(tx_builder::RbfValue::Value(rbf)), _) if !rbf.is_rbf() => {\n                return Err(CreateTxError::RbfSequence)\n            }\n            // RBF with a specific value requested, but the value is incompatible with CSV\n            (Some(tx_builder::RbfValue::Value(rbf)), Some(csv))\n                if !check_nsequence_rbf(rbf, csv) =>\n            {\n                return Err(CreateTxError::RbfSequenceCsv { rbf, csv })\n            }\n\n            // RBF enabled with the default value with CSV also enabled. CSV takes precedence\n            (Some(tx_builder::RbfValue::Default), Some(csv)) => csv,\n            // Valid RBF, either default or with a specific value. We ignore the `CSV` value\n            // because we\'ve already checked it before\n            (Some(rbf), _) => rbf.get_value(),\n        };\n\n        let (fee_rate, mut fee_amount) = match params.fee_policy.unwrap_or_default() {\n            //FIXME: see https://github.com/bitcoindevkit/bdk/issues/256\n            FeePolicy::FeeAmount(fee) => {\n                if let Some(previous_fee) = params.bumping_fee {\n                    if fee < previous_fee.absolute {\n                        return Err(CreateTxError::FeeTooLow {\n                            required: Amount::from_sat(previous_fee.absolute),\n                        });\n                    }\n                }\n                (FeeRate::ZERO, fee)\n            }\n            FeePolicy::FeeRate(rate) => {\n                if let Some(previous_fee) = params.bumping_fee {\n                    let required_feerate = FeeRate::from_sat_per_kwu(\n                        previous_fee.rate.to_sat_per_kwu()\n                            + FeeRate::BROADCAST_MIN.to_sat_per_kwu(), // +1 sat/vb\n                    );\n                    if rate < required_feerate {\n                        return Err(CreateTxError::FeeRateTooLow {\n                            required: required_feerate,\n                        });\n                    }\n                }\n                (rate, 0)\n            }\n        };\n\n        let mut tx = Transaction {\n            version: transaction::Version::non_standard(version),\n            lock_time,\n            input: vec![],\n            output: vec![],\n        };\n\n        if params.manually_selected_only && params.utxos.is_empty() {\n            return Err(CreateTxError::NoUtxosSelected);\n        }\n\n        let mut outgoing = Amount::ZERO;\n        let mut received = Amount::ZERO;\n\n        let recipients = params.recipients.iter().map(|(r, v)| (r, *v));\n\n        for (index, (script_pubkey, value)) in recipients.enumerate() {\n            if !params.allow_dust && value.is_dust(script_pubkey) && !script_pubkey.is_op_return() {\n                return Err(CreateTxError::OutputBelowDustLimit(index));\n            }\n\n            if self.is_mine(script_pubkey) {\n                received += Amount::from_sat(value);\n            }\n\n            let new_out = TxOut {\n                script_pubkey: script_pubkey.clone(),\n                value: Amount::from_sat(value),\n            };\n\n            tx.output.push(new_out);\n\n            outgoing += Amount::from_sat(value);\n        }\n\n        fee_amount += (fee_rate * tx.weight()).to_sat();\n\n        let (required_utxos, optional_utxos) =\n            self.preselect_utxos(&params, Some(current_height.to_consensus_u32()));\n\n        // get drain script\n        let drain_script = match params.drain_to {\n            Some(ref drain_recipient) => drain_recipient.clone(),\n            None => {\n                let change_keychain = KeychainKind::Internal;\n                let ((index, spk), index_changeset) = self\n                    .indexed_graph\n                    .index\n                    .next_unused_spk(&change_keychain)\n                    .expect("keychain must exist");\n                self.indexed_graph.index.mark_used(change_keychain, index);\n                self.stage.append(index_changeset.into());\n                spk\n            }\n        };\n\n        let (required_utxos, optional_utxos) =\n            coin_selection::filter_duplicates(required_utxos, optional_utxos);\n\n        let coin_selection = match coin_selection.coin_select(\n            required_utxos.clone(),\n            optional_utxos.clone(),\n            fee_rate,\n            outgoing.to_sat() + fee_amount,\n            &drain_script,\n        ) {\n            Ok(res) => res,\n            Err(e) => match e {\n                coin_selection::Error::InsufficientFunds { .. } => {\n                    return Err(CreateTxError::CoinSelection(e));\n                }\n                coin_selection::Error::BnBNoExactMatch\n                | coin_selection::Error::BnBTotalTriesExceeded => {\n                    coin_selection::single_random_draw(\n                        required_utxos,\n                        optional_utxos,\n                        outgoing.to_sat() + fee_amount,\n                        &drain_script,\n                        fee_rate,\n                        rng,\n                    )\n                }\n            },\n        };\n        fee_amount += coin_selection.fee_amount;\n        let excess = &coin_selection.excess;\n\n        tx.input = coin_selection\n            .selected\n            .iter()\n            .map(|u| bitcoin::TxIn {\n                previous_output: u.outpoint(),\n                script_sig: ScriptBuf::default(),\n                sequence: u.sequence().unwrap_or(n_sequence),\n                witness: Witness::new(),\n            })\n            .collect();\n\n        if tx.output.is_empty() {\n            // Uh oh, our transaction has no outputs.\n            // We allow this when:\n            // - We have a drain_to address and the utxos we must spend (this happens,\n            // for example, when we RBF)\n            // - We have a drain_to address and drain_wallet set\n            // Otherwise, we don\'t know who we should send the funds to, and how much\n            // we should send!\n            if params.drain_to.is_some() && (params.drain_wallet || !params.utxos.is_empty()) {\n                if let NoChange {\n                    dust_threshold,\n                    remaining_amount,\n                    change_fee,\n                } = excess\n                {\n                    return Err(CreateTxError::CoinSelection(Error::InsufficientFunds {\n                        needed: *dust_threshold,\n                        available: remaining_amount.saturating_sub(*change_fee),\n                    }));\n                }\n            } else {\n                return Err(CreateTxError::NoRecipients);\n            }\n        }\n\n        match excess {\n            NoChange {\n                remaining_amount, ..\n            } => fee_amount += remaining_amount,\n            Change { amount, fee } => {\n                if self.is_mine(&drain_script) {\n                    received += Amount::from_sat(*amount);\n                }\n                fee_amount += fee;\n\n                // create drain output\n                let drain_output = TxOut {\n                    value: Amount::from_sat(*amount),\n                    script_pubkey: drain_script,\n                };\n\n                // TODO: We should pay attention when adding a new output: this might increase\n                // the length of the "number of vouts" parameter by 2 bytes, potentially making\n                // our feerate too low\n                tx.output.push(drain_output);\n            }\n        };\n\n        // sort input/outputs according to the chosen algorithm\n        params.ordering.sort_tx_with_aux_rand(&mut tx, rng);\n\n        let psbt = self.complete_transaction(tx, coin_selection.selected, params)?;\n        Ok(psbt)\n    }\n\n    /// Bump the fee of a transaction previously created with this wallet.\n    ///\n    /// Returns an error if the transaction is already confirmed or doesn\'t explicitly signal\n    /// *replace by fee* (RBF). If the transaction can be fee bumped then it returns a [`TxBuilder`]\n    /// pre-populated with the inputs and outputs of the original transaction.\n    ///\n    /// ## Example\n    ///\n    /// ```no_run\n    /// # // TODO: remove norun -- bumping fee seems to need the tx in the wallet database first.\n    /// # use std::str::FromStr;\n    /// # use bitcoin::*;\n    /// # use bdk_wallet::*;\n    /// # use bdk_wallet::wallet::ChangeSet;\n    /// # use bdk_wallet::wallet::error::CreateTxError;\n    /// # use anyhow::Error;\n    /// # let descriptor = "wpkh(tpubD6NzVbkrYhZ4Xferm7Pz4VnjdcDPFyjVu5K4iZXQ4pVN8Cks4pHVowTBXBKRhX64pkRyJZJN5xAKj4UDNnLPb5p2sSKXhewoYx5GbTdUFWq/*)";\n    /// # let mut wallet = doctest_wallet!();\n    /// # let to_address = Address::from_str("2N4eQYCbKUHCCTUjBJeHcJp9ok6J2GZsTDt").unwrap().assume_checked();\n    /// let mut psbt = {\n    ///     let mut builder = wallet.build_tx();\n    ///     builder\n    ///         .add_recipient(to_address.script_pubkey(), Amount::from_sat(50_000))\n    ///         .enable_rbf();\n    ///     builder.finish()?\n    /// };\n    /// let _ = wallet.sign(&mut psbt, SignOptions::default())?;\n    /// let tx = psbt.clone().extract_tx().expect("tx");\n    /// // broadcast tx but it\'s taking too long to confirm so we want to bump the fee\n    /// let mut psbt =  {\n    ///     let mut builder = wallet.build_fee_bump(tx.compute_txid())?;\n    ///     builder\n    ///         .fee_rate(FeeRate::from_sat_per_vb(5).expect("valid feerate"));\n    ///     builder.finish()?\n    /// };\n    ///\n    /// let _ = wallet.sign(&mut psbt, SignOptions::default())?;\n    /// let fee_bumped_tx = psbt.extract_tx();\n    /// // broadcast fee_bumped_tx to replace original\n    /// # Ok::<(), anyhow::Error>(())\n    /// ```\n    // TODO: support for merging multiple transactions while bumping the fees\n    pub fn build_fee_bump(\n        &mut self,\n        txid: Txid,\n    ) -> Result<TxBuilder<\'_, DefaultCoinSelectionAlgorithm>, BuildFeeBumpError> {\n        let graph = self.indexed_graph.graph();\n        let txout_index = &self.indexed_graph.index;\n        let chain_tip = self.chain.tip().block_id();\n\n        let mut tx = graph\n            .get_tx(txid)\n            .ok_or(BuildFeeBumpError::TransactionNotFound(txid))?\n            .as_ref()\n            .clone();\n\n        let pos = graph\n            .get_chain_position(&self.chain, chain_tip, txid)\n            .ok_or(BuildFeeBumpError::TransactionNotFound(txid))?;\n        if let ChainPosition::Confirmed(_) = pos {\n            return Err(BuildFeeBumpError::TransactionConfirmed(txid));\n        }\n\n        if !tx\n            .input\n            .iter()\n            .any(|txin| txin.sequence.to_consensus_u32() <= 0xFFFFFFFD)\n        {\n            return Err(BuildFeeBumpError::IrreplaceableTransaction(\n                tx.compute_txid(),\n            ));\n        }\n\n        let fee = self\n            .calculate_fee(&tx)\n            .map_err(|_| BuildFeeBumpError::FeeRateUnavailable)?;\n        let fee_rate = self\n            .calculate_fee_rate(&tx)\n            .map_err(|_| BuildFeeBumpError::FeeRateUnavailable)?;\n\n        // remove the inputs from the tx and process them\n        let original_txin = tx.input.drain(..).collect::<Vec<_>>();\n        let original_utxos = original_txin\n            .iter()\n            .map(|txin| -> Result<_, BuildFeeBumpError> {\n                let prev_tx = graph\n                    .get_tx(txin.previous_output.txid)\n                    .ok_or(BuildFeeBumpError::UnknownUtxo(txin.previous_output))?;\n                let txout = &prev_tx.output[txin.previous_output.vout as usize];\n\n                let confirmation_time: ConfirmationTime = graph\n                    .get_chain_position(&self.chain, chain_tip, txin.previous_output.txid)\n                    .ok_or(BuildFeeBumpError::UnknownUtxo(txin.previous_output))?\n                    .cloned()\n                    .into();\n\n                let weighted_utxo = match txout_index.index_of_spk(&txout.script_pubkey) {\n                    Some(&(keychain, derivation_index)) => {\n                        let satisfaction_weight = self\n                            .get_descriptor_for_keychain(keychain)\n                            .max_weight_to_satisfy()\n                            .unwrap();\n                        WeightedUtxo {\n                            utxo: Utxo::Local(LocalOutput {\n                                outpoint: txin.previous_output,\n                                txout: txout.clone(),\n                                keychain,\n                                is_spent: true,\n                                derivation_index,\n                                confirmation_time,\n                            }),\n                            satisfaction_weight,\n                        }\n                    }\n                    None => {\n                        let satisfaction_weight = Weight::from_wu_usize(\n                            serialize(&txin.script_sig).len() * 4 + serialize(&txin.witness).len(),\n                        );\n                        WeightedUtxo {\n                            utxo: Utxo::Foreign {\n                                outpoint: txin.previous_output,\n                                sequence: Some(txin.sequence),\n                                psbt_input: Box::new(psbt::Input {\n                                    witness_utxo: Some(txout.clone()),\n                                    non_witness_utxo: Some(prev_tx.as_ref().clone()),\n                                    ..Default::default()\n                                }),\n                            },\n                            satisfaction_weight,\n                        }\n                    }\n                };\n\n                Ok(weighted_utxo)\n            })\n            .collect::<Result<Vec<_>, _>>()?;\n\n        if tx.output.len() > 1 {\n            let mut change_index = None;\n            for (index, txout) in tx.output.iter().enumerate() {\n                let change_keychain = KeychainKind::Internal;\n                match txout_index.index_of_spk(&txout.script_pubkey) {\n                    Some((keychain, _)) if *keychain == change_keychain => {\n                        change_index = Some(index)\n                    }\n                    _ => {}\n                }\n            }\n\n            if let Some(change_index) = change_index {\n                tx.output.remove(change_index);\n            }\n        }\n\n        let params = TxParams {\n            // TODO: figure out what rbf option should be?\n            version: Some(tx_builder::Version(tx.version.0)),\n            recipients: tx\n                .output\n                .into_iter()\n                .map(|txout| (txout.script_pubkey, txout.value.to_sat()))\n                .collect(),\n            utxos: original_utxos,\n            bumping_fee: Some(tx_builder::PreviousFee {\n                absolute: fee.to_sat(),\n                rate: fee_rate,\n            }),\n            ..Default::default()\n        };\n\n        Ok(TxBuilder {\n            wallet: alloc::rc::Rc::new(core::cell::RefCell::new(self)),\n            params,\n            coin_selection: DefaultCoinSelectionAlgorithm::default(),\n        })\n    }\n\n    /// Sign a transaction with all the wallet\'s signers, in the order specified by every signer\'s\n    /// [`SignerOrdering`]. This function returns the `Result` type with an encapsulated `bool` that has the value true if the PSBT was finalized, or false otherwise.\n    ///\n    /// The [`SignOptions`] can be used to tweak the behavior of the software signers, and the way\n    /// the transaction is finalized at the end. Note that it can\'t be guaranteed that *every*\n    /// signers will follow the options, but the "software signers" (WIF keys and `xprv`) defined\n    /// in this library will.\n    ///\n    /// ## Example\n    ///\n    /// ```\n    /// # use std::str::FromStr;\n    /// # use bitcoin::*;\n    /// # use bdk_wallet::*;\n    /// # use bdk_wallet::wallet::ChangeSet;\n    /// # use bdk_wallet::wallet::error::CreateTxError;\n    /// # let descriptor = "wpkh(tpubD6NzVbkrYhZ4Xferm7Pz4VnjdcDPFyjVu5K4iZXQ4pVN8Cks4pHVowTBXBKRhX64pkRyJZJN5xAKj4UDNnLPb5p2sSKXhewoYx5GbTdUFWq/*)";\n    /// # let mut wallet = doctest_wallet!();\n    /// # let to_address = Address::from_str("2N4eQYCbKUHCCTUjBJeHcJp9ok6J2GZsTDt").unwrap().assume_checked();\n    /// let mut psbt = {\n    ///     let mut builder = wallet.build_tx();\n    ///     builder.add_recipient(to_address.script_pubkey(), Amount::from_sat(50_000));\n    ///     builder.finish()?\n    /// };\n    /// let finalized = wallet.sign(&mut psbt, SignOptions::default())?;\n    /// assert!(finalized, "we should have signed all the inputs");\n    /// # Ok::<(),anyhow::Error>(())\n    pub fn sign(&self, psbt: &mut Psbt, sign_options: SignOptions) -> Result<bool, SignerError> {\n        // This adds all the PSBT metadata for the inputs, which will help us later figure out how\n        // to derive our keys\n        self.update_psbt_with_descriptor(psbt)\n            .map_err(SignerError::MiniscriptPsbt)?;\n\n        // If we aren\'t allowed to use `witness_utxo`, ensure that every input (except p2tr and finalized ones)\n        // has the `non_witness_utxo`\n        if !sign_options.trust_witness_utxo\n            && psbt\n                .inputs\n                .iter()\n                .filter(|i| i.final_script_witness.is_none() && i.final_script_sig.is_none())\n                .filter(|i| i.tap_internal_key.is_none() && i.tap_merkle_root.is_none())\n                .any(|i| i.non_witness_utxo.is_none())\n        {\n            return Err(SignerError::MissingNonWitnessUtxo);\n        }\n\n        // If the user hasn\'t explicitly opted-in, refuse to sign the transaction unless every input\n        // is using `SIGHASH_ALL` or `SIGHASH_DEFAULT` for taproot\n        if !sign_options.allow_all_sighashes\n            && !psbt.inputs.iter().all(|i| {\n                i.sighash_type.is_none()\n                    || i.sighash_type == Some(EcdsaSighashType::All.into())\n                    || i.sighash_type == Some(TapSighashType::All.into())\n                    || i.sighash_type == Some(TapSighashType::Default.into())\n            })\n        {\n            return Err(SignerError::NonStandardSighash);\n        }\n\n        for signer in self\n            .signers\n            .signers()\n            .iter()\n            .chain(self.change_signers.signers().iter())\n        {\n            signer.sign_transaction(psbt, &sign_options, &self.secp)?;\n        }\n\n        // attempt to finalize\n        if sign_options.try_finalize {\n            self.finalize_psbt(psbt, sign_options)\n        } else {\n            Ok(false)\n        }\n    }\n\n    /// Return the spending policies for the wallet\'s descriptor\n    pub fn policies(&self, keychain: KeychainKind) -> Result<Option<Policy>, DescriptorError> {\n        let signers = match keychain {\n            KeychainKind::External => &self.signers,\n            KeychainKind::Internal => &self.change_signers,\n        };\n\n        self.public_descriptor(keychain).extract_policy(\n            signers,\n            BuildSatisfaction::None,\n            &self.secp,\n        )\n    }\n\n    /// Return the "public" version of the wallet\'s descriptor, meaning a new descriptor that has\n    /// the same structure but with every secret key removed\n    ///\n    /// This can be used to build a watch-only version of a wallet\n    pub fn public_descriptor(&self, keychain: KeychainKind) -> &ExtendedDescriptor {\n        self.indexed_graph\n            .index\n            .keychains()\n            .find(|(k, _)| *k == &keychain)\n            .map(|(_, d)| d)\n            .expect("keychain must exist")\n    }\n\n    /// Finalize a PSBT, i.e., for each input determine if sufficient data is available to pass\n    /// validation and construct the respective `scriptSig` or `scriptWitness`. Please refer to\n    /// [BIP174](https://github.com/bitcoin/bips/blob/master/bip-0174.mediawiki#Input_Finalizer),\n    /// and [BIP371](https://github.com/bitcoin/bips/blob/master/bip-0371.mediawiki)\n    /// for further information.\n    ///\n    /// Returns `true` if the PSBT could be finalized, and `false` otherwise.\n    ///\n    /// The [`SignOptions`] can be used to tweak the behavior of the finalizer.\n    pub fn finalize_psbt(\n        &self,\n        psbt: &mut Psbt,\n        sign_options: SignOptions,\n    ) -> Result<bool, SignerError> {\n        let chain_tip = self.chain.tip().block_id();\n\n        let tx = &psbt.unsigned_tx;\n        let mut finished = true;\n\n        for (n, input) in tx.input.iter().enumerate() {\n            let psbt_input = &psbt\n                .inputs\n                .get(n)\n                .ok_or(SignerError::InputIndexOutOfRange)?;\n            if psbt_input.final_script_sig.is_some() || psbt_input.final_script_witness.is_some() {\n                continue;\n            }\n            let confirmation_height = self\n                .indexed_graph\n                .graph()\n                .get_chain_position(&self.chain, chain_tip, input.previous_output.txid)\n                .map(|chain_position| match chain_position {\n                    ChainPosition::Confirmed(a) => a.confirmation_height,\n                    ChainPosition::Unconfirmed(_) => u32::MAX,\n                });\n            let current_height = sign_options\n                .assume_height\n                .unwrap_or_else(|| self.chain.tip().height());\n\n            // - Try to derive the descriptor by looking at the txout. If it\'s in our database, we\n            //   know exactly which `keychain` to use, and which derivation index it is\n            // - If that fails, try to derive it by looking at the psbt input: the complete logic\n            //   is in `src/descriptor/mod.rs`, but it will basically look at `bip32_derivation`,\n            //   `redeem_script` and `witness_script` to determine the right derivation\n            // - If that also fails, it will try it on the internal descriptor, if present\n            let desc = psbt\n                .get_utxo_for(n)\n                .and_then(|txout| self.get_descriptor_for_txout(&txout))\n                .or_else(|| {\n                    self.indexed_graph.index.keychains().find_map(|(_, desc)| {\n                        desc.derive_from_psbt_input(psbt_input, psbt.get_utxo_for(n), &self.secp)\n                    })\n                });\n\n            match desc {\n                Some(desc) => {\n                    let mut tmp_input = bitcoin::TxIn::default();\n                    match desc.satisfy(\n                        &mut tmp_input,\n                        (\n                            PsbtInputSatisfier::new(psbt, n),\n                            After::new(Some(current_height), false),\n                            Older::new(Some(current_height), confirmation_height, false),\n                        ),\n                    ) {\n                        Ok(_) => {\n                            // Set the UTXO fields, final script_sig and witness\n                            // and clear everything else.\n                            let original = mem::take(&mut psbt.inputs[n]);\n                            let psbt_input = &mut psbt.inputs[n];\n                            psbt_input.non_witness_utxo = original.non_witness_utxo;\n                            psbt_input.witness_utxo = original.witness_utxo;\n                            if !tmp_input.script_sig.is_empty() {\n                                psbt_input.final_script_sig = Some(tmp_input.script_sig);\n                            }\n                            if !tmp_input.witness.is_empty() {\n                                psbt_input.final_script_witness = Some(tmp_input.witness);\n                            }\n                        }\n                        Err(_) => finished = false,\n                    }\n                }\n                None => finished = false,\n            }\n        }\n\n        // Clear derivation paths from outputs\n        if finished {\n            for output in &mut psbt.outputs {\n                output.bip32_derivation.clear();\n                output.tap_key_origins.clear();\n            }\n        }\n\n        Ok(finished)\n    }\n\n    /// Return the secp256k1 context used for all signing operations\n    pub fn secp_ctx(&self) -> &SecpCtx {\n        &self.secp\n    }\n\n    /// Returns the descriptor used to create addresses for a particular `keychain`.\n    pub fn get_descriptor_for_keychain(&self, keychain: KeychainKind) -> &ExtendedDescriptor {\n        self.public_descriptor(keychain)\n    }\n\n    /// The derivation index of this wallet. It will return `None` if it has not derived any addresses.\n    /// Otherwise, it will return the index of the highest address it has derived.\n    pub fn derivation_index(&self, keychain: KeychainKind) -> Option<u32> {\n        self.indexed_graph.index.last_revealed_index(&keychain)\n    }\n\n    /// The index of the next address that you would get if you were to ask the wallet for a new address\n    pub fn next_derivation_index(&self, keychain: KeychainKind) -> u32 {\n        self.indexed_graph\n            .index\n            .next_index(&keychain)\n            .expect("keychain must exist")\n            .0\n    }\n\n    /// Informs the wallet that you no longer intend to broadcast a tx that was built from it.\n    ///\n    /// This frees up the change address used when creating the tx for use in future transactions.\n    // TODO: Make this free up reserved utxos when that\'s implemented\n    pub fn cancel_tx(&mut self, tx: &Transaction) {\n        let txout_index = &mut self.indexed_graph.index;\n        for txout in &tx.output {\n            if let Some((keychain, index)) = txout_index.index_of_spk(&txout.script_pubkey) {\n                // NOTE: unmark_used will **not** make something unused if it has actually been used\n                // by a tx in the tracker. It only removes the superficial marking.\n                txout_index.unmark_used(*keychain, *index);\n            }\n        }\n    }\n\n    fn get_descriptor_for_txout(&self, txout: &TxOut) -> Option<DerivedDescriptor> {\n        let &(keychain, child) = self\n            .indexed_graph\n            .index\n            .index_of_spk(&txout.script_pubkey)?;\n        let descriptor = self.get_descriptor_for_keychain(keychain);\n        descriptor.at_derivation_index(child).ok()\n    }\n\n    fn get_available_utxos(&self) -> Vec<(LocalOutput, Weight)> {\n        self.list_unspent()\n            .map(|utxo| {\n                let keychain = utxo.keychain;\n                (utxo, {\n                    self.get_descriptor_for_keychain(keychain)\n                        .max_weight_to_satisfy()\n                        .unwrap()\n                })\n            })\n            .collect()\n    }\n\n    /// Given the options returns the list of utxos that must be used to form the\n    /// transaction and any further that may be used if needed.\n    fn preselect_utxos(\n        &self,\n        params: &TxParams,\n        current_height: Option<u32>,\n    ) -> (Vec<WeightedUtxo>, Vec<WeightedUtxo>) {\n        let TxParams {\n            change_policy,\n            unspendable,\n            utxos,\n            drain_wallet,\n            manually_selected_only,\n            bumping_fee,\n            ..\n        } = params;\n\n        let manually_selected = utxos.clone();\n        // we mandate confirmed transactions if we\'re bumping the fee\n        let must_only_use_confirmed_tx = bumping_fee.is_some();\n        let must_use_all_available = *drain_wallet;\n\n        let chain_tip = self.chain.tip().block_id();\n        //    must_spend <- manually selected utxos\n        //    may_spend  <- all other available utxos\n        let mut may_spend = self.get_available_utxos();\n\n        may_spend.retain(|may_spend| {\n            !manually_selected\n                .iter()\n                .any(|manually_selected| manually_selected.utxo.outpoint() == may_spend.0.outpoint)\n        });\n        let mut must_spend = manually_selected;\n\n        // NOTE: we are intentionally ignoring `unspendable` here. i.e manual\n        // selection overrides unspendable.\n        if *manually_selected_only {\n            return (must_spend, vec![]);\n        }\n\n        let satisfies_confirmed = may_spend\n            .iter()\n            .map(|u| -> bool {\n                let txid = u.0.outpoint.txid;\n                let tx = match self.indexed_graph.graph().get_tx(txid) {\n                    Some(tx) => tx,\n                    None => return false,\n                };\n                let confirmation_time: ConfirmationTime = match self\n                    .indexed_graph\n                    .graph()\n                    .get_chain_position(&self.chain, chain_tip, txid)\n                {\n                    Some(chain_position) => chain_position.cloned().into(),\n                    None => return false,\n                };\n\n                // Whether the UTXO is mature and, if needed, confirmed\n                let mut spendable = true;\n                if must_only_use_confirmed_tx && !confirmation_time.is_confirmed() {\n                    return false;\n                }\n                if tx.is_coinbase() {\n                    debug_assert!(\n                        confirmation_time.is_confirmed(),\n                        "coinbase must always be confirmed"\n                    );\n                    if let Some(current_height) = current_height {\n                        match confirmation_time {\n                            ConfirmationTime::Confirmed { height, .. } => {\n                                // https://github.com/bitcoin/bitcoin/blob/c5e67be03bb06a5d7885c55db1f016fbf2333fe3/src/validation.cpp#L373-L375\n                                spendable &=\n                                    (current_height.saturating_sub(height)) >= COINBASE_MATURITY;\n                            }\n                            ConfirmationTime::Unconfirmed { .. } => spendable = false,\n                        }\n                    }\n                }\n                spendable\n            })\n            .collect::<Vec<_>>();\n\n        let mut i = 0;\n        may_spend.retain(|u| {\n            let retain = change_policy.is_satisfied_by(&u.0)\n                && !unspendable.contains(&u.0.outpoint)\n                && satisfies_confirmed[i];\n            i += 1;\n            retain\n        });\n\n        let mut may_spend = may_spend\n            .into_iter()\n            .map(|(local_utxo, satisfaction_weight)| WeightedUtxo {\n                satisfaction_weight,\n                utxo: Utxo::Local(local_utxo),\n            })\n            .collect();\n\n        if must_use_all_available {\n            must_spend.append(&mut may_spend);\n        }\n\n        (must_spend, may_spend)\n    }\n\n    fn complete_transaction(\n        &self,\n        tx: Transaction,\n        selected: Vec<Utxo>,\n        params: TxParams,\n    ) -> Result<Psbt, CreateTxError> {\n        let mut psbt = Psbt::from_unsigned_tx(tx)?;\n\n        if params.add_global_xpubs {\n            let all_xpubs = self\n                .keychains()\n                .flat_map(|(_, desc)| desc.get_extended_keys())\n                .collect::<Vec<_>>();\n\n            for xpub in all_xpubs {\n                let origin = match xpub.origin {\n                    Some(origin) => origin,\n                    None if xpub.xkey.depth == 0 => {\n                        (xpub.root_fingerprint(&self.secp), vec![].into())\n                    }\n                    _ => return Err(CreateTxError::MissingKeyOrigin(xpub.xkey.to_string())),\n                };\n\n                psbt.xpub.insert(xpub.xkey, origin);\n            }\n        }\n\n        let mut lookup_output = selected\n            .into_iter()\n            .map(|utxo| (utxo.outpoint(), utxo))\n            .collect::<HashMap<_, _>>();\n\n        // add metadata for the inputs\n        for (psbt_input, input) in psbt.inputs.iter_mut().zip(psbt.unsigned_tx.input.iter()) {\n            let utxo = match lookup_output.remove(&input.previous_output) {\n                Some(utxo) => utxo,\n                None => continue,\n            };\n\n            match utxo {\n                Utxo::Local(utxo) => {\n                    *psbt_input =\n                        match self.get_psbt_input(utxo, params.sighash, params.only_witness_utxo) {\n                            Ok(psbt_input) => psbt_input,\n                            Err(e) => match e {\n                                CreateTxError::UnknownUtxo => psbt::Input {\n                                    sighash_type: params.sighash,\n                                    ..psbt::Input::default()\n                                },\n                                _ => return Err(e),\n                            },\n                        }\n                }\n                Utxo::Foreign {\n                    outpoint,\n                    psbt_input: foreign_psbt_input,\n                    ..\n                } => {\n                    let is_taproot = foreign_psbt_input\n                        .witness_utxo\n                        .as_ref()\n                        .map(|txout| txout.script_pubkey.is_p2tr())\n                        .unwrap_or(false);\n                    if !is_taproot\n                        && !params.only_witness_utxo\n                        && foreign_psbt_input.non_witness_utxo.is_none()\n                    {\n                        return Err(CreateTxError::MissingNonWitnessUtxo(outpoint));\n                    }\n                    *psbt_input = *foreign_psbt_input;\n                }\n            }\n        }\n\n        self.update_psbt_with_descriptor(&mut psbt)?;\n\n        Ok(psbt)\n    }\n\n    /// get the corresponding PSBT Input for a LocalUtxo\n    pub fn get_psbt_input(\n        &self,\n        utxo: LocalOutput,\n        sighash_type: Option<psbt::PsbtSighashType>,\n        only_witness_utxo: bool,\n    ) -> Result<psbt::Input, CreateTxError> {\n        // Try to find the prev_script in our db to figure out if this is internal or external,\n        // and the derivation index\n        let &(keychain, child) = self\n            .indexed_graph\n            .index\n            .index_of_spk(&utxo.txout.script_pubkey)\n            .ok_or(CreateTxError::UnknownUtxo)?;\n\n        let mut psbt_input = psbt::Input {\n            sighash_type,\n            ..psbt::Input::default()\n        };\n\n        let desc = self.get_descriptor_for_keychain(keychain);\n        let derived_descriptor = desc\n            .at_derivation_index(child)\n            .expect("child can\'t be hardened");\n\n        psbt_input\n            .update_with_descriptor_unchecked(&derived_descriptor)\n            .map_err(MiniscriptPsbtError::Conversion)?;\n\n        let prev_output = utxo.outpoint;\n        if let Some(prev_tx) = self.indexed_graph.graph().get_tx(prev_output.txid) {\n            if desc.is_witness() || desc.is_taproot() {\n                psbt_input.witness_utxo = Some(prev_tx.output[prev_output.vout as usize].clone());\n            }\n            if !desc.is_taproot() && (!desc.is_witness() || !only_witness_utxo) {\n                psbt_input.non_witness_utxo = Some(prev_tx.as_ref().clone());\n            }\n        }\n        Ok(psbt_input)\n    }\n\n    fn update_psbt_with_descriptor(&self, psbt: &mut Psbt) -> Result<(), MiniscriptPsbtError> {\n        // We need to borrow `psbt` mutably within the loops, so we have to allocate a vec for all\n        // the input utxos and outputs\n        let utxos = (0..psbt.inputs.len())\n            .filter_map(|i| psbt.get_utxo_for(i).map(|utxo| (true, i, utxo)))\n            .chain(\n                psbt.unsigned_tx\n                    .output\n                    .iter()\n                    .enumerate()\n                    .map(|(i, out)| (false, i, out.clone())),\n            )\n            .collect::<Vec<_>>();\n\n        // Try to figure out the keychain and derivation for every input and output\n        for (is_input, index, out) in utxos.into_iter() {\n            if let Some(&(keychain, child)) =\n                self.indexed_graph.index.index_of_spk(&out.script_pubkey)\n            {\n                let desc = self.get_descriptor_for_keychain(keychain);\n                let desc = desc\n                    .at_derivation_index(child)\n                    .expect("child can\'t be hardened");\n\n                if is_input {\n                    psbt.update_input_with_descriptor(index, &desc)\n                        .map_err(MiniscriptPsbtError::UtxoUpdate)?;\n                } else {\n                    psbt.update_output_with_descriptor(index, &desc)\n                        .map_err(MiniscriptPsbtError::OutputUpdate)?;\n                }\n            }\n        }\n\n        Ok(())\n    }\n\n    /// Return the checksum of the public descriptor associated to `keychain`\n    ///\n    /// Internally calls [`Self::get_descriptor_for_keychain`] to fetch the right descriptor\n    pub fn descriptor_checksum(&self, keychain: KeychainKind) -> String {\n        self.get_descriptor_for_keychain(keychain)\n            .to_string()\n            .split_once(\'#\')\n            .unwrap()\n            .1\n            .to_string()\n    }\n\n    /// Applies an update to the wallet and stages the changes (but does not persist them).\n    ///\n    /// Usually you create an `update` by interacting with some blockchain data source and inserting\n    /// transactions related to your wallet into it.\n    ///\n    /// After applying updates you should persist the staged wallet changes. For an example of how\n    /// to persist staged wallet changes see [`Wallet::reveal_next_address`]. `\n    ///\n    /// [`commit`]: Self::commit\n    pub fn apply_update(&mut self, update: impl Into<Update>) -> Result<(), CannotConnectError> {\n        let update = update.into();\n        let mut changeset = match update.chain {\n            Some(chain_update) => ChangeSet::from(self.chain.apply_update(chain_update)?),\n            None => ChangeSet::default(),\n        };\n\n        let index_changeset = self\n            .indexed_graph\n            .index\n            .reveal_to_target_multi(&update.last_active_indices);\n        changeset.append(index_changeset.into());\n        changeset.append(self.indexed_graph.apply_update(update.graph).into());\n        self.stage.append(changeset);\n        Ok(())\n    }\n\n    /// Get a reference of the staged [`ChangeSet`] that are yet to be committed (if any).\n    pub fn staged(&self) -> Option<&ChangeSet> {\n        if self.stage.is_empty() {\n            None\n        } else {\n            Some(&self.stage)\n        }\n    }\n\n    /// Take the staged [`ChangeSet`] to be persisted now (if any).\n    pub fn take_staged(&mut self) -> Option<ChangeSet> {\n        self.stage.take()\n    }\n\n    /// Get a reference to the inner [`TxGraph`].\n    pub fn tx_graph(&self) -> &TxGraph<ConfirmationTimeHeightAnchor> {\n        self.indexed_graph.graph()\n    }\n\n    /// Get a reference to the inner [`KeychainTxOutIndex`].\n    pub fn spk_index(&self) -> &KeychainTxOutIndex<KeychainKind> {\n        &self.indexed_graph.index\n    }\n\n    /// Get a reference to the inner [`LocalChain`].\n    pub fn local_chain(&self) -> &LocalChain {\n        &self.chain\n    }\n\n    /// Introduces a `block` of `height` to the wallet, and tries to connect it to the\n    /// `prev_blockhash` of the block\'s header.\n    ///\n    /// This is a convenience method that is equivalent to calling [`apply_block_connected_to`]\n    /// with `prev_blockhash` and `height-1` as the `connected_to` parameter.\n    ///\n    /// [`apply_block_connected_to`]: Self::apply_block_connected_to\n    pub fn apply_block(&mut self, block: &Block, height: u32) -> Result<(), CannotConnectError> {\n        let connected_to = match height.checked_sub(1) {\n            Some(prev_height) => BlockId {\n                height: prev_height,\n                hash: block.header.prev_blockhash,\n            },\n            None => BlockId {\n                height,\n                hash: block.block_hash(),\n            },\n        };\n        self.apply_block_connected_to(block, height, connected_to)\n            .map_err(|err| match err {\n                ApplyHeaderError::InconsistentBlocks => {\n                    unreachable!("connected_to is derived from the block so must be consistent")\n                }\n                ApplyHeaderError::CannotConnect(err) => err,\n            })\n    }\n\n    /// Applies relevant transactions from `block` of `height` to the wallet, and connects the\n    /// block to the internal chain.\n    ///\n    /// The `connected_to` parameter informs the wallet how this block connects to the internal\n    /// [`LocalChain`]. Relevant transactions are filtered from the `block` and inserted into the\n    /// internal [`TxGraph`].\n    ///\n    /// **WARNING**: You must persist the changes resulting from one or more calls to this method\n    /// if you need the inserted block data to be reloaded after closing the wallet.\n    /// See [`Wallet::reveal_next_address`].\n    pub fn apply_block_connected_to(\n        &mut self,\n        block: &Block,\n        height: u32,\n        connected_to: BlockId,\n    ) -> Result<(), ApplyHeaderError> {\n        let mut changeset = ChangeSet::default();\n        changeset.append(\n            self.chain\n                .apply_header_connected_to(&block.header, height, connected_to)?\n                .into(),\n        );\n        changeset.append(\n            self.indexed_graph\n                .apply_block_relevant(block, height)\n                .into(),\n        );\n        self.stage.append(changeset);\n        Ok(())\n    }\n\n    /// Apply relevant unconfirmed transactions to the wallet.\n    ///\n    /// Transactions that are not relevant are filtered out.\n    ///\n    /// This method takes in an iterator of `(tx, last_seen)` where `last_seen` is the timestamp of\n    /// when the transaction was last seen in the mempool. This is used for conflict resolution\n    /// when there is conflicting unconfirmed transactions. The transaction with the later\n    /// `last_seen` is prioritized.\n    ///\n    /// **WARNING**: You must persist the changes resulting from one or more calls to this method\n    /// if you need the applied unconfirmed transactions to be reloaded after closing the wallet.\n    /// See [`Wallet::reveal_next_address`].\n    pub fn apply_unconfirmed_txs<\'t>(\n        &mut self,\n        unconfirmed_txs: impl IntoIterator<Item = (&\'t Transaction, u64)>,\n    ) {\n        let indexed_graph_changeset = self\n            .indexed_graph\n            .batch_insert_relevant_unconfirmed(unconfirmed_txs);\n        self.stage.append(indexed_graph_changeset.into());\n    }\n}\n\n/// Methods to construct sync/full-scan requests for spk-based chain sources.\nimpl Wallet {\n    /// Create a partial [`SyncRequest`] for this wallet for all revealed spks.\n    ///\n    /// This is the first step when performing a spk-based wallet partial sync, the returned\n    /// [`SyncRequest`] collects all revealed script pubkeys from the wallet keychain needed to\n    /// start a blockchain sync with a spk based blockchain client.\n    pub fn start_sync_with_revealed_spks(&self) -> SyncRequest {\n        SyncRequest::from_chain_tip(self.chain.tip())\n            .populate_with_revealed_spks(&self.indexed_graph.index, ..)\n    }\n\n    /// Create a [`FullScanRequest] for this wallet.\n    ///\n    /// This is the first step when performing a spk-based wallet full scan, the returned\n    /// [`FullScanRequest] collects iterators for the wallet\'s keychain script pub keys needed to\n    /// start a blockchain full scan with a spk based blockchain client.\n    ///\n    /// This operation is generally only used when importing or restoring a previously used wallet\n    /// in which the list of used scripts is not known.\n    pub fn start_full_scan(&self) -> FullScanRequest<KeychainKind> {\n        FullScanRequest::from_keychain_txout_index(self.chain.tip(), &self.indexed_graph.index)\n    }\n}\n\nimpl AsRef<bdk_chain::tx_graph::TxGraph<ConfirmationTimeHeightAnchor>> for Wallet {\n    fn as_ref(&self) -> &bdk_chain::tx_graph::TxGraph<ConfirmationTimeHeightAnchor> {\n        self.indexed_graph.graph()\n    }\n}\n\n/// Deterministically generate a unique name given the descriptors defining the wallet\n///\n/// Compatible with [`wallet_name_from_descriptor`]\npub fn wallet_name_from_descriptor<T>(\n    descriptor: T,\n    change_descriptor: Option<T>,\n    network: Network,\n    secp: &SecpCtx,\n) -> Result<String, DescriptorError>\nwhere\n    T: IntoWalletDescriptor,\n{\n    //TODO check descriptors contains only public keys\n    let descriptor = descriptor\n        .into_wallet_descriptor(secp, network)?\n        .0\n        .to_string();\n    let mut wallet_name = calc_checksum(&descriptor[..descriptor.find(\'#\').unwrap()])?;\n    if let Some(change_descriptor) = change_descriptor {\n        let change_descriptor = change_descriptor\n            .into_wallet_descriptor(secp, network)?\n            .0\n            .to_string();\n        wallet_name.push_str(\n            calc_checksum(&change_descriptor[..change_descriptor.find(\'#\').unwrap()])?.as_str(),\n        );\n    }\n\n    Ok(wallet_name)\n}\n\nfn new_local_utxo(\n    keychain: KeychainKind,\n    derivation_index: u32,\n    full_txo: FullTxOut<ConfirmationTimeHeightAnchor>,\n) -> LocalOutput {\n    LocalOutput {\n        outpoint: full_txo.outpoint,\n        txout: full_txo.txout,\n        is_spent: full_txo.spent_by.is_some(),\n        confirmation_time: full_txo.chain_position.into(),\n        keychain,\n        derivation_index,\n    }\n}\n\nfn create_signers<E: IntoWalletDescriptor>(\n    index: &mut KeychainTxOutIndex<KeychainKind>,\n    secp: &Secp256k1<All>,\n    descriptor: E,\n    change_descriptor: E,\n    network: Network,\n) -> Result<(Arc<SignersContainer>, Arc<SignersContainer>), DescriptorError> {\n    let descriptor = into_wallet_descriptor_checked(descriptor, secp, network)?;\n    let change_descriptor = into_wallet_descriptor_checked(change_descriptor, secp, network)?;\n    let (descriptor, keymap) = descriptor;\n    let signers = Arc::new(SignersContainer::build(keymap, &descriptor, secp));\n    let _ = index\n        .insert_descriptor(KeychainKind::External, descriptor)\n        .expect("this is the first descriptor we\'re inserting");\n\n    let (descriptor, keymap) = change_descriptor;\n    let change_signers = Arc::new(SignersContainer::build(keymap, &descriptor, secp));\n    let _ = index\n        .insert_descriptor(KeychainKind::Internal, descriptor)\n        .map_err(|e| {\n            use bdk_chain::keychain::InsertDescriptorError;\n            match e {\n                InsertDescriptorError::DescriptorAlreadyAssigned { .. } => {\n                    crate::descriptor::error::Error::ExternalAndInternalAreTheSame\n                }\n                InsertDescriptorError::KeychainAlreadyAssigned { .. } => {\n                    unreachable!("this is the first time we\'re assigning internal")\n                }\n            }\n        })?;\n\n    Ok((signers, change_signers))\n}\n\n/// Transforms a [`FeeRate`] to `f64` with unit as sat/vb.\n#[macro_export]\n#[doc(hidden)]\nmacro_rules! floating_rate {\n    ($rate:expr) => {{\n        use $crate::bitcoin::blockdata::constants::WITNESS_SCALE_FACTOR;\n        // sat_kwu / 250.0 -> sat_vb\n        $rate.to_sat_per_kwu() as f64 / ((1000 / WITNESS_SCALE_FACTOR) as f64)\n    }};\n}\n\n#[macro_export]\n#[doc(hidden)]\n/// Macro for getting a wallet for use in a doctest\nmacro_rules! doctest_wallet {\n    () => {{\n        use $crate::bitcoin::{BlockHash, Transaction, absolute, TxOut, Network, hashes::Hash};\n        use $crate::chain::{ConfirmationTime, BlockId};\n        use $crate::{KeychainKind, wallet::Wallet};\n        let descriptor = "tr([73c5da0a/86\'/0\'/0\']tprv8fMn4hSKPRC1oaCPqxDb1JWtgkpeiQvZhsr8W2xuy3GEMkzoArcAWTfJxYb6Wj8XNNDWEjfYKK4wGQXh3ZUXhDF2NcnsALpWTeSwarJt7Vc/0/*)";\n        let change_descriptor = "tr([73c5da0a/86\'/0\'/0\']tprv8fMn4hSKPRC1oaCPqxDb1JWtgkpeiQvZhsr8W2xuy3GEMkzoArcAWTfJxYb6Wj8XNNDWEjfYKK4wGQXh3ZUXhDF2NcnsALpWTeSwarJt7Vc/1/*)";\n\n        let mut wallet = Wallet::new(\n            descriptor,\n            change_descriptor,\n            Network::Regtest,\n        )\n        .unwrap();\n        let address = wallet.peek_address(KeychainKind::External, 0).address;\n        let tx = Transaction {\n            version: transaction::Version::ONE,\n            lock_time: absolute::LockTime::ZERO,\n            input: vec![],\n            output: vec![TxOut {\n                value: Amount::from_sat(500_000),\n                script_pubkey: address.script_pubkey(),\n            }],\n        };\n        let _ = wallet.insert_checkpoint(BlockId { height: 1_000, hash: BlockHash::all_zeros() });\n        let _ = wallet.insert_tx(tx.clone(), ConfirmationTime::Confirmed {\n            height: 500,\n            time: 50_000\n        });\n\n        wallet\n    }}\n}\n',
            'crates/wallet/tests/wallet.rs': 'use std::path::Path;\nuse std::str::FromStr;\n\nuse assert_matches::assert_matches;\nuse bdk_chain::collections::BTreeMap;\nuse bdk_chain::COINBASE_MATURITY;\nuse bdk_chain::{BlockId, ConfirmationTime};\nuse bdk_sqlite::rusqlite::Connection;\nuse bdk_wallet::descriptor::{calc_checksum, DescriptorError, IntoWalletDescriptor};\nuse bdk_wallet::psbt::PsbtUtils;\nuse bdk_wallet::signer::{SignOptions, SignerError};\nuse bdk_wallet::wallet::coin_selection::{self, LargestFirstCoinSelection};\nuse bdk_wallet::wallet::error::CreateTxError;\nuse bdk_wallet::wallet::tx_builder::AddForeignUtxoError;\nuse bdk_wallet::wallet::{AddressInfo, Balance, ChangeSet, NewError, Wallet};\nuse bdk_wallet::KeychainKind;\nuse bitcoin::hashes::Hash;\nuse bitcoin::key::Secp256k1;\nuse bitcoin::psbt;\nuse bitcoin::script::PushBytesBuf;\nuse bitcoin::sighash::{EcdsaSighashType, TapSighashType};\nuse bitcoin::taproot::TapNodeHash;\nuse bitcoin::{\n    absolute, transaction, Address, Amount, BlockHash, FeeRate, Network, OutPoint, ScriptBuf,\n    Sequence, Transaction, TxIn, TxOut, Txid, Weight,\n};\nuse rand::rngs::StdRng;\nuse rand::SeedableRng;\n\nmod common;\nuse common::*;\n\nfn receive_output(wallet: &mut Wallet, value: u64, height: ConfirmationTime) -> OutPoint {\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let tx = Transaction {\n        version: transaction::Version::ONE,\n        lock_time: absolute::LockTime::ZERO,\n        input: vec![],\n        output: vec![TxOut {\n            script_pubkey: addr.script_pubkey(),\n            value: Amount::from_sat(value),\n        }],\n    };\n\n    wallet.insert_tx(tx.clone(), height).unwrap();\n\n    OutPoint {\n        txid: tx.compute_txid(),\n        vout: 0,\n    }\n}\n\nfn receive_output_in_latest_block(wallet: &mut Wallet, value: u64) -> OutPoint {\n    let latest_cp = wallet.latest_checkpoint();\n    let height = latest_cp.height();\n    let anchor = if height == 0 {\n        ConfirmationTime::Unconfirmed { last_seen: 0 }\n    } else {\n        ConfirmationTime::Confirmed { height, time: 0 }\n    };\n    receive_output(wallet, value, anchor)\n}\n\n// The satisfaction size of a P2WPKH is 112 WU =\n// 1 (elements in witness) + 1 (OP_PUSH) + 33 (pk) + 1 (OP_PUSH) + 72 (signature + sighash) + 1*4 (script len)\n// On the witness itself, we have to push once for the pk (33WU) and once for signature + sighash (72WU), for\n// a total of 105 WU.\n// Here, we push just once for simplicity, so we have to add an extra byte for the missing\n// OP_PUSH.\nconst P2WPKH_FAKE_WITNESS_SIZE: usize = 106;\n\nconst DB_MAGIC: &[u8] = &[0x21, 0x24, 0x48];\n\n#[test]\nfn load_recovers_wallet() -> anyhow::Result<()> {\n    fn run<Db, New, Recover, Read, Write>(\n        filename: &str,\n        create_new: New,\n        recover: Recover,\n        read: Read,\n        write: Write,\n    ) -> anyhow::Result<()>\n    where\n        New: Fn(&Path) -> anyhow::Result<Db>,\n        Recover: Fn(&Path) -> anyhow::Result<Db>,\n        Read: Fn(&mut Db) -> anyhow::Result<Option<ChangeSet>>,\n        Write: Fn(&mut Db, &ChangeSet) -> anyhow::Result<()>,\n    {\n        let temp_dir = tempfile::tempdir().expect("must create tempdir");\n        let file_path = temp_dir.path().join(filename);\n        let (desc, change_desc) = get_test_tr_single_sig_xprv_with_change_desc();\n\n        // create new wallet\n        let wallet_spk_index = {\n            let mut wallet =\n                Wallet::new(desc, change_desc, Network::Testnet).expect("must init wallet");\n\n            wallet.reveal_next_address(KeychainKind::External);\n\n            // persist new wallet changes\n            let mut db = create_new(&file_path).expect("must create db");\n            if let Some(changeset) = wallet.take_staged() {\n                write(&mut db, &changeset)?;\n            }\n            wallet.spk_index().clone()\n        };\n\n        // recover wallet\n        {\n            // load persisted wallet changes\n            let db = &mut recover(&file_path).expect("must recover db");\n            let changeset = read(db).expect("must recover wallet").expect("changeset");\n\n            let wallet = Wallet::load_from_changeset(changeset).expect("must recover wallet");\n            assert_eq!(wallet.network(), Network::Testnet);\n            assert_eq!(\n                wallet.spk_index().keychains().collect::<Vec<_>>(),\n                wallet_spk_index.keychains().collect::<Vec<_>>()\n            );\n            assert_eq!(\n                wallet.spk_index().last_revealed_indices(),\n                wallet_spk_index.last_revealed_indices()\n            );\n            let secp = Secp256k1::new();\n            assert_eq!(\n                *wallet.get_descriptor_for_keychain(KeychainKind::External),\n                desc.into_wallet_descriptor(&secp, wallet.network())\n                    .unwrap()\n                    .0\n            );\n        }\n\n        Ok(())\n    }\n\n    run(\n        "store.db",\n        |path| Ok(bdk_file_store::Store::create_new(DB_MAGIC, path)?),\n        |path| Ok(bdk_file_store::Store::open(DB_MAGIC, path)?),\n        |db| Ok(bdk_file_store::Store::aggregate_changesets(db)?),\n        |db, changeset| Ok(bdk_file_store::Store::append_changeset(db, changeset)?),\n    )?;\n    run(\n        "store.sqlite",\n        |path| Ok(bdk_sqlite::Store::new(Connection::open(path)?)?),\n        |path| Ok(bdk_sqlite::Store::new(Connection::open(path)?)?),\n        |db| Ok(bdk_sqlite::Store::read(db)?),\n        |db, changeset| Ok(bdk_sqlite::Store::write(db, changeset)?),\n    )?;\n\n    Ok(())\n}\n\n#[test]\nfn new_or_load() -> anyhow::Result<()> {\n    fn run<Db, NewOrRecover, Read, Write>(\n        filename: &str,\n        new_or_load: NewOrRecover,\n        read: Read,\n        write: Write,\n    ) -> anyhow::Result<()>\n    where\n        NewOrRecover: Fn(&Path) -> anyhow::Result<Db>,\n        Read: Fn(&mut Db) -> anyhow::Result<Option<ChangeSet>>,\n        Write: Fn(&mut Db, &ChangeSet) -> anyhow::Result<()>,\n    {\n        let temp_dir = tempfile::tempdir().expect("must create tempdir");\n        let file_path = temp_dir.path().join(filename);\n        let (desc, change_desc) = get_test_wpkh_with_change_desc();\n\n        // init wallet when non-existent\n        let wallet_keychains: BTreeMap<_, _> = {\n            let wallet = &mut Wallet::new_or_load(desc, change_desc, None, Network::Testnet)\n                .expect("must init wallet");\n            let mut db = new_or_load(&file_path).expect("must create db");\n            if let Some(changeset) = wallet.take_staged() {\n                write(&mut db, &changeset)?;\n            }\n            wallet.keychains().map(|(k, v)| (*k, v.clone())).collect()\n        };\n\n        // wrong network\n        {\n            let mut db = new_or_load(&file_path).expect("must create db");\n            let changeset = read(&mut db)?;\n            let err = Wallet::new_or_load(desc, change_desc, changeset, Network::Bitcoin)\n                .expect_err("wrong network");\n            assert!(\n                matches!(\n                    err,\n                    bdk_wallet::wallet::NewOrLoadError::LoadedNetworkDoesNotMatch {\n                        got: Some(Network::Testnet),\n                        expected: Network::Bitcoin\n                    }\n                ),\n                "err: {}",\n                err,\n            );\n        }\n\n        // wrong genesis hash\n        {\n            let exp_blockhash = BlockHash::all_zeros();\n            let got_blockhash =\n                bitcoin::blockdata::constants::genesis_block(Network::Testnet).block_hash();\n\n            let db = &mut new_or_load(&file_path).expect("must open db");\n            let changeset = read(db)?;\n            let err = Wallet::new_or_load_with_genesis_hash(\n                desc,\n                change_desc,\n                changeset,\n                Network::Testnet,\n                exp_blockhash,\n            )\n            .expect_err("wrong genesis hash");\n            assert!(\n                matches!(\n                    err,\n                    bdk_wallet::wallet::NewOrLoadError::LoadedGenesisDoesNotMatch { got, expected }\n                    if got == Some(got_blockhash) && expected == exp_blockhash\n                ),\n                "err: {}",\n                err,\n            );\n        }\n\n        // wrong external descriptor\n        {\n            let (exp_descriptor, exp_change_desc) = get_test_tr_single_sig_xprv_with_change_desc();\n            let got_descriptor = desc\n                .into_wallet_descriptor(&Secp256k1::new(), Network::Testnet)\n                .unwrap()\n                .0;\n\n            let db = &mut new_or_load(&file_path).expect("must open db");\n            let changeset = read(db)?;\n            let err =\n                Wallet::new_or_load(exp_descriptor, exp_change_desc, changeset, Network::Testnet)\n                    .expect_err("wrong external descriptor");\n            assert!(\n                matches!(\n                    err,\n                    bdk_wallet::wallet::NewOrLoadError::LoadedDescriptorDoesNotMatch { ref got, keychain }\n                    if got == &Some(got_descriptor) && keychain == KeychainKind::External\n                ),\n                "err: {}",\n                err,\n            );\n        }\n\n        // wrong internal descriptor\n        {\n            let exp_descriptor = get_test_tr_single_sig();\n            let got_descriptor = change_desc\n                .into_wallet_descriptor(&Secp256k1::new(), Network::Testnet)\n                .unwrap()\n                .0;\n\n            let db = &mut new_or_load(&file_path).expect("must open db");\n            let changeset = read(db)?;\n            let err = Wallet::new_or_load(desc, exp_descriptor, changeset, Network::Testnet)\n                .expect_err("wrong internal descriptor");\n            assert!(\n                matches!(\n                    err,\n                    bdk_wallet::wallet::NewOrLoadError::LoadedDescriptorDoesNotMatch { ref got, keychain }\n                    if got == &Some(got_descriptor) && keychain == KeychainKind::Internal\n                ),\n                "err: {}",\n                err,\n            );\n        }\n\n        // all parameters match\n        {\n            let db = &mut new_or_load(&file_path).expect("must open db");\n            let changeset = read(db)?;\n            let wallet = Wallet::new_or_load(desc, change_desc, changeset, Network::Testnet)\n                .expect("must recover wallet");\n            assert_eq!(wallet.network(), Network::Testnet);\n            assert!(wallet\n                .keychains()\n                .map(|(k, v)| (*k, v.clone()))\n                .eq(wallet_keychains));\n        }\n        Ok(())\n    }\n\n    run(\n        "store.db",\n        |path| Ok(bdk_file_store::Store::open_or_create_new(DB_MAGIC, path)?),\n        |db| Ok(bdk_file_store::Store::aggregate_changesets(db)?),\n        |db, changeset| Ok(bdk_file_store::Store::append_changeset(db, changeset)?),\n    )?;\n    run(\n        "store.sqlite",\n        |path| Ok(bdk_sqlite::Store::new(Connection::open(path)?)?),\n        |db| Ok(bdk_sqlite::Store::read(db)?),\n        |db, changeset| Ok(bdk_sqlite::Store::write(db, changeset)?),\n    )?;\n\n    Ok(())\n}\n\n#[test]\nfn test_error_external_and_internal_are_the_same() {\n    // identical descriptors should fail to create wallet\n    let desc = get_test_wpkh();\n    let err = Wallet::new(desc, desc, Network::Testnet);\n    assert!(\n        matches!(\n            &err,\n            Err(NewError::Descriptor(\n                DescriptorError::ExternalAndInternalAreTheSame\n            ))\n        ),\n        "expected same descriptors error, got {:?}",\n        err,\n    );\n\n    // public + private of same descriptor should fail to create wallet\n    let desc = "wpkh(tprv8ZgxMBicQKsPdcAqYBpzAFwU5yxBUo88ggoBqu1qPcHUfSbKK1sKMLmC7EAk438btHQrSdu3jGGQa6PA71nvH5nkDexhLteJqkM4dQmWF9g/84\'/1\'/0\'/0/*)";\n    let change_desc = "wpkh([3c31d632/84\'/1\'/0\']tpubDCYwFkks2cg78N7eoYbBatsFEGje8vW8arSKW4rLwD1AU1s9KJMDRHE32JkvYERuiFjArrsH7qpWSpJATed5ShZbG9KsskA5Rmi6NSYgYN2/0/*)";\n    let err = Wallet::new(desc, change_desc, Network::Testnet);\n    assert!(\n        matches!(\n            err,\n            Err(NewError::Descriptor(\n                DescriptorError::ExternalAndInternalAreTheSame\n            ))\n        ),\n        "expected same descriptors error, got {:?}",\n        err,\n    );\n}\n\n#[test]\nfn test_descriptor_checksum() {\n    let (wallet, _) = get_funded_wallet_wpkh();\n    let checksum = wallet.descriptor_checksum(KeychainKind::External);\n    assert_eq!(checksum.len(), 8);\n\n    let raw_descriptor = wallet\n        .keychains()\n        .next()\n        .unwrap()\n        .1\n        .to_string()\n        .split_once(\'#\')\n        .unwrap()\n        .0\n        .to_string();\n    assert_eq!(calc_checksum(&raw_descriptor).unwrap(), checksum);\n}\n\n#[test]\nfn test_get_funded_wallet_balance() {\n    let (wallet, _) = get_funded_wallet_wpkh();\n\n    // The funded wallet contains a tx with a 76_000 sats input and two outputs, one spending 25_000\n    // to a foreign address and one returning 50_000 back to the wallet as change. The remaining 1000\n    // sats are the transaction fee.\n    assert_eq!(wallet.balance().confirmed, Amount::from_sat(50_000));\n}\n\n#[test]\nfn test_get_funded_wallet_sent_and_received() {\n    let (wallet, txid) = get_funded_wallet_wpkh();\n\n    let mut tx_amounts: Vec<(Txid, (Amount, Amount))> = wallet\n        .transactions()\n        .map(|ct| (ct.tx_node.txid, wallet.sent_and_received(&ct.tx_node)))\n        .collect();\n    tx_amounts.sort_by(|a1, a2| a1.0.cmp(&a2.0));\n\n    let tx = wallet.get_tx(txid).expect("transaction").tx_node.tx;\n    let (sent, received) = wallet.sent_and_received(&tx);\n\n    // The funded wallet contains a tx with a 76_000 sats input and two outputs, one spending 25_000\n    // to a foreign address and one returning 50_000 back to the wallet as change. The remaining 1000\n    // sats are the transaction fee.\n    assert_eq!(sent.to_sat(), 76_000);\n    assert_eq!(received.to_sat(), 50_000);\n}\n\n#[test]\nfn test_get_funded_wallet_tx_fees() {\n    let (wallet, txid) = get_funded_wallet_wpkh();\n\n    let tx = wallet.get_tx(txid).expect("transaction").tx_node.tx;\n    let tx_fee = wallet.calculate_fee(&tx).expect("transaction fee");\n\n    // The funded wallet contains a tx with a 76_000 sats input and two outputs, one spending 25_000\n    // to a foreign address and one returning 50_000 back to the wallet as change. The remaining 1000\n    // sats are the transaction fee.\n    assert_eq!(tx_fee, Amount::from_sat(1000))\n}\n\n#[test]\nfn test_get_funded_wallet_tx_fee_rate() {\n    let (wallet, txid) = get_funded_wallet_wpkh();\n\n    let tx = wallet.get_tx(txid).expect("transaction").tx_node.tx;\n    let tx_fee_rate = wallet\n        .calculate_fee_rate(&tx)\n        .expect("transaction fee rate");\n\n    // The funded wallet contains a tx with a 76_000 sats input and two outputs, one spending 25_000\n    // to a foreign address and one returning 50_000 back to the wallet as change. The remaining 1000\n    // sats are the transaction fee.\n\n    // tx weight = 452 wu, as vbytes = (452 + 3) / 4 = 113\n    // fee_rate (sats per kwu) = fee / weight = 1000sat / 0.452kwu = 2212\n    // fee_rate (sats per vbyte ceil) = fee / vsize = 1000sat / 113vb = 9\n    assert_eq!(tx_fee_rate.to_sat_per_kwu(), 2212);\n    assert_eq!(tx_fee_rate.to_sat_per_vb_ceil(), 9);\n}\n\n#[test]\nfn test_list_output() {\n    let (wallet, txid) = get_funded_wallet_wpkh();\n    let txos = wallet\n        .list_output()\n        .map(|op| (op.outpoint, op))\n        .collect::<std::collections::BTreeMap<_, _>>();\n    assert_eq!(txos.len(), 2);\n    for (op, txo) in txos {\n        if op.txid == txid {\n            assert_eq!(txo.txout.value.to_sat(), 50_000);\n            assert!(!txo.is_spent);\n        } else {\n            assert_eq!(txo.txout.value.to_sat(), 76_000);\n            assert!(txo.is_spent);\n        }\n    }\n}\n\nmacro_rules! assert_fee_rate {\n    ($psbt:expr, $fees:expr, $fee_rate:expr $( ,@dust_change $( $dust_change:expr )* )* $( ,@add_signature $( $add_signature:expr )* )* ) => ({\n        let psbt = $psbt.clone();\n        #[allow(unused_mut)]\n        let mut tx = $psbt.clone().extract_tx().expect("failed to extract tx");\n        $(\n            $( $add_signature )*\n                for txin in &mut tx.input {\n                    txin.witness.push([0x00; P2WPKH_FAKE_WITNESS_SIZE]); // fake signature\n                }\n        )*\n\n            #[allow(unused_mut)]\n        #[allow(unused_assignments)]\n        let mut dust_change = false;\n        $(\n            $( $dust_change )*\n                dust_change = true;\n        )*\n\n            let fee_amount = psbt\n            .inputs\n            .iter()\n            .fold(Amount::ZERO, |acc, i| acc + i.witness_utxo.as_ref().unwrap().value)\n            - psbt\n            .unsigned_tx\n            .output\n            .iter()\n            .fold(Amount::ZERO, |acc, o| acc + o.value);\n\n        assert_eq!(fee_amount, $fees);\n\n        let tx_fee_rate = (fee_amount / tx.weight())\n            .to_sat_per_kwu();\n        let fee_rate = $fee_rate.to_sat_per_kwu();\n        let half_default = FeeRate::BROADCAST_MIN.checked_div(2)\n            .unwrap()\n            .to_sat_per_kwu();\n\n        if !dust_change {\n            assert!(tx_fee_rate >= fee_rate && tx_fee_rate - fee_rate < half_default, "Expected fee rate of {:?}, the tx has {:?}", fee_rate, tx_fee_rate);\n        } else {\n            assert!(tx_fee_rate >= fee_rate, "Expected fee rate of at least {:?}, the tx has {:?}", fee_rate, tx_fee_rate);\n        }\n    });\n}\n\nmacro_rules! from_str {\n    ($e:expr, $t:ty) => {{\n        use core::str::FromStr;\n        <$t>::from_str($e).unwrap()\n    }};\n\n    ($e:expr) => {\n        from_str!($e, _)\n    };\n}\n\n#[test]\n#[should_panic(expected = "NoRecipients")]\nfn test_create_tx_empty_recipients() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    wallet.build_tx().finish().unwrap();\n}\n\n#[test]\n#[should_panic(expected = "NoUtxosSelected")]\nfn test_create_tx_manually_selected_empty_utxos() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .manually_selected_only();\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_create_tx_version_0() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .version(0);\n    assert!(matches!(builder.finish(), Err(CreateTxError::Version0)));\n}\n\n#[test]\nfn test_create_tx_version_1_csv() {\n    let (mut wallet, _) = get_funded_wallet(get_test_single_sig_csv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .version(1);\n    assert!(matches!(builder.finish(), Err(CreateTxError::Version1Csv)));\n}\n\n#[test]\nfn test_create_tx_custom_version() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .version(42);\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.version.0, 42);\n}\n\n#[test]\nfn test_create_tx_default_locktime_is_last_sync_height() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let psbt = builder.finish().unwrap();\n\n    // Since we never synced the wallet we don\'t have a last_sync_height\n    // we could use to try to prevent fee sniping. We default to 0.\n    assert_eq!(psbt.unsigned_tx.lock_time.to_consensus_u32(), 2_000);\n}\n\n#[test]\nfn test_create_tx_fee_sniping_locktime_last_sync() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n\n    let psbt = builder.finish().unwrap();\n\n    // If there\'s no current_height we\'re left with using the last sync height\n    assert_eq!(\n        psbt.unsigned_tx.lock_time.to_consensus_u32(),\n        wallet.latest_checkpoint().height()\n    );\n}\n\n#[test]\nfn test_create_tx_default_locktime_cltv() {\n    let (mut wallet, _) = get_funded_wallet(get_test_single_sig_cltv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.lock_time.to_consensus_u32(), 100_000);\n}\n\n#[test]\nfn test_create_tx_custom_locktime() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .current_height(630_001)\n        .nlocktime(absolute::LockTime::from_height(630_000).unwrap());\n    let psbt = builder.finish().unwrap();\n\n    // When we explicitly specify a nlocktime\n    // we don\'t try any fee sniping prevention trick\n    // (we ignore the current_height)\n    assert_eq!(psbt.unsigned_tx.lock_time.to_consensus_u32(), 630_000);\n}\n\n#[test]\nfn test_create_tx_custom_locktime_compatible_with_cltv() {\n    let (mut wallet, _) = get_funded_wallet(get_test_single_sig_cltv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .nlocktime(absolute::LockTime::from_height(630_000).unwrap());\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.lock_time.to_consensus_u32(), 630_000);\n}\n\n#[test]\nfn test_create_tx_custom_locktime_incompatible_with_cltv() {\n    let (mut wallet, _) = get_funded_wallet(get_test_single_sig_cltv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .nlocktime(absolute::LockTime::from_height(50000).unwrap());\n    assert!(matches!(builder.finish(),\n        Err(CreateTxError::LockTime { requested, required })\n        if requested.to_consensus_u32() == 50_000 && required.to_consensus_u32() == 100_000));\n}\n\n#[test]\nfn test_create_tx_no_rbf_csv() {\n    let (mut wallet, _) = get_funded_wallet(get_test_single_sig_csv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.input[0].sequence, Sequence(6));\n}\n\n#[test]\nfn test_create_tx_with_default_rbf_csv() {\n    let (mut wallet, _) = get_funded_wallet(get_test_single_sig_csv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    // When CSV is enabled it takes precedence over the rbf value (unless forced by the user).\n    // It will be set to the OP_CSV value, in this case 6\n    assert_eq!(psbt.unsigned_tx.input[0].sequence, Sequence(6));\n}\n\n#[test]\nfn test_create_tx_with_custom_rbf_csv() {\n    let (mut wallet, _) = get_funded_wallet(get_test_single_sig_csv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .enable_rbf_with_sequence(Sequence(3));\n    assert!(matches!(builder.finish(),\n        Err(CreateTxError::RbfSequenceCsv { rbf, csv })\n        if rbf.to_consensus_u32() == 3 && csv.to_consensus_u32() == 6));\n}\n\n#[test]\nfn test_create_tx_no_rbf_cltv() {\n    let (mut wallet, _) = get_funded_wallet(get_test_single_sig_cltv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.input[0].sequence, Sequence(0xFFFFFFFE));\n}\n\n#[test]\nfn test_create_tx_invalid_rbf_sequence() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .enable_rbf_with_sequence(Sequence(0xFFFFFFFE));\n    assert!(matches!(builder.finish(), Err(CreateTxError::RbfSequence)));\n}\n\n#[test]\nfn test_create_tx_custom_rbf_sequence() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .enable_rbf_with_sequence(Sequence(0xDEADBEEF));\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.input[0].sequence, Sequence(0xDEADBEEF));\n}\n\n#[test]\nfn test_create_tx_change_policy() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .do_not_spend_change();\n    assert!(builder.finish().is_ok());\n\n    // wallet has no change, so setting `only_spend_change`\n    // should cause tx building to fail\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .only_spend_change();\n    assert!(matches!(\n        builder.finish(),\n        Err(CreateTxError::CoinSelection(\n            coin_selection::Error::InsufficientFunds { .. }\n        )),\n    ));\n}\n\n#[test]\nfn test_create_tx_default_sequence() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.input[0].sequence, Sequence(0xFFFFFFFE));\n}\n\nmacro_rules! check_fee {\n    ($wallet:expr, $psbt: expr) => {{\n        let tx = $psbt.clone().extract_tx().expect("failed to extract tx");\n        let tx_fee = $wallet.calculate_fee(&tx).ok();\n        assert_eq!(tx_fee, $psbt.fee_amount());\n        tx_fee\n    }};\n}\n\n#[test]\nfn test_create_tx_drain_wallet_and_drain_to() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(psbt.unsigned_tx.output.len(), 1);\n    assert_eq!(\n        psbt.unsigned_tx.output[0].value,\n        Amount::from_sat(50_000) - fee.unwrap_or(Amount::ZERO)\n    );\n}\n\n#[test]\nfn test_create_tx_drain_wallet_and_drain_to_and_with_recipient() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = Address::from_str("2N4eQYCbKUHCCTUjBJeHcJp9ok6J2GZsTDt")\n        .unwrap()\n        .assume_checked();\n    let drain_addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(20_000))\n        .drain_to(drain_addr.script_pubkey())\n        .drain_wallet();\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n    let outputs = psbt.unsigned_tx.output;\n\n    assert_eq!(outputs.len(), 2);\n    let main_output = outputs\n        .iter()\n        .find(|x| x.script_pubkey == addr.script_pubkey())\n        .unwrap();\n    let drain_output = outputs\n        .iter()\n        .find(|x| x.script_pubkey == drain_addr.script_pubkey())\n        .unwrap();\n    assert_eq!(main_output.value, Amount::from_sat(20_000));\n    assert_eq!(\n        drain_output.value,\n        Amount::from_sat(30_000) - fee.unwrap_or(Amount::ZERO)\n    );\n}\n\n#[test]\nfn test_create_tx_drain_to_and_utxos() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let utxos: Vec<_> = wallet.list_unspent().map(|u| u.outpoint).collect();\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .add_utxos(&utxos)\n        .unwrap();\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(psbt.unsigned_tx.output.len(), 1);\n    assert_eq!(\n        psbt.unsigned_tx.output[0].value,\n        Amount::from_sat(50_000) - fee.unwrap_or(Amount::ZERO)\n    );\n}\n\n#[test]\n#[should_panic(expected = "NoRecipients")]\nfn test_create_tx_drain_to_no_drain_wallet_no_utxos() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let drain_addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(drain_addr.script_pubkey());\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_create_tx_default_fee_rate() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), FeeRate::BROADCAST_MIN, @add_signature);\n}\n\n#[test]\nfn test_create_tx_custom_fee_rate() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .fee_rate(FeeRate::from_sat_per_vb_unchecked(5));\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), FeeRate::from_sat_per_vb_unchecked(5), @add_signature);\n}\n\n#[test]\nfn test_create_tx_absolute_fee() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .drain_wallet()\n        .fee_absolute(Amount::from_sat(100));\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(fee.unwrap_or(Amount::ZERO), Amount::from_sat(100));\n    assert_eq!(psbt.unsigned_tx.output.len(), 1);\n    assert_eq!(\n        psbt.unsigned_tx.output[0].value,\n        Amount::from_sat(50_000) - fee.unwrap_or(Amount::ZERO)\n    );\n}\n\n#[test]\nfn test_create_tx_absolute_zero_fee() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .drain_wallet()\n        .fee_absolute(Amount::ZERO);\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(fee.unwrap_or(Amount::ZERO), Amount::ZERO);\n    assert_eq!(psbt.unsigned_tx.output.len(), 1);\n    assert_eq!(\n        psbt.unsigned_tx.output[0].value,\n        Amount::from_sat(50_000) - fee.unwrap_or(Amount::ZERO)\n    );\n}\n\n#[test]\n#[should_panic(expected = "InsufficientFunds")]\nfn test_create_tx_absolute_high_fee() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .drain_wallet()\n        .fee_absolute(Amount::from_sat(60_000));\n    let _ = builder.finish().unwrap();\n}\n\n#[test]\nfn test_create_tx_add_change() {\n    use bdk_wallet::wallet::tx_builder::TxOrdering;\n    let seed = [0; 32];\n    let mut rng: StdRng = SeedableRng::from_seed(seed);\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .ordering(TxOrdering::Shuffle);\n    let psbt = builder.finish_with_aux_rand(&mut rng).unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(psbt.unsigned_tx.output.len(), 2);\n    assert_eq!(psbt.unsigned_tx.output[0].value, Amount::from_sat(25_000));\n    assert_eq!(\n        psbt.unsigned_tx.output[1].value,\n        Amount::from_sat(25_000) - fee.unwrap_or(Amount::ZERO)\n    );\n}\n\n#[test]\nfn test_create_tx_skip_change_dust() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(49_800));\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(psbt.unsigned_tx.output.len(), 1);\n    assert_eq!(psbt.unsigned_tx.output[0].value.to_sat(), 49_800);\n    assert_eq!(fee.unwrap_or(Amount::ZERO), Amount::from_sat(200));\n}\n\n#[test]\n#[should_panic(expected = "InsufficientFunds")]\nfn test_create_tx_drain_to_dust_amount() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    // very high fee rate, so that the only output would be below dust\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .drain_wallet()\n        .fee_rate(FeeRate::from_sat_per_vb_unchecked(454));\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_create_tx_ordering_respected() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(30_000))\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(10_000))\n        .ordering(bdk_wallet::wallet::tx_builder::TxOrdering::Bip69Lexicographic);\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(psbt.unsigned_tx.output.len(), 3);\n    assert_eq!(\n        psbt.unsigned_tx.output[0].value,\n        Amount::from_sat(10_000) - fee.unwrap_or(Amount::ZERO)\n    );\n    assert_eq!(psbt.unsigned_tx.output[1].value, Amount::from_sat(10_000));\n    assert_eq!(psbt.unsigned_tx.output[2].value, Amount::from_sat(30_000));\n}\n\n#[test]\nfn test_create_tx_default_sighash() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(30_000));\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.inputs[0].sighash_type, None);\n}\n\n#[test]\nfn test_create_tx_custom_sighash() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(30_000))\n        .sighash(EcdsaSighashType::Single.into());\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(\n        psbt.inputs[0].sighash_type,\n        Some(EcdsaSighashType::Single.into())\n    );\n}\n\n#[test]\nfn test_create_tx_input_hd_keypaths() {\n    use bitcoin::bip32::{DerivationPath, Fingerprint};\n    use core::str::FromStr;\n\n    let (mut wallet, _) = get_funded_wallet("wpkh([d34db33f/44\'/0\'/0\']tpubDEnoLuPdBep9bzw5LoGYpsxUQYheRQ9gcgrJhJEcdKFB9cWQRyYmkCyRoTqeD4tJYiVVgt6A3rN6rWn9RYhR9sBsGxji29LYWHuKKbdb1ev/0/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.inputs[0].bip32_derivation.len(), 1);\n    assert_eq!(\n        psbt.inputs[0].bip32_derivation.values().next().unwrap(),\n        &(\n            Fingerprint::from_str("d34db33f").unwrap(),\n            DerivationPath::from_str("m/44\'/0\'/0\'/0/0").unwrap()\n        )\n    );\n}\n\n#[test]\nfn test_create_tx_output_hd_keypaths() {\n    use bitcoin::bip32::{DerivationPath, Fingerprint};\n    use core::str::FromStr;\n\n    let (mut wallet, _) = get_funded_wallet("wpkh([d34db33f/44\'/0\'/0\']tpubDEnoLuPdBep9bzw5LoGYpsxUQYheRQ9gcgrJhJEcdKFB9cWQRyYmkCyRoTqeD4tJYiVVgt6A3rN6rWn9RYhR9sBsGxji29LYWHuKKbdb1ev/0/*)");\n\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.outputs[0].bip32_derivation.len(), 1);\n    let expected_derivation_path = format!("m/44\'/0\'/0\'/0/{}", addr.index);\n    assert_eq!(\n        psbt.outputs[0].bip32_derivation.values().next().unwrap(),\n        &(\n            Fingerprint::from_str("d34db33f").unwrap(),\n            DerivationPath::from_str(&expected_derivation_path).unwrap()\n        )\n    );\n}\n\n#[test]\nfn test_create_tx_set_redeem_script_p2sh() {\n    use bitcoin::hex::FromHex;\n\n    let (mut wallet, _) =\n        get_funded_wallet("sh(pk(cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW))");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(\n        psbt.inputs[0].redeem_script,\n        Some(ScriptBuf::from(\n            Vec::<u8>::from_hex(\n                "21032b0558078bec38694a84933d659303e2575dae7e91685911454115bfd64487e3ac"\n            )\n            .unwrap()\n        ))\n    );\n    assert_eq!(psbt.inputs[0].witness_script, None);\n}\n\n#[test]\nfn test_create_tx_set_witness_script_p2wsh() {\n    use bitcoin::hex::FromHex;\n\n    let (mut wallet, _) =\n        get_funded_wallet("wsh(pk(cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW))");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.inputs[0].redeem_script, None);\n    assert_eq!(\n        psbt.inputs[0].witness_script,\n        Some(ScriptBuf::from(\n            Vec::<u8>::from_hex(\n                "21032b0558078bec38694a84933d659303e2575dae7e91685911454115bfd64487e3ac"\n            )\n            .unwrap()\n        ))\n    );\n}\n\n#[test]\nfn test_create_tx_set_redeem_witness_script_p2wsh_p2sh() {\n    let (mut wallet, _) =\n        get_funded_wallet("sh(wsh(pk(cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW)))");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    let script = ScriptBuf::from_hex(\n        "21032b0558078bec38694a84933d659303e2575dae7e91685911454115bfd64487e3ac",\n    )\n    .unwrap();\n\n    assert_eq!(psbt.inputs[0].redeem_script, Some(script.to_p2wsh()));\n    assert_eq!(psbt.inputs[0].witness_script, Some(script));\n}\n\n#[test]\nfn test_create_tx_non_witness_utxo() {\n    let (mut wallet, _) =\n        get_funded_wallet("sh(pk(cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW))");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert!(psbt.inputs[0].non_witness_utxo.is_some());\n    assert!(psbt.inputs[0].witness_utxo.is_none());\n}\n\n#[test]\nfn test_create_tx_only_witness_utxo() {\n    let (mut wallet, _) =\n        get_funded_wallet("wsh(pk(cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW))");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .only_witness_utxo()\n        .drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert!(psbt.inputs[0].non_witness_utxo.is_none());\n    assert!(psbt.inputs[0].witness_utxo.is_some());\n}\n\n#[test]\nfn test_create_tx_shwpkh_has_witness_utxo() {\n    let (mut wallet, _) =\n        get_funded_wallet("sh(wpkh(cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW))");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert!(psbt.inputs[0].witness_utxo.is_some());\n}\n\n#[test]\nfn test_create_tx_both_non_witness_utxo_and_witness_utxo_default() {\n    let (mut wallet, _) =\n        get_funded_wallet("wsh(pk(cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW))");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert!(psbt.inputs[0].non_witness_utxo.is_some());\n    assert!(psbt.inputs[0].witness_utxo.is_some());\n}\n\n#[test]\nfn test_create_tx_add_utxo() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let small_output_tx = Transaction {\n        input: vec![],\n        output: vec![TxOut {\n            script_pubkey: wallet\n                .next_unused_address(KeychainKind::External)\n                .script_pubkey(),\n            value: Amount::from_sat(25_000),\n        }],\n        version: transaction::Version::non_standard(0),\n        lock_time: absolute::LockTime::ZERO,\n    };\n    wallet\n        .insert_tx(\n            small_output_tx.clone(),\n            ConfirmationTime::Unconfirmed { last_seen: 0 },\n        )\n        .unwrap();\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(30_000))\n        .add_utxo(OutPoint {\n            txid: small_output_tx.compute_txid(),\n            vout: 0,\n        })\n        .unwrap();\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n\n    assert_eq!(\n        psbt.unsigned_tx.input.len(),\n        2,\n        "should add an additional input since 25_000 < 30_000"\n    );\n    assert_eq!(\n        sent_received.0,\n        Amount::from_sat(75_000),\n        "total should be sum of both inputs"\n    );\n}\n\n#[test]\n#[should_panic(expected = "InsufficientFunds")]\nfn test_create_tx_manually_selected_insufficient() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let small_output_tx = Transaction {\n        input: vec![],\n        output: vec![TxOut {\n            script_pubkey: wallet\n                .next_unused_address(KeychainKind::External)\n                .script_pubkey(),\n            value: Amount::from_sat(25_000),\n        }],\n        version: transaction::Version::non_standard(0),\n        lock_time: absolute::LockTime::ZERO,\n    };\n\n    wallet\n        .insert_tx(\n            small_output_tx.clone(),\n            ConfirmationTime::Unconfirmed { last_seen: 0 },\n        )\n        .unwrap();\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(30_000))\n        .add_utxo(OutPoint {\n            txid: small_output_tx.compute_txid(),\n            vout: 0,\n        })\n        .unwrap()\n        .manually_selected_only();\n    builder.finish().unwrap();\n}\n\n#[test]\n#[should_panic(expected = "SpendingPolicyRequired(External)")]\nfn test_create_tx_policy_path_required() {\n    let (mut wallet, _) = get_funded_wallet(get_test_a_or_b_plus_csv());\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(10_000));\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_create_tx_policy_path_no_csv() {\n    let (desc, change_desc) = get_test_wpkh_with_change_desc();\n    let mut wallet = Wallet::new(desc, change_desc, Network::Regtest).expect("wallet");\n\n    let tx = Transaction {\n        version: transaction::Version::non_standard(0),\n        lock_time: absolute::LockTime::ZERO,\n        input: vec![],\n        output: vec![TxOut {\n            script_pubkey: wallet\n                .next_unused_address(KeychainKind::External)\n                .script_pubkey(),\n            value: Amount::from_sat(50_000),\n        }],\n    };\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let external_policy = wallet.policies(KeychainKind::External).unwrap().unwrap();\n    let root_id = external_policy.id;\n    // child #0 is just the key "A"\n    let path = vec![(root_id, vec![0])].into_iter().collect();\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(30_000))\n        .policy_path(path, KeychainKind::External);\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.input[0].sequence, Sequence(0xFFFFFFFF));\n}\n\n#[test]\nfn test_create_tx_policy_path_use_csv() {\n    let (mut wallet, _) = get_funded_wallet(get_test_a_or_b_plus_csv());\n\n    let external_policy = wallet.policies(KeychainKind::External).unwrap().unwrap();\n    let root_id = external_policy.id;\n    // child #1 is or(pk(B),older(144))\n    let path = vec![(root_id, vec![1])].into_iter().collect();\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(30_000))\n        .policy_path(path, KeychainKind::External);\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.input[0].sequence, Sequence(144));\n}\n\n#[test]\nfn test_create_tx_policy_path_ignored_subtree_with_csv() {\n    let (mut wallet, _) = get_funded_wallet("wsh(or_d(pk(cRjo6jqfVNP33HhSS76UhXETZsGTZYx8FMFvR9kpbtCSV1PmdZdu),or_i(and_v(v:pkh(cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW),older(30)),and_v(v:pkh(cMnkdebixpXMPfkcNEjjGin7s94hiehAH4mLbYkZoh9KSiNNmqC8),older(90)))))");\n\n    let external_policy = wallet.policies(KeychainKind::External).unwrap().unwrap();\n    let root_id = external_policy.id;\n    // child #0 is pk(cRjo6jqfVNP33HhSS76UhXETZsGTZYx8FMFvR9kpbtCSV1PmdZdu)\n    let path = vec![(root_id, vec![0])].into_iter().collect();\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(30_000))\n        .policy_path(path, KeychainKind::External);\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(psbt.unsigned_tx.input[0].sequence, Sequence(0xFFFFFFFE));\n}\n\n#[test]\nfn test_create_tx_global_xpubs_with_origin() {\n    use bitcoin::bip32;\n    let (mut wallet, _) = get_funded_wallet("wpkh([73756c7f/48\'/0\'/0\'/2\']tpubDCKxNyM3bLgbEX13Mcd8mYxbVg9ajDkWXMh29hMWBurKfVmBfWAM96QVP3zaUcN51HvkZ3ar4VwP82kC8JZhhux8vFQoJintSpVBwpFvyU3/0/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .add_global_xpubs();\n    let psbt = builder.finish().unwrap();\n\n    let key = bip32::Xpub::from_str("tpubDCKxNyM3bLgbEX13Mcd8mYxbVg9ajDkWXMh29hMWBurKfVmBfWAM96QVP3zaUcN51HvkZ3ar4VwP82kC8JZhhux8vFQoJintSpVBwpFvyU3").unwrap();\n    let fingerprint = bip32::Fingerprint::from_hex("73756c7f").unwrap();\n    let path = bip32::DerivationPath::from_str("m/48\'/0\'/0\'/2\'").unwrap();\n\n    assert_eq!(psbt.xpub.len(), 2);\n    assert_eq!(psbt.xpub.get(&key), Some(&(fingerprint, path)));\n}\n\n#[test]\nfn test_add_foreign_utxo() {\n    let (mut wallet1, _) = get_funded_wallet_wpkh();\n    let (wallet2, _) =\n        get_funded_wallet("wpkh(cVbZ8ovhye9AoAHFsqobCf7LxbXDAECy9Kb8TZdfsDYMZGBUyCnm)");\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let utxo = wallet2.list_unspent().next().expect("must take!");\n    let foreign_utxo_satisfaction = wallet2\n        .get_descriptor_for_keychain(KeychainKind::External)\n        .max_weight_to_satisfy()\n        .unwrap();\n\n    let psbt_input = psbt::Input {\n        witness_utxo: Some(utxo.txout.clone()),\n        ..Default::default()\n    };\n\n    let mut builder = wallet1.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(60_000))\n        .only_witness_utxo()\n        .add_foreign_utxo(utxo.outpoint, psbt_input, foreign_utxo_satisfaction)\n        .unwrap();\n    let mut psbt = builder.finish().unwrap();\n    wallet1.insert_txout(utxo.outpoint, utxo.txout);\n    let fee = check_fee!(wallet1, psbt);\n    let sent_received =\n        wallet1.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n\n    assert_eq!(\n        (sent_received.0 - sent_received.1),\n        Amount::from_sat(10_000) + fee.unwrap_or(Amount::ZERO),\n        "we should have only net spent ~10_000"\n    );\n\n    assert!(\n        psbt.unsigned_tx\n            .input\n            .iter()\n            .any(|input| input.previous_output == utxo.outpoint),\n        "foreign_utxo should be in there"\n    );\n\n    let finished = wallet1\n        .sign(\n            &mut psbt,\n            SignOptions {\n                trust_witness_utxo: true,\n                ..Default::default()\n            },\n        )\n        .unwrap();\n\n    assert!(\n        !finished,\n        "only one of the inputs should have been signed so far"\n    );\n\n    let finished = wallet2\n        .sign(\n            &mut psbt,\n            SignOptions {\n                trust_witness_utxo: true,\n                ..Default::default()\n            },\n        )\n        .unwrap();\n    assert!(finished, "all the inputs should have been signed now");\n}\n\n#[test]\n#[should_panic(\n    expected = "MissingTxOut([OutPoint { txid: 21d7fb1bceda00ab4069fc52d06baa13470803e9050edd16f5736e5d8c4925fd, vout: 0 }])"\n)]\nfn test_calculate_fee_with_missing_foreign_utxo() {\n    let (mut wallet1, _) = get_funded_wallet_wpkh();\n    let (wallet2, _) =\n        get_funded_wallet("wpkh(cVbZ8ovhye9AoAHFsqobCf7LxbXDAECy9Kb8TZdfsDYMZGBUyCnm)");\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let utxo = wallet2.list_unspent().next().expect("must take!");\n    let foreign_utxo_satisfaction = wallet2\n        .get_descriptor_for_keychain(KeychainKind::External)\n        .max_weight_to_satisfy()\n        .unwrap();\n\n    let psbt_input = psbt::Input {\n        witness_utxo: Some(utxo.txout.clone()),\n        ..Default::default()\n    };\n\n    let mut builder = wallet1.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(60_000))\n        .only_witness_utxo()\n        .add_foreign_utxo(utxo.outpoint, psbt_input, foreign_utxo_satisfaction)\n        .unwrap();\n    let psbt = builder.finish().unwrap();\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    wallet1.calculate_fee(&tx).unwrap();\n}\n\n#[test]\nfn test_add_foreign_utxo_invalid_psbt_input() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let outpoint = wallet.list_unspent().next().expect("must exist").outpoint;\n    let foreign_utxo_satisfaction = wallet\n        .get_descriptor_for_keychain(KeychainKind::External)\n        .max_weight_to_satisfy()\n        .unwrap();\n\n    let mut builder = wallet.build_tx();\n    let result =\n        builder.add_foreign_utxo(outpoint, psbt::Input::default(), foreign_utxo_satisfaction);\n    assert!(matches!(result, Err(AddForeignUtxoError::MissingUtxo)));\n}\n\n#[test]\nfn test_add_foreign_utxo_where_outpoint_doesnt_match_psbt_input() {\n    let (mut wallet1, txid1) = get_funded_wallet_wpkh();\n    let (wallet2, txid2) =\n        get_funded_wallet("wpkh(cVbZ8ovhye9AoAHFsqobCf7LxbXDAECy9Kb8TZdfsDYMZGBUyCnm)");\n\n    let utxo2 = wallet2.list_unspent().next().unwrap();\n    let tx1 = wallet1.get_tx(txid1).unwrap().tx_node.tx.clone();\n    let tx2 = wallet2.get_tx(txid2).unwrap().tx_node.tx.clone();\n\n    let satisfaction_weight = wallet2\n        .get_descriptor_for_keychain(KeychainKind::External)\n        .max_weight_to_satisfy()\n        .unwrap();\n\n    let mut builder = wallet1.build_tx();\n    assert!(\n        builder\n            .add_foreign_utxo(\n                utxo2.outpoint,\n                psbt::Input {\n                    non_witness_utxo: Some(tx1.as_ref().clone()),\n                    ..Default::default()\n                },\n                satisfaction_weight\n            )\n            .is_err(),\n        "should fail when outpoint doesn\'t match psbt_input"\n    );\n    assert!(\n        builder\n            .add_foreign_utxo(\n                utxo2.outpoint,\n                psbt::Input {\n                    non_witness_utxo: Some(tx2.as_ref().clone()),\n                    ..Default::default()\n                },\n                satisfaction_weight\n            )\n            .is_ok(),\n        "should be ok when outpoint does match psbt_input"\n    );\n}\n\n#[test]\nfn test_add_foreign_utxo_only_witness_utxo() {\n    let (mut wallet1, _) = get_funded_wallet_wpkh();\n    let (wallet2, txid2) =\n        get_funded_wallet("wpkh(cVbZ8ovhye9AoAHFsqobCf7LxbXDAECy9Kb8TZdfsDYMZGBUyCnm)");\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let utxo2 = wallet2.list_unspent().next().unwrap();\n\n    let satisfaction_weight = wallet2\n        .get_descriptor_for_keychain(KeychainKind::External)\n        .max_weight_to_satisfy()\n        .unwrap();\n\n    let mut builder = wallet1.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(60_000));\n\n    {\n        let mut builder = builder.clone();\n        let psbt_input = psbt::Input {\n            witness_utxo: Some(utxo2.txout.clone()),\n            ..Default::default()\n        };\n        builder\n            .add_foreign_utxo(utxo2.outpoint, psbt_input, satisfaction_weight)\n            .unwrap();\n        assert!(\n            builder.finish().is_err(),\n            "psbt_input with witness_utxo should fail with only witness_utxo"\n        );\n    }\n\n    {\n        let mut builder = builder.clone();\n        let psbt_input = psbt::Input {\n            witness_utxo: Some(utxo2.txout.clone()),\n            ..Default::default()\n        };\n        builder\n            .only_witness_utxo()\n            .add_foreign_utxo(utxo2.outpoint, psbt_input, satisfaction_weight)\n            .unwrap();\n        assert!(\n            builder.finish().is_ok(),\n            "psbt_input with just witness_utxo should succeed when `only_witness_utxo` is enabled"\n        );\n    }\n\n    {\n        let mut builder = builder.clone();\n        let tx2 = wallet2.get_tx(txid2).unwrap().tx_node.tx;\n        let psbt_input = psbt::Input {\n            non_witness_utxo: Some(tx2.as_ref().clone()),\n            ..Default::default()\n        };\n        builder\n            .add_foreign_utxo(utxo2.outpoint, psbt_input, satisfaction_weight)\n            .unwrap();\n        assert!(\n            builder.finish().is_ok(),\n            "psbt_input with non_witness_utxo should succeed by default"\n        );\n    }\n}\n\n#[test]\nfn test_get_psbt_input() {\n    // this should grab a known good utxo and set the input\n    let (wallet, _) = get_funded_wallet_wpkh();\n    for utxo in wallet.list_unspent() {\n        let psbt_input = wallet.get_psbt_input(utxo, None, false).unwrap();\n        assert!(psbt_input.witness_utxo.is_some() || psbt_input.non_witness_utxo.is_some());\n    }\n}\n\n#[test]\n#[should_panic(\n    expected = "MissingKeyOrigin(\\"tpubDCKxNyM3bLgbEX13Mcd8mYxbVg9ajDkWXMh29hMWBurKfVmBfWAM96QVP3zaUcN51HvkZ3ar4VwP82kC8JZhhux8vFQoJintSpVBwpFvyU3\\")"\n)]\nfn test_create_tx_global_xpubs_origin_missing() {\n    let (mut wallet, _) = get_funded_wallet("wpkh(tpubDCKxNyM3bLgbEX13Mcd8mYxbVg9ajDkWXMh29hMWBurKfVmBfWAM96QVP3zaUcN51HvkZ3ar4VwP82kC8JZhhux8vFQoJintSpVBwpFvyU3/0/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .add_global_xpubs();\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_create_tx_global_xpubs_master_without_origin() {\n    use bitcoin::bip32;\n    let (mut wallet, _) = get_funded_wallet("wpkh(tpubD6NzVbkrYhZ4Y55A58Gv9RSNF5hy84b5AJqYy7sCcjFrkcLpPre8kmgfit6kY1Zs3BLgeypTDBZJM222guPpdz7Cup5yzaMu62u7mYGbwFL/0/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .add_global_xpubs();\n    let psbt = builder.finish().unwrap();\n\n    let key = bip32::Xpub::from_str("tpubD6NzVbkrYhZ4Y55A58Gv9RSNF5hy84b5AJqYy7sCcjFrkcLpPre8kmgfit6kY1Zs3BLgeypTDBZJM222guPpdz7Cup5yzaMu62u7mYGbwFL").unwrap();\n    let fingerprint = bip32::Fingerprint::from_hex("997a323b").unwrap();\n\n    assert_eq!(psbt.xpub.len(), 2);\n    assert_eq!(\n        psbt.xpub.get(&key),\n        Some(&(fingerprint, bip32::DerivationPath::default()))\n    );\n}\n\n#[test]\n#[should_panic(expected = "IrreplaceableTransaction")]\nfn test_bump_fee_irreplaceable_tx() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let psbt = builder.finish().unwrap();\n\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n    wallet.build_fee_bump(txid).unwrap().finish().unwrap();\n}\n\n#[test]\n#[should_panic(expected = "TransactionConfirmed")]\nfn test_bump_fee_confirmed_tx() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let psbt = builder.finish().unwrap();\n\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let txid = tx.compute_txid();\n\n    wallet\n        .insert_tx(\n            tx,\n            ConfirmationTime::Confirmed {\n                height: 42,\n                time: 42_000,\n            },\n        )\n        .unwrap();\n\n    wallet.build_fee_bump(txid).unwrap().finish().unwrap();\n}\n\n#[test]\nfn test_bump_fee_low_fee_rate() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let feerate = psbt.fee_rate().unwrap();\n\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let txid = tx.compute_txid();\n\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder.fee_rate(FeeRate::BROADCAST_MIN);\n    let res = builder.finish();\n    assert_matches!(\n        res,\n        Err(CreateTxError::FeeRateTooLow { .. }),\n        "expected FeeRateTooLow error"\n    );\n\n    let required = feerate.to_sat_per_kwu() + 250; // +1 sat/vb\n    let sat_vb = required as f64 / 250.0;\n    let expect = format!("Fee rate too low: required {} sat/vb", sat_vb);\n    assert_eq!(res.unwrap_err().to_string(), expect);\n}\n\n#[test]\n#[should_panic(expected = "FeeTooLow")]\nfn test_bump_fee_low_abs() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let txid = tx.compute_txid();\n\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder.fee_absolute(Amount::from_sat(10));\n    builder.finish().unwrap();\n}\n\n#[test]\n#[should_panic(expected = "FeeTooLow")]\nfn test_bump_fee_zero_abs() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder.fee_absolute(Amount::ZERO);\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_bump_fee_reduce_change() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(25_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let original_sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let original_fee = check_fee!(wallet, psbt);\n\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let feerate = FeeRate::from_sat_per_kwu(625); // 2.5 sat/vb\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder.fee_rate(feerate).enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(sent_received.0, original_sent_received.0);\n    assert_eq!(\n        sent_received.1 + fee.unwrap_or(Amount::ZERO),\n        original_sent_received.1 + original_fee.unwrap_or(Amount::ZERO)\n    );\n    assert!(fee.unwrap_or(Amount::ZERO) > original_fee.unwrap_or(Amount::ZERO));\n\n    let tx = &psbt.unsigned_tx;\n    assert_eq!(tx.output.len(), 2);\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey == addr.script_pubkey())\n            .unwrap()\n            .value,\n        Amount::from_sat(25_000)\n    );\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey != addr.script_pubkey())\n            .unwrap()\n            .value,\n        sent_received.1\n    );\n\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), feerate, @add_signature);\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder.fee_absolute(Amount::from_sat(200));\n    builder.enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(sent_received.0, original_sent_received.0);\n    assert_eq!(\n        sent_received.1 + fee.unwrap_or(Amount::ZERO),\n        original_sent_received.1 + original_fee.unwrap_or(Amount::ZERO)\n    );\n    assert!(\n        fee.unwrap_or(Amount::ZERO) > original_fee.unwrap_or(Amount::ZERO),\n        "{} > {}",\n        fee.unwrap_or(Amount::ZERO),\n        original_fee.unwrap_or(Amount::ZERO)\n    );\n\n    let tx = &psbt.unsigned_tx;\n    assert_eq!(tx.output.len(), 2);\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey == addr.script_pubkey())\n            .unwrap()\n            .value,\n        Amount::from_sat(25_000)\n    );\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey != addr.script_pubkey())\n            .unwrap()\n            .value,\n        sent_received.1\n    );\n\n    assert_eq!(fee.unwrap_or(Amount::ZERO), Amount::from_sat(200));\n}\n\n#[test]\nfn test_bump_fee_reduce_single_recipient() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .drain_wallet()\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let tx = psbt.clone().extract_tx().expect("failed to extract tx");\n    let original_sent_received = wallet.sent_and_received(&tx);\n    let original_fee = check_fee!(wallet, psbt);\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let feerate = FeeRate::from_sat_per_kwu(625); // 2.5 sat/vb\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder\n        .fee_rate(feerate)\n        // remove original tx drain_to address and amount\n        .set_recipients(Vec::new())\n        // set back original drain_to address\n        .drain_to(addr.script_pubkey())\n        // drain wallet output amount will be re-calculated with new fee rate\n        .drain_wallet();\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(sent_received.0, original_sent_received.0);\n    assert!(fee.unwrap_or(Amount::ZERO) > original_fee.unwrap_or(Amount::ZERO));\n\n    let tx = &psbt.unsigned_tx;\n    assert_eq!(tx.output.len(), 1);\n    assert_eq!(\n        tx.output[0].value + fee.unwrap_or(Amount::ZERO),\n        sent_received.0\n    );\n\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), feerate, @add_signature);\n}\n\n#[test]\nfn test_bump_fee_absolute_reduce_single_recipient() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .drain_wallet()\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let original_fee = check_fee!(wallet, psbt);\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let original_sent_received = wallet.sent_and_received(&tx);\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder\n        .fee_absolute(Amount::from_sat(300))\n        // remove original tx drain_to address and amount\n        .set_recipients(Vec::new())\n        // set back original drain_to address\n        .drain_to(addr.script_pubkey())\n        // drain wallet output amount will be re-calculated with new fee rate\n        .drain_wallet();\n    let psbt = builder.finish().unwrap();\n    let tx = &psbt.unsigned_tx;\n    let sent_received = wallet.sent_and_received(tx);\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(sent_received.0, original_sent_received.0);\n    assert!(fee.unwrap_or(Amount::ZERO) > original_fee.unwrap_or(Amount::ZERO));\n\n    assert_eq!(tx.output.len(), 1);\n    assert_eq!(\n        tx.output[0].value + fee.unwrap_or(Amount::ZERO),\n        sent_received.0\n    );\n\n    assert_eq!(fee.unwrap_or(Amount::ZERO), Amount::from_sat(300));\n}\n\n#[test]\nfn test_bump_fee_drain_wallet() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    // receive an extra tx so that our wallet has two utxos.\n    let tx = Transaction {\n        version: transaction::Version::ONE,\n        lock_time: absolute::LockTime::ZERO,\n        input: vec![],\n        output: vec![TxOut {\n            script_pubkey: wallet\n                .next_unused_address(KeychainKind::External)\n                .script_pubkey(),\n            value: Amount::from_sat(25_000),\n        }],\n    };\n    wallet\n        .insert_tx(\n            tx.clone(),\n            ConfirmationTime::Confirmed {\n                height: wallet.latest_checkpoint().height(),\n                time: 42_000,\n            },\n        )\n        .unwrap();\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .add_utxo(OutPoint {\n            txid: tx.compute_txid(),\n            vout: 0,\n        })\n        .unwrap()\n        .manually_selected_only()\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let original_sent_received = wallet.sent_and_received(&tx);\n\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n    assert_eq!(original_sent_received.0, Amount::from_sat(25_000));\n\n    // for the new feerate, it should be enough to reduce the output, but since we specify\n    // `drain_wallet` we expect to spend everything\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder\n        .drain_wallet()\n        .fee_rate(FeeRate::from_sat_per_vb_unchecked(5));\n    let psbt = builder.finish().unwrap();\n    let sent_received = wallet.sent_and_received(&psbt.extract_tx().expect("failed to extract tx"));\n\n    assert_eq!(sent_received.0, Amount::from_sat(75_000));\n}\n\n#[test]\n#[should_panic(expected = "InsufficientFunds")]\nfn test_bump_fee_remove_output_manually_selected_only() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    // receive an extra tx so that our wallet has two utxos. then we manually pick only one of\n    // them, and make sure that `bump_fee` doesn\'t try to add more. This fails because we\'ve\n    // told the wallet it\'s not allowed to add more inputs AND it can\'t reduce the value of the\n    // existing output. In other words, bump_fee + manually_selected_only is always an error\n    // unless there is a change output.\n    let init_tx = Transaction {\n        version: transaction::Version::ONE,\n        lock_time: absolute::LockTime::ZERO,\n        input: vec![],\n        output: vec![TxOut {\n            script_pubkey: wallet\n                .next_unused_address(KeychainKind::External)\n                .script_pubkey(),\n            value: Amount::from_sat(25_000),\n        }],\n    };\n    wallet\n        .insert_tx(\n            init_tx.clone(),\n            wallet\n                .transactions()\n                .last()\n                .unwrap()\n                .chain_position\n                .cloned()\n                .into(),\n        )\n        .unwrap();\n    let outpoint = OutPoint {\n        txid: init_tx.compute_txid(),\n        vout: 0,\n    };\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .add_utxo(outpoint)\n        .unwrap()\n        .manually_selected_only()\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let original_sent_received = wallet.sent_and_received(&tx);\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n    assert_eq!(original_sent_received.0, Amount::from_sat(25_000));\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder\n        .manually_selected_only()\n        .fee_rate(FeeRate::from_sat_per_vb_unchecked(255));\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_bump_fee_add_input() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let init_tx = Transaction {\n        version: transaction::Version::ONE,\n        lock_time: absolute::LockTime::ZERO,\n        input: vec![],\n        output: vec![TxOut {\n            script_pubkey: wallet\n                .next_unused_address(KeychainKind::External)\n                .script_pubkey(),\n            value: Amount::from_sat(25_000),\n        }],\n    };\n    let pos = wallet\n        .transactions()\n        .last()\n        .unwrap()\n        .chain_position\n        .cloned()\n        .into();\n    wallet.insert_tx(init_tx, pos).unwrap();\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx().coin_selection(LargestFirstCoinSelection);\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(45_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let original_details = wallet.sent_and_received(&tx);\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder.fee_rate(FeeRate::from_sat_per_vb_unchecked(50));\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let fee = check_fee!(wallet, psbt);\n    assert_eq!(\n        sent_received.0,\n        original_details.0 + Amount::from_sat(25_000)\n    );\n    assert_eq!(\n        fee.unwrap_or(Amount::ZERO) + sent_received.1,\n        Amount::from_sat(30_000)\n    );\n\n    let tx = &psbt.unsigned_tx;\n    assert_eq!(tx.input.len(), 2);\n    assert_eq!(tx.output.len(), 2);\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey == addr.script_pubkey())\n            .unwrap()\n            .value,\n        Amount::from_sat(45_000)\n    );\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey != addr.script_pubkey())\n            .unwrap()\n            .value,\n        sent_received.1\n    );\n\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), FeeRate::from_sat_per_vb_unchecked(50), @add_signature);\n}\n\n#[test]\nfn test_bump_fee_absolute_add_input() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    receive_output_in_latest_block(&mut wallet, 25_000);\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx().coin_selection(LargestFirstCoinSelection);\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(45_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let original_sent_received = wallet.sent_and_received(&tx);\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder.fee_absolute(Amount::from_sat(6_000));\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(\n        sent_received.0,\n        original_sent_received.0 + Amount::from_sat(25_000)\n    );\n    assert_eq!(\n        fee.unwrap_or(Amount::ZERO) + sent_received.1,\n        Amount::from_sat(30_000)\n    );\n\n    let tx = &psbt.unsigned_tx;\n    assert_eq!(tx.input.len(), 2);\n    assert_eq!(tx.output.len(), 2);\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey == addr.script_pubkey())\n            .unwrap()\n            .value,\n        Amount::from_sat(45_000)\n    );\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey != addr.script_pubkey())\n            .unwrap()\n            .value,\n        sent_received.1\n    );\n\n    assert_eq!(fee.unwrap_or(Amount::ZERO), Amount::from_sat(6_000));\n}\n\n#[test]\nfn test_bump_fee_no_change_add_input_and_change() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let op = receive_output_in_latest_block(&mut wallet, 25_000);\n\n    // initially make a tx without change by using `drain_to`\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .add_utxo(op)\n        .unwrap()\n        .manually_selected_only()\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let original_sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let original_fee = check_fee!(wallet, psbt);\n\n    let tx = psbt.extract_tx().expect("failed to extract tx");\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    // Now bump the fees, the wallet should add an extra input and a change output, and leave\n    // the original output untouched.\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder.fee_rate(FeeRate::from_sat_per_vb_unchecked(50));\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let fee = check_fee!(wallet, psbt);\n\n    let original_send_all_amount = original_sent_received.0 - original_fee.unwrap_or(Amount::ZERO);\n    assert_eq!(\n        sent_received.0,\n        original_sent_received.0 + Amount::from_sat(50_000)\n    );\n    assert_eq!(\n        sent_received.1,\n        Amount::from_sat(75_000) - original_send_all_amount - fee.unwrap_or(Amount::ZERO)\n    );\n\n    let tx = &psbt.unsigned_tx;\n    assert_eq!(tx.input.len(), 2);\n    assert_eq!(tx.output.len(), 2);\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey == addr.script_pubkey())\n            .unwrap()\n            .value,\n        original_send_all_amount\n    );\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey != addr.script_pubkey())\n            .unwrap()\n            .value,\n        Amount::from_sat(75_000) - original_send_all_amount - fee.unwrap_or(Amount::ZERO)\n    );\n\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), FeeRate::from_sat_per_vb_unchecked(50), @add_signature);\n}\n\n#[test]\nfn test_bump_fee_add_input_change_dust() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    receive_output_in_latest_block(&mut wallet, 25_000);\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx().coin_selection(LargestFirstCoinSelection);\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(45_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let original_sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let original_fee = check_fee!(wallet, psbt);\n\n    let mut tx = psbt.extract_tx().expect("failed to extract tx");\n    for txin in &mut tx.input {\n        txin.witness.push([0x00; P2WPKH_FAKE_WITNESS_SIZE]); // to get realistic weight\n    }\n    let original_tx_weight = tx.weight();\n    assert_eq!(tx.input.len(), 1);\n    assert_eq!(tx.output.len(), 2);\n    let txid = tx.compute_txid();\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    // We set a fee high enough that during rbf we are forced to add\n    // a new input and also that we have to remove the change\n    // that we had previously\n\n    // We calculate the new weight as:\n    //   original weight\n    // + extra input weight: 160 WU = (32 (prevout) + 4 (vout) + 4 (nsequence)) * 4\n    // + input satisfaction weight: 112 WU = 106 (witness) + 2 (witness len) + (1 (script len)) * 4\n    // - change output weight: 124 WU = (8 (value) + 1 (script len) + 22 (script)) * 4\n    let new_tx_weight =\n        original_tx_weight + Weight::from_wu(160) + Weight::from_wu(112) - Weight::from_wu(124);\n    // two inputs (50k, 25k) and one output (45k) - epsilon\n    // We use epsilon here to avoid asking for a slightly too high feerate\n    let fee_abs = 50_000 + 25_000 - 45_000 - 10;\n    builder.fee_rate(Amount::from_sat(fee_abs) / new_tx_weight);\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(\n        original_sent_received.1,\n        Amount::from_sat(5_000) - original_fee.unwrap_or(Amount::ZERO)\n    );\n\n    assert_eq!(\n        sent_received.0,\n        original_sent_received.0 + Amount::from_sat(25_000)\n    );\n    assert_eq!(fee.unwrap_or(Amount::ZERO), Amount::from_sat(30_000));\n    assert_eq!(sent_received.1, Amount::ZERO);\n\n    let tx = &psbt.unsigned_tx;\n    assert_eq!(tx.input.len(), 2);\n    assert_eq!(tx.output.len(), 1);\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey == addr.script_pubkey())\n            .unwrap()\n            .value,\n        Amount::from_sat(45_000)\n    );\n\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), FeeRate::from_sat_per_vb_unchecked(140), @dust_change, @add_signature);\n}\n\n#[test]\nfn test_bump_fee_force_add_input() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let incoming_op = receive_output_in_latest_block(&mut wallet, 25_000);\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx().coin_selection(LargestFirstCoinSelection);\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(45_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let mut tx = psbt.extract_tx().expect("failed to extract tx");\n    let original_sent_received = wallet.sent_and_received(&tx);\n    let txid = tx.compute_txid();\n    for txin in &mut tx.input {\n        txin.witness.push([0x00; P2WPKH_FAKE_WITNESS_SIZE]); // fake signature\n    }\n    wallet\n        .insert_tx(tx.clone(), ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n    // the new fee_rate is low enough that just reducing the change would be fine, but we force\n    // the addition of an extra input with `add_utxo()`\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder\n        .add_utxo(incoming_op)\n        .unwrap()\n        .fee_rate(FeeRate::from_sat_per_vb_unchecked(5));\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(\n        sent_received.0,\n        original_sent_received.0 + Amount::from_sat(25_000)\n    );\n    assert_eq!(\n        fee.unwrap_or(Amount::ZERO) + sent_received.1,\n        Amount::from_sat(30_000)\n    );\n\n    let tx = &psbt.unsigned_tx;\n    assert_eq!(tx.input.len(), 2);\n    assert_eq!(tx.output.len(), 2);\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey == addr.script_pubkey())\n            .unwrap()\n            .value,\n        Amount::from_sat(45_000)\n    );\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey != addr.script_pubkey())\n            .unwrap()\n            .value,\n        sent_received.1\n    );\n\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), FeeRate::from_sat_per_vb_unchecked(5), @add_signature);\n}\n\n#[test]\nfn test_bump_fee_absolute_force_add_input() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let incoming_op = receive_output_in_latest_block(&mut wallet, 25_000);\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx().coin_selection(LargestFirstCoinSelection);\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(45_000))\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let mut tx = psbt.extract_tx().expect("failed to extract tx");\n    let original_sent_received = wallet.sent_and_received(&tx);\n    let txid = tx.compute_txid();\n    // skip saving the new utxos, we know they can\'t be used anyways\n    for txin in &mut tx.input {\n        txin.witness.push([0x00; P2WPKH_FAKE_WITNESS_SIZE]); // fake signature\n    }\n    wallet\n        .insert_tx(tx.clone(), ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    // the new fee_rate is low enough that just reducing the change would be fine, but we force\n    // the addition of an extra input with `add_utxo()`\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder\n        .add_utxo(incoming_op)\n        .unwrap()\n        .fee_absolute(Amount::from_sat(250));\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(\n        sent_received.0,\n        original_sent_received.0 + Amount::from_sat(25_000)\n    );\n    assert_eq!(\n        fee.unwrap_or(Amount::ZERO) + sent_received.1,\n        Amount::from_sat(30_000)\n    );\n\n    let tx = &psbt.unsigned_tx;\n    assert_eq!(tx.input.len(), 2);\n    assert_eq!(tx.output.len(), 2);\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey == addr.script_pubkey())\n            .unwrap()\n            .value,\n        Amount::from_sat(45_000)\n    );\n    assert_eq!(\n        tx.output\n            .iter()\n            .find(|txout| txout.script_pubkey != addr.script_pubkey())\n            .unwrap()\n            .value,\n        sent_received.1\n    );\n\n    assert_eq!(fee.unwrap_or(Amount::ZERO), Amount::from_sat(250));\n}\n\n#[test]\n#[should_panic(expected = "InsufficientFunds")]\nfn test_bump_fee_unconfirmed_inputs_only() {\n    // We try to bump the fee, but:\n    // - We can\'t reduce the change, as we have no change\n    // - All our UTXOs are unconfirmed\n    // So, we fail with "InsufficientFunds", as per RBF rule 2:\n    // The replacement transaction may only include an unconfirmed input\n    // if that input was included in one of the original transactions.\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_wallet()\n        .drain_to(addr.script_pubkey())\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    // Now we receive one transaction with 0 confirmations. We won\'t be able to use that for\n    // fee bumping, as it\'s still unconfirmed!\n    receive_output(\n        &mut wallet,\n        25_000,\n        ConfirmationTime::Unconfirmed { last_seen: 0 },\n    );\n    let mut tx = psbt.extract_tx().expect("failed to extract tx");\n    let txid = tx.compute_txid();\n    for txin in &mut tx.input {\n        txin.witness.push([0x00; P2WPKH_FAKE_WITNESS_SIZE]); // fake signature\n    }\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder.fee_rate(FeeRate::from_sat_per_vb_unchecked(25));\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_bump_fee_unconfirmed_input() {\n    // We create a tx draining the wallet and spending one confirmed\n    // and one unconfirmed UTXO. We check that we can fee bump normally\n    // (BIP125 rule 2 only apply to newly added unconfirmed input, you can\n    // always fee bump with an unconfirmed input if it was included in the\n    // original transaction)\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    // We receive a tx with 0 confirmations, which will be used as an input\n    // in the drain tx.\n    receive_output(&mut wallet, 25_000, ConfirmationTime::unconfirmed(0));\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_wallet()\n        .drain_to(addr.script_pubkey())\n        .enable_rbf();\n    let psbt = builder.finish().unwrap();\n    let mut tx = psbt.extract_tx().expect("failed to extract tx");\n    let txid = tx.compute_txid();\n    for txin in &mut tx.input {\n        txin.witness.push([0x00; P2WPKH_FAKE_WITNESS_SIZE]); // fake signature\n    }\n    wallet\n        .insert_tx(tx, ConfirmationTime::Unconfirmed { last_seen: 0 })\n        .unwrap();\n\n    let mut builder = wallet.build_fee_bump(txid).unwrap();\n    builder\n        .fee_rate(FeeRate::from_sat_per_vb_unchecked(15))\n        // remove original tx drain_to address and amount\n        .set_recipients(Vec::new())\n        // set back original drain_to address\n        .drain_to(addr.script_pubkey())\n        // drain wallet output amount will be re-calculated with new fee rate\n        .drain_wallet();\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_fee_amount_negative_drain_val() {\n    // While building the transaction, bdk would calculate the drain_value\n    // as\n    // current_delta - fee_amount - drain_fee\n    // using saturating_sub, meaning that if the result would end up negative,\n    // it\'ll remain to zero instead.\n    // This caused a bug in master where we would calculate the wrong fee\n    // for a transaction.\n    // See https://github.com/bitcoindevkit/bdk/issues/660\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let send_to = Address::from_str("tb1ql7w62elx9ucw4pj5lgw4l028hmuw80sndtntxt")\n        .unwrap()\n        .assume_checked();\n    let fee_rate = FeeRate::from_sat_per_kwu(500);\n    let incoming_op = receive_output_in_latest_block(&mut wallet, 8859);\n\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(send_to.script_pubkey(), Amount::from_sat(8630))\n        .add_utxo(incoming_op)\n        .unwrap()\n        .enable_rbf()\n        .fee_rate(fee_rate);\n    let psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    assert_eq!(psbt.inputs.len(), 1);\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), fee_rate, @add_signature);\n}\n\n#[test]\nfn test_sign_single_xprv() {\n    let (mut wallet, _) = get_funded_wallet("wpkh(tprv8ZgxMBicQKsPd3EupYiPRhaMooHKUHJxNsTfYuScep13go8QFfHdtkG9nRkFGb7busX4isf6X9dURGCoKgitaApQ6MupRhZMcELAxTBRJgS/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    let finalized = wallet.sign(&mut psbt, Default::default()).unwrap();\n    assert!(finalized);\n\n    let extracted = psbt.extract_tx().expect("failed to extract tx");\n    assert_eq!(extracted.input[0].witness.len(), 2);\n}\n\n#[test]\nfn test_sign_single_xprv_with_master_fingerprint_and_path() {\n    let (mut wallet, _) = get_funded_wallet("wpkh([d34db33f/84h/1h/0h]tprv8ZgxMBicQKsPd3EupYiPRhaMooHKUHJxNsTfYuScep13go8QFfHdtkG9nRkFGb7busX4isf6X9dURGCoKgitaApQ6MupRhZMcELAxTBRJgS/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    let finalized = wallet.sign(&mut psbt, Default::default()).unwrap();\n    assert!(finalized);\n\n    let extracted = psbt.extract_tx().expect("failed to extract tx");\n    assert_eq!(extracted.input[0].witness.len(), 2);\n}\n\n#[test]\nfn test_sign_single_xprv_bip44_path() {\n    let (mut wallet, _) = get_funded_wallet("wpkh(tprv8ZgxMBicQKsPd3EupYiPRhaMooHKUHJxNsTfYuScep13go8QFfHdtkG9nRkFGb7busX4isf6X9dURGCoKgitaApQ6MupRhZMcELAxTBRJgS/44\'/0\'/0\'/0/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    let finalized = wallet.sign(&mut psbt, Default::default()).unwrap();\n    assert!(finalized);\n\n    let extracted = psbt.extract_tx().expect("failed to extract tx");\n    assert_eq!(extracted.input[0].witness.len(), 2);\n}\n\n#[test]\nfn test_sign_single_xprv_sh_wpkh() {\n    let (mut wallet, _) = get_funded_wallet("sh(wpkh(tprv8ZgxMBicQKsPd3EupYiPRhaMooHKUHJxNsTfYuScep13go8QFfHdtkG9nRkFGb7busX4isf6X9dURGCoKgitaApQ6MupRhZMcELAxTBRJgS/*))");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    let finalized = wallet.sign(&mut psbt, Default::default()).unwrap();\n    assert!(finalized);\n\n    let extracted = psbt.extract_tx().expect("failed to extract tx");\n    assert_eq!(extracted.input[0].witness.len(), 2);\n}\n\n#[test]\nfn test_sign_single_wif() {\n    let (mut wallet, _) =\n        get_funded_wallet("wpkh(cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    let finalized = wallet.sign(&mut psbt, Default::default()).unwrap();\n    assert!(finalized);\n\n    let extracted = psbt.extract_tx().expect("failed to extract tx");\n    assert_eq!(extracted.input[0].witness.len(), 2);\n}\n\n#[test]\nfn test_sign_single_xprv_no_hd_keypaths() {\n    let (mut wallet, _) = get_funded_wallet("wpkh(tprv8ZgxMBicQKsPd3EupYiPRhaMooHKUHJxNsTfYuScep13go8QFfHdtkG9nRkFGb7busX4isf6X9dURGCoKgitaApQ6MupRhZMcELAxTBRJgS/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    psbt.inputs[0].bip32_derivation.clear();\n    assert_eq!(psbt.inputs[0].bip32_derivation.len(), 0);\n\n    let finalized = wallet.sign(&mut psbt, Default::default()).unwrap();\n    assert!(finalized);\n\n    let extracted = psbt.extract_tx().expect("failed to extract tx");\n    assert_eq!(extracted.input[0].witness.len(), 2);\n}\n\n#[test]\nfn test_include_output_redeem_witness_script() {\n    let desc = get_test_wpkh();\n    let change_desc = "sh(wsh(multi(1,cVpPVruEDdmutPzisEsYvtST1usBR3ntr8pXSyt6D2YYqXRyPcFW,cRjo6jqfVNP33HhSS76UhXETZsGTZYx8FMFvR9kpbtCSV1PmdZdu)))";\n    let (mut wallet, _) = get_funded_wallet_with_change(desc, change_desc);\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(45_000))\n        .include_output_redeem_witness_script();\n    let psbt = builder.finish().unwrap();\n\n    // p2sh-p2wsh transaction should contain both witness and redeem scripts\n    assert!(psbt\n        .outputs\n        .iter()\n        .any(|output| output.redeem_script.is_some() && output.witness_script.is_some()));\n}\n\n#[test]\nfn test_signing_only_one_of_multiple_inputs() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(45_000))\n        .include_output_redeem_witness_script();\n    let mut psbt = builder.finish().unwrap();\n\n    // add another input to the psbt that is at least passable.\n    let dud_input = bitcoin::psbt::Input {\n        witness_utxo: Some(TxOut {\n            value: Amount::from_sat(100_000),\n            script_pubkey: miniscript::Descriptor::<bitcoin::PublicKey>::from_str(\n                "wpkh(025476c2e83188368da1ff3e292e7acafcdb3566bb0ad253f62fc70f07aeee6357)",\n            )\n            .unwrap()\n            .script_pubkey(),\n        }),\n        ..Default::default()\n    };\n\n    psbt.inputs.push(dud_input);\n    psbt.unsigned_tx.input.push(bitcoin::TxIn::default());\n    let is_final = wallet\n        .sign(\n            &mut psbt,\n            SignOptions {\n                trust_witness_utxo: true,\n                ..Default::default()\n            },\n        )\n        .unwrap();\n    assert!(\n        !is_final,\n        "shouldn\'t be final since we can\'t sign one of the inputs"\n    );\n    assert!(\n        psbt.inputs[0].final_script_witness.is_some(),\n        "should finalized input it signed"\n    )\n}\n\n#[test]\nfn test_try_finalize_sign_option() {\n    let (mut wallet, _) = get_funded_wallet("wpkh(tprv8ZgxMBicQKsPd3EupYiPRhaMooHKUHJxNsTfYuScep13go8QFfHdtkG9nRkFGb7busX4isf6X9dURGCoKgitaApQ6MupRhZMcELAxTBRJgS/*)");\n\n    for try_finalize in &[true, false] {\n        let addr = wallet.next_unused_address(KeychainKind::External);\n        let mut builder = wallet.build_tx();\n        builder.drain_to(addr.script_pubkey()).drain_wallet();\n        let mut psbt = builder.finish().unwrap();\n\n        let finalized = wallet\n            .sign(\n                &mut psbt,\n                SignOptions {\n                    try_finalize: *try_finalize,\n                    ..Default::default()\n                },\n            )\n            .unwrap();\n\n        psbt.inputs.iter().for_each(|input| {\n            if *try_finalize {\n                assert!(finalized);\n                assert!(input.final_script_sig.is_none());\n                assert!(input.final_script_witness.is_some());\n            } else {\n                assert!(!finalized);\n                assert!(input.final_script_sig.is_none());\n                assert!(input.final_script_witness.is_none());\n            }\n        });\n    }\n}\n\n#[test]\nfn test_taproot_try_finalize_sign_option() {\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_with_taptree());\n\n    for try_finalize in &[true, false] {\n        let addr = wallet.next_unused_address(KeychainKind::External);\n        let mut builder = wallet.build_tx();\n        builder.drain_to(addr.script_pubkey()).drain_wallet();\n        let mut psbt = builder.finish().unwrap();\n\n        let finalized = wallet\n            .sign(\n                &mut psbt,\n                SignOptions {\n                    try_finalize: *try_finalize,\n                    ..Default::default()\n                },\n            )\n            .unwrap();\n\n        psbt.inputs.iter().for_each(|input| {\n            if *try_finalize {\n                assert!(finalized);\n                assert!(input.final_script_sig.is_none());\n                assert!(input.final_script_witness.is_some());\n                assert!(input.tap_key_sig.is_none());\n                assert!(input.tap_script_sigs.is_empty());\n                assert!(input.tap_scripts.is_empty());\n                assert!(input.tap_key_origins.is_empty());\n                assert!(input.tap_internal_key.is_none());\n                assert!(input.tap_merkle_root.is_none());\n            } else {\n                assert!(!finalized);\n                assert!(input.final_script_sig.is_none());\n                assert!(input.final_script_witness.is_none());\n            }\n        });\n        psbt.outputs.iter().for_each(|output| {\n            if *try_finalize {\n                assert!(finalized);\n                assert!(output.tap_key_origins.is_empty());\n            } else {\n                assert!(!finalized);\n                assert!(!output.tap_key_origins.is_empty());\n            }\n        });\n    }\n}\n\n#[test]\nfn test_sign_nonstandard_sighash() {\n    let sighash = EcdsaSighashType::NonePlusAnyoneCanPay;\n\n    let (mut wallet, _) = get_funded_wallet("wpkh(tprv8ZgxMBicQKsPd3EupYiPRhaMooHKUHJxNsTfYuScep13go8QFfHdtkG9nRkFGb7busX4isf6X9dURGCoKgitaApQ6MupRhZMcELAxTBRJgS/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .sighash(sighash.into())\n        .drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    let result = wallet.sign(&mut psbt, Default::default());\n    assert!(\n        result.is_err(),\n        "Signing should have failed because the TX uses non-standard sighashes"\n    );\n    assert_matches!(\n        result,\n        Err(SignerError::NonStandardSighash),\n        "Signing failed with the wrong error type"\n    );\n\n    // try again after opting-in\n    let result = wallet.sign(\n        &mut psbt,\n        SignOptions {\n            allow_all_sighashes: true,\n            ..Default::default()\n        },\n    );\n    assert!(result.is_ok(), "Signing should have worked");\n    assert!(\n        result.unwrap(),\n        "Should finalize the input since we can produce signatures"\n    );\n\n    let extracted = psbt.extract_tx().expect("failed to extract tx");\n    assert_eq!(\n        *extracted.input[0].witness.to_vec()[0].last().unwrap(),\n        sighash.to_u32() as u8,\n        "The signature should have been made with the right sighash"\n    );\n}\n\n#[test]\nfn test_unused_address() {\n    let desc = "wpkh(tpubEBr4i6yk5nf5DAaJpsi9N2pPYBeJ7fZ5Z9rmN4977iYLCGco1VyjB9tvvuvYtfZzjD5A8igzgw3HeWeeKFmanHYqksqZXYXGsw5zjnj7KM9/*)";\n    let change_desc = get_test_wpkh();\n    let mut wallet = Wallet::new(desc, change_desc, Network::Testnet).expect("wallet");\n\n    // `list_unused_addresses` should be empty if we haven\'t revealed any\n    assert!(wallet\n        .list_unused_addresses(KeychainKind::External)\n        .next()\n        .is_none());\n\n    assert_eq!(\n        wallet\n            .next_unused_address(KeychainKind::External)\n            .to_string(),\n        "tb1q6yn66vajcctph75pvylgkksgpp6nq04ppwct9a"\n    );\n    assert_eq!(\n        wallet\n            .list_unused_addresses(KeychainKind::External)\n            .next()\n            .unwrap()\n            .to_string(),\n        "tb1q6yn66vajcctph75pvylgkksgpp6nq04ppwct9a"\n    );\n}\n\n#[test]\nfn test_next_unused_address() {\n    let descriptor = "wpkh(tpubEBr4i6yk5nf5DAaJpsi9N2pPYBeJ7fZ5Z9rmN4977iYLCGco1VyjB9tvvuvYtfZzjD5A8igzgw3HeWeeKFmanHYqksqZXYXGsw5zjnj7KM9/*)";\n    let change = get_test_wpkh();\n    let mut wallet = Wallet::new(descriptor, change, Network::Testnet).expect("wallet");\n    assert_eq!(wallet.derivation_index(KeychainKind::External), None);\n\n    assert_eq!(\n        wallet\n            .next_unused_address(KeychainKind::External)\n            .to_string(),\n        "tb1q6yn66vajcctph75pvylgkksgpp6nq04ppwct9a"\n    );\n    assert_eq!(wallet.derivation_index(KeychainKind::External), Some(0));\n    // calling next_unused again gives same address\n    assert_eq!(\n        wallet\n            .next_unused_address(KeychainKind::External)\n            .to_string(),\n        "tb1q6yn66vajcctph75pvylgkksgpp6nq04ppwct9a"\n    );\n    assert_eq!(wallet.derivation_index(KeychainKind::External), Some(0));\n\n    // test mark used / unused\n    assert!(wallet.mark_used(KeychainKind::External, 0));\n    let next_unused_addr = wallet.next_unused_address(KeychainKind::External);\n    assert_eq!(next_unused_addr.index, 1);\n\n    assert!(wallet.unmark_used(KeychainKind::External, 0));\n    let next_unused_addr = wallet.next_unused_address(KeychainKind::External);\n    assert_eq!(next_unused_addr.index, 0);\n\n    // use the above address\n    receive_output_in_latest_block(&mut wallet, 25_000);\n\n    assert_eq!(\n        wallet\n            .next_unused_address(KeychainKind::External)\n            .to_string(),\n        "tb1q4er7kxx6sssz3q7qp7zsqsdx4erceahhax77d7"\n    );\n    assert_eq!(wallet.derivation_index(KeychainKind::External), Some(1));\n\n    // trying to mark index 0 unused should return false\n    assert!(!wallet.unmark_used(KeychainKind::External, 0));\n}\n\n#[test]\nfn test_peek_address_at_index() {\n    let desc = "wpkh(tpubEBr4i6yk5nf5DAaJpsi9N2pPYBeJ7fZ5Z9rmN4977iYLCGco1VyjB9tvvuvYtfZzjD5A8igzgw3HeWeeKFmanHYqksqZXYXGsw5zjnj7KM9/*)";\n    let change_desc = get_test_wpkh();\n    let mut wallet = Wallet::new(desc, change_desc, Network::Testnet).unwrap();\n\n    assert_eq!(\n        wallet.peek_address(KeychainKind::External, 1).to_string(),\n        "tb1q4er7kxx6sssz3q7qp7zsqsdx4erceahhax77d7"\n    );\n\n    assert_eq!(\n        wallet.peek_address(KeychainKind::External, 0).to_string(),\n        "tb1q6yn66vajcctph75pvylgkksgpp6nq04ppwct9a"\n    );\n\n    assert_eq!(\n        wallet.peek_address(KeychainKind::External, 2).to_string(),\n        "tb1qzntf2mqex4ehwkjlfdyy3ewdlk08qkvkvrz7x2"\n    );\n\n    // current new address is not affected\n    assert_eq!(\n        wallet\n            .reveal_next_address(KeychainKind::External)\n            .to_string(),\n        "tb1q6yn66vajcctph75pvylgkksgpp6nq04ppwct9a"\n    );\n\n    assert_eq!(\n        wallet\n            .reveal_next_address(KeychainKind::External)\n            .to_string(),\n        "tb1q4er7kxx6sssz3q7qp7zsqsdx4erceahhax77d7"\n    );\n}\n\n#[test]\nfn test_peek_address_at_index_not_derivable() {\n    let wallet = Wallet::new("wpkh(tpubEBr4i6yk5nf5DAaJpsi9N2pPYBeJ7fZ5Z9rmN4977iYLCGco1VyjB9tvvuvYtfZzjD5A8igzgw3HeWeeKFmanHYqksqZXYXGsw5zjnj7KM9/1)",\n                                 get_test_wpkh(), Network::Testnet).unwrap();\n\n    assert_eq!(\n        wallet.peek_address(KeychainKind::External, 1).to_string(),\n        "tb1q4er7kxx6sssz3q7qp7zsqsdx4erceahhax77d7"\n    );\n\n    assert_eq!(\n        wallet.peek_address(KeychainKind::External, 0).to_string(),\n        "tb1q4er7kxx6sssz3q7qp7zsqsdx4erceahhax77d7"\n    );\n\n    assert_eq!(\n        wallet.peek_address(KeychainKind::External, 2).to_string(),\n        "tb1q4er7kxx6sssz3q7qp7zsqsdx4erceahhax77d7"\n    );\n}\n\n#[test]\nfn test_returns_index_and_address() {\n    let mut wallet = Wallet::new("wpkh(tpubEBr4i6yk5nf5DAaJpsi9N2pPYBeJ7fZ5Z9rmN4977iYLCGco1VyjB9tvvuvYtfZzjD5A8igzgw3HeWeeKFmanHYqksqZXYXGsw5zjnj7KM9/*)",\n                                 get_test_wpkh(), Network::Testnet).unwrap();\n\n    // new index 0\n    assert_eq!(\n        wallet.reveal_next_address(KeychainKind::External),\n        AddressInfo {\n            index: 0,\n            address: Address::from_str("tb1q6yn66vajcctph75pvylgkksgpp6nq04ppwct9a")\n                .unwrap()\n                .assume_checked(),\n            keychain: KeychainKind::External,\n        }\n    );\n\n    // new index 1\n    assert_eq!(\n        wallet.reveal_next_address(KeychainKind::External),\n        AddressInfo {\n            index: 1,\n            address: Address::from_str("tb1q4er7kxx6sssz3q7qp7zsqsdx4erceahhax77d7")\n                .unwrap()\n                .assume_checked(),\n            keychain: KeychainKind::External,\n        }\n    );\n\n    // peek index 25\n    assert_eq!(\n        wallet.peek_address(KeychainKind::External, 25),\n        AddressInfo {\n            index: 25,\n            address: Address::from_str("tb1qsp7qu0knx3sl6536dzs0703u2w2ag6ppl9d0c2")\n                .unwrap()\n                .assume_checked(),\n            keychain: KeychainKind::External,\n        }\n    );\n\n    // new index 2\n    assert_eq!(\n        wallet.reveal_next_address(KeychainKind::External),\n        AddressInfo {\n            index: 2,\n            address: Address::from_str("tb1qzntf2mqex4ehwkjlfdyy3ewdlk08qkvkvrz7x2")\n                .unwrap()\n                .assume_checked(),\n            keychain: KeychainKind::External,\n        }\n    );\n}\n\n#[test]\nfn test_sending_to_bip350_bech32m_address() {\n    let (mut wallet, _) = get_funded_wallet_wpkh();\n    let addr = Address::from_str("tb1pqqqqp399et2xygdj5xreqhjjvcmzhxw4aywxecjdzew6hylgvsesf3hn0c")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(45_000));\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_get_address() {\n    use bdk_wallet::descriptor::template::Bip84;\n    let key = bitcoin::bip32::Xpriv::from_str("tprv8ZgxMBicQKsPcx5nBGsR63Pe8KnRUqmbJNENAfGftF3yuXoMMoVJJcYeUw5eVkm9WBPjWYt6HMWYJNesB5HaNVBaFc1M6dRjWSYnmewUMYy").unwrap();\n    let wallet = Wallet::new(\n        Bip84(key, KeychainKind::External),\n        Bip84(key, KeychainKind::Internal),\n        Network::Regtest,\n    )\n    .unwrap();\n\n    assert_eq!(\n        wallet.peek_address(KeychainKind::External, 0),\n        AddressInfo {\n            index: 0,\n            address: Address::from_str("bcrt1qrhgaqu0zvf5q2d0gwwz04w0dh0cuehhqvzpp4w")\n                .unwrap()\n                .assume_checked(),\n            keychain: KeychainKind::External,\n        }\n    );\n\n    assert_eq!(\n        wallet.peek_address(KeychainKind::Internal, 0),\n        AddressInfo {\n            index: 0,\n            address: Address::from_str("bcrt1q0ue3s5y935tw7v3gmnh36c5zzsaw4n9c9smq79")\n                .unwrap()\n                .assume_checked(),\n            keychain: KeychainKind::Internal,\n        }\n    );\n}\n\n#[test]\nfn test_reveal_addresses() {\n    let (desc, change_desc) = get_test_tr_single_sig_xprv_with_change_desc();\n    let mut wallet = Wallet::new(desc, change_desc, Network::Signet).unwrap();\n    let keychain = KeychainKind::External;\n\n    let last_revealed_addr = wallet.reveal_addresses_to(keychain, 9).last().unwrap();\n    assert_eq!(wallet.derivation_index(keychain), Some(9));\n\n    let unused_addrs = wallet.list_unused_addresses(keychain).collect::<Vec<_>>();\n    assert_eq!(unused_addrs.len(), 10);\n    assert_eq!(unused_addrs.last().unwrap(), &last_revealed_addr);\n\n    // revealing to an already revealed index returns nothing\n    let mut already_revealed = wallet.reveal_addresses_to(keychain, 9);\n    assert!(already_revealed.next().is_none());\n}\n\n#[test]\nfn test_get_address_no_reuse() {\n    use bdk_wallet::descriptor::template::Bip84;\n    use std::collections::HashSet;\n\n    let key = bitcoin::bip32::Xpriv::from_str("tprv8ZgxMBicQKsPcx5nBGsR63Pe8KnRUqmbJNENAfGftF3yuXoMMoVJJcYeUw5eVkm9WBPjWYt6HMWYJNesB5HaNVBaFc1M6dRjWSYnmewUMYy").unwrap();\n    let mut wallet = Wallet::new(\n        Bip84(key, KeychainKind::External),\n        Bip84(key, KeychainKind::Internal),\n        Network::Regtest,\n    )\n    .unwrap();\n\n    let mut used_set = HashSet::new();\n\n    (0..3).for_each(|_| {\n        let external_addr = wallet.reveal_next_address(KeychainKind::External).address;\n        assert!(used_set.insert(external_addr));\n\n        let internal_addr = wallet.reveal_next_address(KeychainKind::Internal).address;\n        assert!(used_set.insert(internal_addr));\n    });\n}\n\n#[test]\nfn test_taproot_psbt_populate_tap_key_origins() {\n    let (desc, change_desc) = get_test_tr_single_sig_xprv_with_change_desc();\n    let (mut wallet, _) = get_funded_wallet_with_change(desc, change_desc);\n    let addr = wallet.reveal_next_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(\n        psbt.inputs[0]\n            .tap_key_origins\n            .clone()\n            .into_iter()\n            .collect::<Vec<_>>(),\n        vec![(\n            from_str!("0841db1dbaf949dbbda893e01a18f2cca9179cf8ea2d8e667857690502b06483"),\n            (vec![], (from_str!("f6a5cb8b"), from_str!("m/0/0")))\n        )],\n        "Wrong input tap_key_origins"\n    );\n    assert_eq!(\n        psbt.outputs[0]\n            .tap_key_origins\n            .clone()\n            .into_iter()\n            .collect::<Vec<_>>(),\n        vec![(\n            from_str!("9187c1e80002d19ddde9c5c7f5394e9a063cee8695867b58815af0562695ca21"),\n            (vec![], (from_str!("f6a5cb8b"), from_str!("m/0/1")))\n        )],\n        "Wrong output tap_key_origins"\n    );\n}\n\n#[test]\nfn test_taproot_psbt_populate_tap_key_origins_repeated_key() {\n    let (mut wallet, _) =\n        get_funded_wallet_with_change(get_test_tr_repeated_key(), get_test_tr_single_sig());\n    let addr = wallet.reveal_next_address(KeychainKind::External);\n\n    let path = vec![("rn4nre9c".to_string(), vec![0])]\n        .into_iter()\n        .collect();\n\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .drain_wallet()\n        .policy_path(path, KeychainKind::External);\n    let psbt = builder.finish().unwrap();\n\n    let mut input_key_origins = psbt.inputs[0]\n        .tap_key_origins\n        .clone()\n        .into_iter()\n        .collect::<Vec<_>>();\n    input_key_origins.sort();\n\n    assert_eq!(\n        input_key_origins,\n        vec![\n            (\n                from_str!("2b0558078bec38694a84933d659303e2575dae7e91685911454115bfd64487e3"),\n                (\n                    vec![\n                        from_str!(\n                            "858ad7a7d7f270e2c490c4d6ba00c499e46b18fdd59ea3c2c47d20347110271e"\n                        ),\n                        from_str!(\n                            "f6e927ad4492c051fe325894a4f5f14538333b55a35f099876be42009ec8f903"\n                        ),\n                    ],\n                    (FromStr::from_str("ece52657").unwrap(), vec![].into())\n                )\n            ),\n            (\n                from_str!("b511bd5771e47ee27558b1765e87b541668304ec567721c7b880edc0a010da55"),\n                (\n                    vec![],\n                    (FromStr::from_str("871fd295").unwrap(), vec![].into())\n                )\n            )\n        ],\n        "Wrong input tap_key_origins"\n    );\n\n    let mut output_key_origins = psbt.outputs[0]\n        .tap_key_origins\n        .clone()\n        .into_iter()\n        .collect::<Vec<_>>();\n    output_key_origins.sort();\n\n    assert_eq!(\n        input_key_origins, output_key_origins,\n        "Wrong output tap_key_origins"\n    );\n}\n\n#[test]\nfn test_taproot_psbt_input_tap_tree() {\n    use bitcoin::hex::FromHex;\n    use bitcoin::taproot;\n\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_with_taptree());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let psbt = builder.finish().unwrap();\n\n    assert_eq!(\n        psbt.inputs[0].tap_merkle_root,\n        Some(\n            TapNodeHash::from_str(\n                "61f81509635053e52d9d1217545916167394490da2287aca4693606e43851986"\n            )\n            .unwrap()\n        ),\n    );\n    assert_eq!(\n        psbt.inputs[0].tap_scripts.clone().into_iter().collect::<Vec<_>>(),\n        vec![\n            (taproot::ControlBlock::decode(&Vec::<u8>::from_hex("c0b511bd5771e47ee27558b1765e87b541668304ec567721c7b880edc0a010da55b7ef769a745e625ed4b9a4982a4dc08274c59187e73e6f07171108f455081cb2").unwrap()).unwrap(), (ScriptBuf::from_hex("208aee2b8120a5f157f1223f72b5e62b825831a27a9fdf427db7cc697494d4a642ac").unwrap(), taproot::LeafVersion::TapScript)),\n            (taproot::ControlBlock::decode(&Vec::<u8>::from_hex("c0b511bd5771e47ee27558b1765e87b541668304ec567721c7b880edc0a010da55b9a515f7be31a70186e3c5937ee4a70cc4b4e1efe876c1d38e408222ffc64834").unwrap()).unwrap(), (ScriptBuf::from_hex("2051494dc22e24a32fe9dcfbd7e85faf345fa1df296fb49d156e859ef345201295ac").unwrap(), taproot::LeafVersion::TapScript)),\n        ],\n    );\n    assert_eq!(\n        psbt.inputs[0].tap_internal_key,\n        Some(from_str!(\n            "b511bd5771e47ee27558b1765e87b541668304ec567721c7b880edc0a010da55"\n        ))\n    );\n\n    // Since we are creating an output to the same address as the input, assert that the\n    // internal_key is the same\n    assert_eq!(\n        psbt.inputs[0].tap_internal_key,\n        psbt.outputs[0].tap_internal_key\n    );\n\n    let tap_tree: bitcoin::taproot::TapTree = serde_json::from_str(r#"[1,{"Script":["2051494dc22e24a32fe9dcfbd7e85faf345fa1df296fb49d156e859ef345201295ac",192]},1,{"Script":["208aee2b8120a5f157f1223f72b5e62b825831a27a9fdf427db7cc697494d4a642ac",192]}]"#).unwrap();\n    assert_eq!(psbt.outputs[0].tap_tree, Some(tap_tree));\n}\n\n#[test]\nfn test_taproot_sign_missing_witness_utxo() {\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_single_sig());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n    let witness_utxo = psbt.inputs[0].witness_utxo.take();\n\n    let result = wallet.sign(\n        &mut psbt,\n        SignOptions {\n            allow_all_sighashes: true,\n            ..Default::default()\n        },\n    );\n    assert_matches!(\n        result,\n        Err(SignerError::MissingWitnessUtxo),\n        "Signing should have failed with the correct error because the witness_utxo is missing"\n    );\n\n    // restore the witness_utxo\n    psbt.inputs[0].witness_utxo = witness_utxo;\n\n    let result = wallet.sign(\n        &mut psbt,\n        SignOptions {\n            allow_all_sighashes: true,\n            ..Default::default()\n        },\n    );\n\n    assert_matches!(\n        result,\n        Ok(true),\n        "Should finalize the input since we can produce signatures"\n    );\n}\n\n#[test]\nfn test_taproot_sign_using_non_witness_utxo() {\n    let (mut wallet, prev_txid) = get_funded_wallet(get_test_tr_single_sig());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder.drain_to(addr.script_pubkey()).drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    psbt.inputs[0].witness_utxo = None;\n    psbt.inputs[0].non_witness_utxo =\n        Some(wallet.get_tx(prev_txid).unwrap().tx_node.as_ref().clone());\n    assert!(\n        psbt.inputs[0].non_witness_utxo.is_some(),\n        "Previous tx should be present in the database"\n    );\n\n    let result = wallet.sign(&mut psbt, Default::default());\n    assert!(result.is_ok(), "Signing should have worked");\n    assert!(\n        result.unwrap(),\n        "Should finalize the input since we can produce signatures"\n    );\n}\n\n#[test]\nfn test_taproot_foreign_utxo() {\n    let (mut wallet1, _) = get_funded_wallet_wpkh();\n    let (wallet2, _) = get_funded_wallet(get_test_tr_single_sig());\n\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let utxo = wallet2.list_unspent().next().unwrap();\n    let psbt_input = wallet2.get_psbt_input(utxo.clone(), None, false).unwrap();\n    let foreign_utxo_satisfaction = wallet2\n        .get_descriptor_for_keychain(KeychainKind::External)\n        .max_weight_to_satisfy()\n        .unwrap();\n\n    assert!(\n        psbt_input.non_witness_utxo.is_none(),\n        "`non_witness_utxo` should never be populated for taproot"\n    );\n\n    let mut builder = wallet1.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), Amount::from_sat(60_000))\n        .add_foreign_utxo(utxo.outpoint, psbt_input, foreign_utxo_satisfaction)\n        .unwrap();\n    let psbt = builder.finish().unwrap();\n    let sent_received =\n        wallet1.sent_and_received(&psbt.clone().extract_tx().expect("failed to extract tx"));\n    wallet1.insert_txout(utxo.outpoint, utxo.txout);\n    let fee = check_fee!(wallet1, psbt);\n\n    assert_eq!(\n        sent_received.0 - sent_received.1,\n        Amount::from_sat(10_000) + fee.unwrap_or(Amount::ZERO),\n        "we should have only net spent ~10_000"\n    );\n\n    assert!(\n        psbt.unsigned_tx\n            .input\n            .iter()\n            .any(|input| input.previous_output == utxo.outpoint),\n        "foreign_utxo should be in there"\n    );\n}\n\nfn test_spend_from_wallet(mut wallet: Wallet) {\n    let addr = wallet.next_unused_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let mut psbt = builder.finish().unwrap();\n\n    assert!(\n        wallet.sign(&mut psbt, Default::default()).unwrap(),\n        "Unable to finalize tx"\n    );\n}\n\n//     #[test]\n//     fn test_taproot_key_spend() {\n//         let (mut wallet, _) = get_funded_wallet(get_test_tr_single_sig());\n//         test_spend_from_wallet(wallet);\n\n//         let (mut wallet, _) = get_funded_wallet(get_test_tr_single_sig_xprv());\n//         test_spend_from_wallet(wallet);\n//     }\n\n#[test]\nfn test_taproot_no_key_spend() {\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_with_taptree_both_priv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let mut psbt = builder.finish().unwrap();\n\n    assert!(\n        wallet\n            .sign(\n                &mut psbt,\n                SignOptions {\n                    sign_with_tap_internal_key: false,\n                    ..Default::default()\n                },\n            )\n            .unwrap(),\n        "Unable to finalize tx"\n    );\n\n    assert!(psbt.inputs.iter().all(|i| i.tap_key_sig.is_none()));\n}\n\n#[test]\nfn test_taproot_script_spend() {\n    let (wallet, _) = get_funded_wallet(get_test_tr_with_taptree());\n    test_spend_from_wallet(wallet);\n\n    let (wallet, _) = get_funded_wallet(get_test_tr_with_taptree_xprv());\n    test_spend_from_wallet(wallet);\n}\n\n#[test]\nfn test_taproot_script_spend_sign_all_leaves() {\n    use bdk_wallet::signer::TapLeavesOptions;\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_with_taptree_both_priv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let mut psbt = builder.finish().unwrap();\n\n    assert!(\n        wallet\n            .sign(\n                &mut psbt,\n                SignOptions {\n                    tap_leaves_options: TapLeavesOptions::All,\n                    ..Default::default()\n                },\n            )\n            .unwrap(),\n        "Unable to finalize tx"\n    );\n\n    assert!(psbt\n        .inputs\n        .iter()\n        .all(|i| i.tap_script_sigs.len() == i.tap_scripts.len()));\n}\n\n#[test]\nfn test_taproot_script_spend_sign_include_some_leaves() {\n    use bdk_wallet::signer::TapLeavesOptions;\n    use bitcoin::taproot::TapLeafHash;\n\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_with_taptree_both_priv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let mut psbt = builder.finish().unwrap();\n    let mut script_leaves: Vec<_> = psbt.inputs[0]\n        .tap_scripts\n        .clone()\n        .values()\n        .map(|(script, version)| TapLeafHash::from_script(script, *version))\n        .collect();\n    let included_script_leaves = vec![script_leaves.pop().unwrap()];\n    let excluded_script_leaves = script_leaves;\n\n    assert!(\n        wallet\n            .sign(\n                &mut psbt,\n                SignOptions {\n                    tap_leaves_options: TapLeavesOptions::Include(included_script_leaves.clone()),\n                    ..Default::default()\n                },\n            )\n            .unwrap(),\n        "Unable to finalize tx"\n    );\n\n    assert!(psbt.inputs[0]\n        .tap_script_sigs\n        .iter()\n        .all(|s| included_script_leaves.contains(&s.0 .1)\n            && !excluded_script_leaves.contains(&s.0 .1)));\n}\n\n#[test]\nfn test_taproot_script_spend_sign_exclude_some_leaves() {\n    use bdk_wallet::signer::TapLeavesOptions;\n    use bitcoin::taproot::TapLeafHash;\n\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_with_taptree_both_priv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let mut psbt = builder.finish().unwrap();\n    let mut script_leaves: Vec<_> = psbt.inputs[0]\n        .tap_scripts\n        .clone()\n        .values()\n        .map(|(script, version)| TapLeafHash::from_script(script, *version))\n        .collect();\n    let included_script_leaves = [script_leaves.pop().unwrap()];\n    let excluded_script_leaves = script_leaves;\n\n    assert!(\n        wallet\n            .sign(\n                &mut psbt,\n                SignOptions {\n                    tap_leaves_options: TapLeavesOptions::Exclude(excluded_script_leaves.clone()),\n                    ..Default::default()\n                },\n            )\n            .unwrap(),\n        "Unable to finalize tx"\n    );\n\n    assert!(psbt.inputs[0]\n        .tap_script_sigs\n        .iter()\n        .all(|s| included_script_leaves.contains(&s.0 .1)\n            && !excluded_script_leaves.contains(&s.0 .1)));\n}\n\n#[test]\nfn test_taproot_script_spend_sign_no_leaves() {\n    use bdk_wallet::signer::TapLeavesOptions;\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_with_taptree_both_priv());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let mut psbt = builder.finish().unwrap();\n\n    wallet\n        .sign(\n            &mut psbt,\n            SignOptions {\n                tap_leaves_options: TapLeavesOptions::None,\n                ..Default::default()\n            },\n        )\n        .unwrap();\n\n    assert!(psbt.inputs.iter().all(|i| i.tap_script_sigs.is_empty()));\n}\n\n#[test]\nfn test_taproot_sign_derive_index_from_psbt() {\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_single_sig_xprv());\n\n    let addr = wallet.next_unused_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n    builder.add_recipient(addr.script_pubkey(), Amount::from_sat(25_000));\n    let mut psbt = builder.finish().unwrap();\n\n    // re-create the wallet with an empty db\n    let wallet_empty = Wallet::new(\n        get_test_tr_single_sig_xprv(),\n        get_test_tr_single_sig(),\n        Network::Regtest,\n    )\n    .unwrap();\n\n    // signing with an empty db means that we will only look at the psbt to infer the\n    // derivation index\n    assert!(\n        wallet_empty.sign(&mut psbt, Default::default()).unwrap(),\n        "Unable to finalize tx"\n    );\n}\n\n#[test]\nfn test_taproot_sign_explicit_sighash_all() {\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_single_sig());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .sighash(TapSighashType::All.into())\n        .drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    let result = wallet.sign(&mut psbt, Default::default());\n    assert!(\n        result.is_ok(),\n        "Signing should work because SIGHASH_ALL is safe"\n    )\n}\n\n#[test]\nfn test_taproot_sign_non_default_sighash() {\n    let sighash = TapSighashType::NonePlusAnyoneCanPay;\n\n    let (mut wallet, _) = get_funded_wallet(get_test_tr_single_sig());\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .sighash(sighash.into())\n        .drain_wallet();\n    let mut psbt = builder.finish().unwrap();\n\n    let witness_utxo = psbt.inputs[0].witness_utxo.take();\n\n    let result = wallet.sign(&mut psbt, Default::default());\n    assert!(\n        result.is_err(),\n        "Signing should have failed because the TX uses non-standard sighashes"\n    );\n    assert_matches!(\n        result,\n        Err(SignerError::NonStandardSighash),\n        "Signing failed with the wrong error type"\n    );\n\n    // try again after opting-in\n    let result = wallet.sign(\n        &mut psbt,\n        SignOptions {\n            allow_all_sighashes: true,\n            ..Default::default()\n        },\n    );\n    assert!(\n        result.is_err(),\n        "Signing should have failed because the witness_utxo is missing"\n    );\n    assert_matches!(\n        result,\n        Err(SignerError::MissingWitnessUtxo),\n        "Signing failed with the wrong error type"\n    );\n\n    // restore the witness_utxo\n    psbt.inputs[0].witness_utxo = witness_utxo;\n\n    let result = wallet.sign(\n        &mut psbt,\n        SignOptions {\n            allow_all_sighashes: true,\n            ..Default::default()\n        },\n    );\n\n    assert!(result.is_ok(), "Signing should have worked");\n    assert!(\n        result.unwrap(),\n        "Should finalize the input since we can produce signatures"\n    );\n\n    let extracted = psbt.extract_tx().expect("failed to extract tx");\n    assert_eq!(\n        *extracted.input[0].witness.to_vec()[0].last().unwrap(),\n        sighash as u8,\n        "The signature should have been made with the right sighash"\n    );\n}\n\n#[test]\nfn test_spend_coinbase() {\n    let (desc, change_desc) = get_test_wpkh_with_change_desc();\n    let mut wallet = Wallet::new(desc, change_desc, Network::Regtest).unwrap();\n\n    let confirmation_height = 5;\n    wallet\n        .insert_checkpoint(BlockId {\n            height: confirmation_height,\n            hash: BlockHash::all_zeros(),\n        })\n        .unwrap();\n    let coinbase_tx = Transaction {\n        version: transaction::Version::ONE,\n        lock_time: absolute::LockTime::ZERO,\n        input: vec![TxIn {\n            previous_output: OutPoint::null(),\n            ..Default::default()\n        }],\n        output: vec![TxOut {\n            script_pubkey: wallet\n                .next_unused_address(KeychainKind::External)\n                .script_pubkey(),\n            value: Amount::from_sat(25_000),\n        }],\n    };\n    wallet\n        .insert_tx(\n            coinbase_tx,\n            ConfirmationTime::Confirmed {\n                height: confirmation_height,\n                time: 30_000,\n            },\n        )\n        .unwrap();\n\n    let not_yet_mature_time = confirmation_height + COINBASE_MATURITY - 1;\n    let maturity_time = confirmation_height + COINBASE_MATURITY;\n\n    let balance = wallet.balance();\n    assert_eq!(\n        balance,\n        Balance {\n            immature: Amount::from_sat(25_000),\n            trusted_pending: Amount::ZERO,\n            untrusted_pending: Amount::ZERO,\n            confirmed: Amount::ZERO\n        }\n    );\n\n    // We try to create a transaction, only to notice that all\n    // our funds are unspendable\n    let addr = Address::from_str("2N1Ffz3WaNzbeLFBb51xyFMHYSEUXcbiSoX")\n        .unwrap()\n        .assume_checked();\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), balance.immature / 2)\n        .current_height(confirmation_height);\n    assert!(matches!(\n        builder.finish(),\n        Err(CreateTxError::CoinSelection(\n            coin_selection::Error::InsufficientFunds {\n                needed: _,\n                available: 0\n            }\n        ))\n    ));\n\n    // Still unspendable...\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), balance.immature / 2)\n        .current_height(not_yet_mature_time);\n    assert_matches!(\n        builder.finish(),\n        Err(CreateTxError::CoinSelection(\n            coin_selection::Error::InsufficientFunds {\n                needed: _,\n                available: 0\n            }\n        ))\n    );\n\n    wallet\n        .insert_checkpoint(BlockId {\n            height: maturity_time,\n            hash: BlockHash::all_zeros(),\n        })\n        .unwrap();\n    let balance = wallet.balance();\n    assert_eq!(\n        balance,\n        Balance {\n            immature: Amount::ZERO,\n            trusted_pending: Amount::ZERO,\n            untrusted_pending: Amount::ZERO,\n            confirmed: Amount::from_sat(25_000)\n        }\n    );\n    let mut builder = wallet.build_tx();\n    builder\n        .add_recipient(addr.script_pubkey(), balance.confirmed / 2)\n        .current_height(maturity_time);\n    builder.finish().unwrap();\n}\n\n#[test]\nfn test_allow_dust_limit() {\n    let (mut wallet, _) = get_funded_wallet(get_test_single_sig_cltv());\n\n    let addr = wallet.next_unused_address(KeychainKind::External);\n\n    let mut builder = wallet.build_tx();\n\n    builder.add_recipient(addr.script_pubkey(), Amount::ZERO);\n\n    assert_matches!(\n        builder.finish(),\n        Err(CreateTxError::OutputBelowDustLimit(0))\n    );\n\n    let mut builder = wallet.build_tx();\n\n    builder\n        .allow_dust(true)\n        .add_recipient(addr.script_pubkey(), Amount::ZERO);\n\n    assert!(builder.finish().is_ok());\n}\n\n#[test]\nfn test_fee_rate_sign_no_grinding_high_r() {\n    // Our goal is to obtain a transaction with a signature with high-R (71 bytes\n    // instead of 70). We then check that our fee rate and fee calculation is\n    // alright.\n    let (mut wallet, _) = get_funded_wallet("wpkh(tprv8ZgxMBicQKsPd3EupYiPRhaMooHKUHJxNsTfYuScep13go8QFfHdtkG9nRkFGb7busX4isf6X9dURGCoKgitaApQ6MupRhZMcELAxTBRJgS/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let fee_rate = FeeRate::from_sat_per_vb_unchecked(1);\n    let mut builder = wallet.build_tx();\n    let mut data = PushBytesBuf::try_from(vec![0]).unwrap();\n    builder\n        .drain_to(addr.script_pubkey())\n        .drain_wallet()\n        .fee_rate(fee_rate)\n        .add_data(&data);\n    let mut psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n    let (op_return_vout, _) = psbt\n        .unsigned_tx\n        .output\n        .iter()\n        .enumerate()\n        .find(|(_n, i)| i.script_pubkey.is_op_return())\n        .unwrap();\n\n    let mut sig_len: usize = 0;\n    // We try to sign many different times until we find a longer signature (71 bytes)\n    while sig_len < 71 {\n        // Changing the OP_RETURN data will make the signature change (but not the fee, until\n        // data[0] is small enough)\n        data.as_mut_bytes()[0] += 1;\n        psbt.unsigned_tx.output[op_return_vout].script_pubkey = ScriptBuf::new_op_return(&data);\n        // Clearing the previous signature\n        psbt.inputs[0].partial_sigs.clear();\n        // Signing\n        wallet\n            .sign(\n                &mut psbt,\n                SignOptions {\n                    try_finalize: false,\n                    allow_grinding: false,\n                    ..Default::default()\n                },\n            )\n            .unwrap();\n        // We only have one key in the partial_sigs map, this is a trick to retrieve it\n        let key = psbt.inputs[0].partial_sigs.keys().next().unwrap();\n        sig_len = psbt.inputs[0].partial_sigs[key]\n            .signature\n            .serialize_der()\n            .len();\n    }\n    // Actually finalizing the transaction...\n    wallet\n        .sign(\n            &mut psbt,\n            SignOptions {\n                allow_grinding: false,\n                ..Default::default()\n            },\n        )\n        .unwrap();\n    // ...and checking that everything is fine\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), fee_rate);\n}\n\n#[test]\nfn test_fee_rate_sign_grinding_low_r() {\n    // Our goal is to obtain a transaction with a signature with low-R (70 bytes)\n    // by setting the `allow_grinding` signing option as true.\n    // We then check that our fee rate and fee calculation is alright and that our\n    // signature is 70 bytes.\n    let (mut wallet, _) = get_funded_wallet("wpkh(tprv8ZgxMBicQKsPd3EupYiPRhaMooHKUHJxNsTfYuScep13go8QFfHdtkG9nRkFGb7busX4isf6X9dURGCoKgitaApQ6MupRhZMcELAxTBRJgS/*)");\n    let addr = wallet.next_unused_address(KeychainKind::External);\n    let fee_rate = FeeRate::from_sat_per_vb_unchecked(1);\n    let mut builder = wallet.build_tx();\n    builder\n        .drain_to(addr.script_pubkey())\n        .drain_wallet()\n        .fee_rate(fee_rate);\n    let mut psbt = builder.finish().unwrap();\n    let fee = check_fee!(wallet, psbt);\n\n    wallet\n        .sign(\n            &mut psbt,\n            SignOptions {\n                try_finalize: false,\n                allow_grinding: true,\n                ..Default::default()\n            },\n        )\n        .unwrap();\n\n    let key = psbt.inputs[0].partial_sigs.keys().next().unwrap();\n    let sig_len = psbt.inputs[0].partial_sigs[key]\n        .signature\n        .serialize_der()\n        .len();\n    assert_eq!(sig_len, 70);\n    assert_fee_rate!(psbt, fee.unwrap_or(Amount::ZERO), fee_rate);\n}\n\n#[test]\nfn test_taproot_load_descriptor_duplicated_keys() {\n    // Added after issue https://github.com/bitcoindevkit/bdk/issues/760\n    //\n    // Having the same key in multiple taproot leaves is safe and should be accepted by BDK\n\n    let (wallet, _) = get_funded_wallet(get_test_tr_dup_keys());\n    let addr = wallet.peek_address(KeychainKind::External, 0);\n\n    assert_eq!(\n        addr.to_string(),\n        "bcrt1pvysh4nmh85ysrkpwtrr8q8gdadhgdejpy6f9v424a8v9htjxjhyqw9c5s5"\n    );\n}\n\n#[test]\n/// The wallet should re-use previously allocated change addresses when the tx using them is cancelled\nfn test_tx_cancellation() {\n    macro_rules! new_tx {\n        ($wallet:expr) => {{\n            let addr = Address::from_str("2N4eQYCbKUHCCTUjBJeHcJp9ok6J2GZsTDt")\n                .unwrap()\n                .assume_checked();\n            let mut builder = $wallet.build_tx();\n            builder.add_recipient(addr.script_pubkey(), Amount::from_sat(10_000));\n\n            let psbt = builder.finish().unwrap();\n\n            psbt\n        }};\n    }\n\n    let (mut wallet, _) =\n        get_funded_wallet_with_change(get_test_wpkh(), get_test_tr_single_sig_xprv());\n\n    let psbt1 = new_tx!(wallet);\n    let change_derivation_1 = psbt1\n        .unsigned_tx\n        .output\n        .iter()\n        .find_map(|txout| wallet.derivation_of_spk(&txout.script_pubkey))\n        .unwrap();\n    assert_eq!(change_derivation_1, (KeychainKind::Internal, 0));\n\n    let psbt2 = new_tx!(wallet);\n\n    let change_derivation_2 = psbt2\n        .unsigned_tx\n        .output\n        .iter()\n        .find_map(|txout| wallet.derivation_of_spk(&txout.script_pubkey))\n        .unwrap();\n    assert_eq!(change_derivation_2, (KeychainKind::Internal, 1));\n\n    wallet.cancel_tx(&psbt1.extract_tx().expect("failed to extract tx"));\n\n    let psbt3 = new_tx!(wallet);\n    let change_derivation_3 = psbt3\n        .unsigned_tx\n        .output\n        .iter()\n        .find_map(|txout| wallet.derivation_of_spk(&txout.script_pubkey))\n        .unwrap();\n    assert_eq!(change_derivation_3, (KeychainKind::Internal, 0));\n\n    let psbt3 = new_tx!(wallet);\n    let change_derivation_3 = psbt3\n        .unsigned_tx\n        .output\n        .iter()\n        .find_map(|txout| wallet.derivation_of_spk(&txout.script_pubkey))\n        .unwrap();\n    assert_eq!(change_derivation_3, (KeychainKind::Internal, 2));\n\n    wallet.cancel_tx(&psbt3.extract_tx().expect("failed to extract tx"));\n\n    let psbt3 = new_tx!(wallet);\n    let change_derivation_4 = psbt3\n        .unsigned_tx\n        .output\n        .iter()\n        .find_map(|txout| wallet.derivation_of_spk(&txout.script_pubkey))\n        .unwrap();\n    assert_eq!(change_derivation_4, (KeychainKind::Internal, 2));\n}\n\n#[test]\nfn test_thread_safety() {\n    fn thread_safe<T: Send + Sync>() {}\n    thread_safe::<Wallet>(); // compiles only if true\n}\n',
        }
